import type { LocalizedString } from '~/lib/domain'
import { L } from '../locale'

/**
 * TOPIK 1 usage notes — keyed by Grammar.ko (the v1 stable id).
 * Extracted from grammars-n1.ts so the study sheet can look them up by ko
 * (like grammar-examples / pronunciation), independent of the Supabase catalog
 * which does not carry this field. Single source of truth for usage notes.
 */
export const TOPIK_1_USAGE_NOTES: Record<string, LocalizedString> = {
  '은/는': L(
      'Marks the topic of the sentence — what you\'re going to talk about ("as for X..."). Form: 은 after a consonant (저는), 는 after a vowel (어머니는).\n\nDon\'t confuse with 이/가. 은/는 introduces something known or general; 이/가 highlights new info or answers "who?/what?". In casual speech the particle is often dropped when the topic is obvious.',
      'Marca el tema de la frase — aquello sobre lo que vas a decir algo ("en cuanto a X..."). Forma: 은 tras consonante (저는), 는 tras vocal (어머니는).\n\nOjo, no la mezcles con 이/가. 은/는 introduce algo general o ya sabido; 이/가 destaca info nueva o responde a "¿quién?/¿qué?". En habla coloquial la partícula se omite cuando el tema queda claro.',
      'Marque le thème de la phrase — ce dont on va parler (« quant à X... »). Forme : 은 après consonne (저는), 는 après voyelle (어머니는).\n\nÀ ne pas confondre avec 이/가. 은/는 introduit une info générale ou déjà connue ; 이/가 met en relief une info nouvelle ou répond à « qui ? / quoi ? ». À l\'oral familier, la particule tombe souvent lorsque le thème est évident.',
      'Marca o tópico da frase — aquilo sobre o que você vai falar ("quanto a X..."). Forma: 은 depois de consoante (저는), 는 depois de vogal (어머니는).\n\nNão confunda com 이/가. 은/는 introduz algo geral ou já conhecido; 이/가 destaca info nova ou responde "quem?/o quê?". Na fala casual a partícula costuma cair quando o tópico está claro.',
      'แสดงหัวเรื่องของประโยค — สิ่งที่กำลังจะพูดถึง ("สำหรับ X..."). รูป: 은 หลังพยัญชนะ (저는), 는 หลังสระ (어머니는).\n\nอย่าสับสนกับ 이/가. 은/는 แนะนำข้อมูลทั่วไปหรือที่รู้กันอยู่แล้ว ส่วน 이/가 เน้นข้อมูลใหม่หรือใช้ตอบ "ใคร?/อะไร?". ในภาษาพูดอย่างกันเอง อนุภาคนี้มักถูกตัดออกเมื่อหัวเรื่องชัดเจนอยู่แล้ว',
      'Menandai topik kalimat — apa yang akan dibicarakan ("mengenai X..."). Bentuk: 은 setelah konsonan (저는), 는 setelah vokal (어머니는).\n\nJangan tertukar dengan 이/가. 은/는 memperkenalkan informasi umum atau yang sudah diketahui; 이/가 menekankan info baru atau menjawab "siapa?/apa?". Dalam percakapan santai, partikel ini sering dilepas saat topiknya sudah jelas.',
      'Đánh dấu chủ đề của câu — điều bạn sắp nói tới ("về phần X..."). Hình thức: 은 sau phụ âm (저는), 는 sau nguyên âm (어머니는).\n\nĐừng nhầm với 이/가. 은/는 giới thiệu thông tin chung hoặc đã biết; 이/가 làm nổi bật thông tin mới hoặc trả lời "ai?/cái gì?". Trong khẩu ngữ thân mật, tiểu từ này thường được bỏ khi chủ đề đã rõ.',
      '文の主題を示す（「Xについて言えば」）。形: 子音の後は 은（저는）、母音の後は 는（어머니는）。\n\n이/가 と混同しないこと。은/는 は既知や一般的な情報を提示するのに対し、이/가 は新情報を際立たせたり「誰が／何が？」に答えたりする。くだけた会話では、主題が明らかなときに省略されることがある。',
    ),
  '이/가': L(
      'Marks the grammatical subject — who or what performs the action, or what an adjective applies to. Use 이 after a consonant (책이), 가 after a vowel (의자가).\n\nPicks up new information or emphasizes "who?/what?", whereas 은/는 marks the topic ("as for X..."). Watch the irregular forms: 나 + 가 → 내가, 저 + 가 → 제가, 누구 + 가 → 누가. Casual speech may drop the particle when context is clear.',
      'Marca el sujeto gramatical — quién o qué realiza la acción o a quién se aplica el adjetivo. Se usa 이 tras consonante (책이) y 가 tras vocal (의자가).\n\nIntroduce información nueva o enfatiza "¿quién?/¿qué?", mientras que 은/는 marca el tema ("en cuanto a X..."). Ojo con formas irregulares: 나 + 가 → 내가, 저 + 가 → 제가, 누구 + 가 → 누가. En habla coloquial se puede omitir si el contexto es claro.',
      "Marque le sujet grammatical — qui fait l'action ou à qui s'applique l'adjectif. 이 après consonne (책이), 가 après voyelle (의자가).\n\nPrésente une info nouvelle ou met en relief « qui ? / quoi ? », tandis que 은/는 marque le thème (« quant à X... »). Attention aux formes irrégulières : 나 + 가 → 내가, 저 + 가 → 제가, 누구 + 가 → 누가. La particule peut tomber à l'oral si le contexte est clair.",
      'Marca o sujeito gramatical — quem ou o que faz a ação ou a que o adjetivo se refere. Use 이 depois de consoante (책이) e 가 depois de vogal (의자가).\n\nApresenta info nova ou enfatiza "quem?/o quê?", enquanto 은/는 marca o tópico ("quanto a X..."). Cuidado com formas irregulares: 나 + 가 → 내가, 저 + 가 → 제가, 누구 + 가 → 누가. Na fala casual a partícula pode cair se o contexto estiver claro.',
      'แสดงประธานของประโยค — ผู้กระทำหรือสิ่งที่คำคุณศัพท์ขยาย. ใช้ 이 หลังพยัญชนะ (책이) และ 가 หลังสระ (의자가).\n\nแนะนำข้อมูลใหม่หรือเน้น "ใคร?/อะไร?" ในขณะที่ 은/는 แสดงหัวเรื่อง ("สำหรับ X..."). ระวังรูปเฉพาะ: 나 + 가 → 내가, 저 + 가 → 제가, 누구 + 가 → 누가. ในภาษาพูดอย่างกันเองอาจตัดออกได้เมื่อบริบทชัดเจน',
      'Menandai subjek gramatikal — siapa atau apa yang melakukan aksi atau dijelaskan oleh adjektiva. Gunakan 이 setelah konsonan (책이), 가 setelah vokal (의자가).\n\nMemperkenalkan info baru atau menekankan "siapa?/apa?", sedangkan 은/는 menandai topik ("mengenai X..."). Hati-hati bentuk tak beraturan: 나 + 가 → 내가, 저 + 가 → 제가, 누구 + 가 → 누가. Dalam percakapan santai bisa dilepas kalau konteksnya jelas.',
      'Đánh dấu chủ ngữ ngữ pháp — ai hoặc cái gì thực hiện hành động, hoặc đối tượng mà tính từ mô tả. Dùng 이 sau phụ âm (책이), 가 sau nguyên âm (의자가).\n\nGiới thiệu thông tin mới hoặc nhấn mạnh "ai?/cái gì?", còn 은/는 đánh dấu chủ đề ("về phần X..."). Lưu ý dạng bất quy tắc: 나 + 가 → 내가, 저 + 가 → 제가, 누구 + 가 → 누가. Trong khẩu ngữ thân mật có thể bỏ khi ngữ cảnh rõ.',
      '文法上の主語を示す。動作主や形容詞がかかる対象。子音の後は 이(책이)、母音の後は 가(의자가)。\n\n은/는 が主題を示すのに対し、이/가 は新情報を持ち込み「誰が？／何が？」に答える。不規則形に注意：나 + 가 → 내가、저 + 가 → 제가、누구 + 가 → 누가。くだけた会話では文脈次第で省略されることがある。',
    ),
  '을/를': L(
      'Marks the direct object — what receives the action. Use 을 after a consonant (책을), 를 after a vowel (커피를).\n\nKorean and your native language don\'t always agree on which verbs take a direct object: 만나다 "meet" takes 을/를 (친구를 만나요), but 결혼하다 "marry" takes 와/과 instead (친구와 결혼해요). In casual speech the particle is often dropped when the object is obvious.',
      'Marca el objeto directo — lo que recibe la acción. Se usa 을 tras consonante (책을) y 를 tras vocal (커피를).\n\nEl coreano no siempre coincide con tu idioma sobre qué verbos llevan objeto directo: 만나다 "encontrar/conocer" lleva 을/를 (친구를 만나요), pero verbos como 결혼하다 "casarse" llevan 와/과 (친구와 결혼해요). En habla coloquial se suele omitir cuando el objeto es obvio.',
      "Marque le complément d'objet direct — ce qui subit l'action. 을 après consonne (책을), 를 après voyelle (커피를).\n\nLe coréen et le français ne s'accordent pas toujours sur les verbes transitifs : 만나다 « rencontrer » prend 을/를 (친구를 만나요), mais 결혼하다 « se marier » prend 와/과 (친구와 결혼해요). À l'oral familier, la particule disparaît souvent quand l'objet est évident.",
      'Marca o objeto direto — o que recebe a ação. Use 을 depois de consoante (책을) e 를 depois de vogal (커피를).\n\nCoreano e seu idioma nem sempre concordam sobre quais verbos pedem objeto direto: 만나다 "encontrar" leva 을/를 (친구를 만나요), mas 결혼하다 "casar" leva 와/과 (친구와 결혼해요). Na fala casual a partícula costuma cair quando o objeto está claro.',
      'แสดงกรรมตรง — สิ่งที่ถูกการกระทำ. ใช้ 을 หลังพยัญชนะ (책을) และ 를 หลังสระ (커피를).\n\nภาษาเกาหลีกับภาษาคุณไม่ตรงกันเสมอเรื่องว่าคำกริยาใดต้องการกรรมตรง: 만나다 "พบ" ใช้ 을/를 (친구를 만나요) แต่ 결혼하다 "แต่งงาน" ใช้ 와/과 แทน (친구와 결혼해요). ในภาษาพูดอย่างกันเองมักจะตัดทิ้งเมื่อกรรมชัดเจน',
      'Menandai objek langsung — yang menerima aksi. Gunakan 을 setelah konsonan (책을), 를 setelah vokal (커피를).\n\nBahasa Korea dan bahasamu tidak selalu sepakat soal verba mana yang butuh objek langsung: 만나다 "menemui" pakai 을/를 (친구를 만나요), tapi 결혼하다 "menikah" pakai 와/과 (친구와 결혼해요). Dalam percakapan santai sering dilepas kalau objeknya jelas.',
      'Đánh dấu tân ngữ trực tiếp — đối tượng nhận hành động. Dùng 을 sau phụ âm (책을), 를 sau nguyên âm (커피를).\n\nTiếng Hàn và tiếng mẹ đẻ của bạn không phải lúc nào cũng nhất trí về động từ nào cần tân ngữ trực tiếp: 만나다 "gặp" lấy 을/를 (친구를 만나요), nhưng 결혼하다 "kết hôn" lấy 와/과 (친구와 결혼해요). Trong khẩu ngữ thường lược bỏ khi tân ngữ đã rõ.',
      '目的語(動作の対象)を示す。子音の後は 을(책을)、母音の後は 를(커피를)。\n\n日本語と必ずしも同じ動詞が目的語を取るとは限らない。만나다 「会う」は 을/를 をとる(친구를 만나요)が、결혼하다 「結婚する」は 와/과 をとる(친구와 결혼해요)。くだけた会話では目的語が明らかなとき省略されることが多い。',
    ),
  '에': L(
      'Three uses: (1) static location — where something exists or is placed (집에 있어요 "be at home"), used with 있다/없다 and 살다; (2) destination — where you\'re going (학교에 가요), used with 가다/오다 and similar; (3) point in time — 3시에 (at 3), 월요일에 (on Monday), 2026년에 (in 2026).\n\nNote: 에 is NOT used for the place where an action happens — that\'s 에서 (학교에서 공부해요 "study at school").',
      'Tres usos: (1) ubicación estática — dónde algo está o se encuentra (집에 있어요 "estar en casa"), con 있다/없다 y 살다; (2) destino — adónde vas (학교에 가요), con 가다/오다 y similares; (3) momento puntual — 3시에 (a las 3), 월요일에 (el lunes), 2026년에 (en 2026).\n\nAtención: 에 NO se usa para el lugar donde ocurre una acción — para eso va 에서 (학교에서 공부해요 "estudiar en la escuela").',
      "Trois emplois : (1) lieu statique — où quelque chose se trouve (집에 있어요 « être à la maison »), avec 있다/없다 et 살다 ; (2) destination — où l'on va (학교에 가요), avec 가다/오다 et verbes similaires ; (3) point dans le temps — 3시에 (à 3 h), 월요일에 (le lundi), 2026년에 (en 2026).\n\nAttention : 에 ne marque PAS le lieu où une action se déroule — c'est 에서 (학교에서 공부해요 « étudier à l'école »).",
      'Três usos: (1) localização estática — onde algo está (집에 있어요 "estar em casa"), com 있다/없다 e 살다; (2) destino — para onde você vai (학교에 가요), com 가다/오다 e similares; (3) ponto no tempo — 3시에 (às 3), 월요일에 (na segunda), 2026년에 (em 2026).\n\nAtenção: 에 NÃO é usado para o lugar onde uma ação acontece — para isso vai 에서 (학교에서 공부해요 "estudar na escola").',
      'ใช้ได้ 3 แบบ: (1) ตำแหน่งแบบหยุดนิ่ง — ที่บางสิ่งอยู่ (집에 있어요 "อยู่ที่บ้าน") ใช้กับ 있다/없다 และ 살다; (2) ปลายทาง — ไปที่ไหน (학교에 가요) ใช้กับ 가다/오다 และคำคล้าย; (3) จุดเวลา — 3시에 (สามโมง) 월요일에 (วันจันทร์) 2026년에 (ปี 2026).\n\nระวัง: 에 ไม่ใช้กับสถานที่เกิดการกระทำ — ใช้ 에서 แทน (학교에서 공부해요 "เรียนที่โรงเรียน")',
      'Tiga penggunaan: (1) lokasi statis — tempat sesuatu berada (집에 있어요 "di rumah"), dengan 있다/없다 dan 살다; (2) tujuan — ke mana kamu pergi (학교에 가요), dengan 가다/오다 dan sejenisnya; (3) titik waktu — 3시에 (jam 3), 월요일에 (pada hari Senin), 2026년에 (di tahun 2026).\n\nCatat: 에 TIDAK dipakai untuk tempat aksi terjadi — pakai 에서 (학교에서 공부해요 "belajar di sekolah").',
      'Ba cách dùng: (1) vị trí tĩnh — nơi cái gì đó ở đó (집에 있어요 "ở nhà"), đi với 있다/없다 và 살다; (2) đích đến — nơi bạn đến (학교에 가요), đi với 가다/오다 và tương tự; (3) thời điểm — 3시에 (3 giờ), 월요일에 (vào thứ Hai), 2026년에 (năm 2026).\n\nLưu ý: 에 KHÔNG dùng cho nơi diễn ra hành động — phải dùng 에서 (학교에서 공부해요 "học ở trường").',
      '3つの用法: (1) 静的な場所 — 物がある場所(집에 있어요「家にいる」)、있다/없다 や 살다 と共起; (2) 行き先 — 向かう場所(학교에 가요)、가다/오다 などの動詞と共起; (3) 時の一点 — 3시에(3時に)、월요일에(月曜に)、2026년에(2026年に)。\n\n注意: 에 は動作が行われる場所には使わない — それは 에서(학교에서 공부해요「学校で勉強する」)。',
    ),
  '에서': L(
      'Two uses: (1) location where an action happens — used with active verbs like 공부하다, 일하다, 먹다 (도서관에서 공부해요 "study at the library"); (2) origin — "from" a place (부산에서 왔어요 "I came from Busan").\n\nContrasts with 에: static location and destination use 에 (도서관에 있어요 "be at the library"), but an action performed AT that location uses 에서. Quick test: if you can replace the verb with 있다 and it still makes sense → 에; if it has to be a doing-verb → 에서.',
      'Dos usos: (1) lugar donde ocurre una acción — con verbos de actividad como 공부하다, 일하다, 먹다 (도서관에서 공부해요 "estudiar en la biblioteca"); (2) origen — "desde" un lugar (부산에서 왔어요 "vine de Busan").\n\nContrasta con 에: ubicación estática y destino llevan 에 (도서관에 있어요 "estar en la biblioteca"), pero la acción realizada EN ese lugar lleva 에서. Truco: si puedes cambiar el verbo por 있다 y la frase aún tiene sentido → 에; si necesita un verbo de acción → 에서.',
      "Deux emplois : (1) lieu où se déroule une action — avec des verbes d'activité comme 공부하다, 일하다, 먹다 (도서관에서 공부해요 « étudier à la bibliothèque ») ; (2) origine — « de » un lieu (부산에서 왔어요 « je viens de Busan »).\n\nÀ distinguer de 에 : lieu statique et destination prennent 에 (도서관에 있어요 « être à la bibliothèque »), mais une action effectuée DANS ce lieu prend 에서. Test : si on peut remplacer le verbe par 있다 et que la phrase reste sensée → 에 ; sinon → 에서.",
      'Dois usos: (1) lugar onde uma ação acontece — com verbos de atividade como 공부하다, 일하다, 먹다 (도서관에서 공부해요 "estudar na biblioteca"); (2) origem — "de" um lugar (부산에서 왔어요 "vim de Busan").\n\nContrasta com 에: localização estática e destino levam 에 (도서관에 있어요 "estar na biblioteca"), mas uma ação realizada NAQUELE lugar leva 에서. Dica: se você pode trocar o verbo por 있다 e a frase faz sentido → 에; se precisa de verbo de ação → 에서.',
      'ใช้ได้ 2 แบบ: (1) สถานที่ที่เกิดการกระทำ — ใช้กับกริยาแอคทีฟอย่าง 공부하다, 일하다, 먹다 (도서관에서 공부해요 "เรียนที่ห้องสมุด"); (2) จุดเริ่มต้น — "จาก" สถานที่ (부산에서 왔어요 "ฉันมาจากปูซาน").\n\nต่างจาก 에: ตำแหน่งหยุดนิ่งและปลายทางใช้ 에 (도서관에 있어요 "อยู่ที่ห้องสมุด") แต่การกระทำในที่นั้นใช้ 에서. เคล็ดลับ: ถ้าเปลี่ยนกริยาเป็น 있다 แล้วประโยคยังมีความหมาย → 에; ถ้าต้องเป็นกริยากระทำ → 에서',
      'Dua penggunaan: (1) tempat aksi terjadi — dengan verba aktivitas seperti 공부하다, 일하다, 먹다 (도서관에서 공부해요 "belajar di perpustakaan"); (2) asal — "dari" suatu tempat (부산에서 왔어요 "saya datang dari Busan").\n\nBerbeda dengan 에: lokasi statis dan tujuan pakai 에 (도서관에 있어요 "di perpustakaan"), tapi aksi yang dilakukan DI tempat itu pakai 에서. Tips: kalau verba bisa diganti 있다 dan kalimat tetap masuk akal → 에; kalau harus verba aksi → 에서.',
      'Hai cách dùng: (1) nơi diễn ra hành động — đi với động từ hoạt động như 공부하다, 일하다, 먹다 (도서관에서 공부해요 "học ở thư viện"); (2) nguồn gốc — "từ" một nơi (부산에서 왔어요 "tôi đến từ Busan").\n\nTương phản với 에: vị trí tĩnh và đích đến dùng 에 (도서관에 있어요 "ở thư viện"), nhưng hành động được thực hiện TẠI nơi đó dùng 에서. Mẹo: nếu thay động từ bằng 있다 mà câu vẫn hợp lý → 에; nếu cần động từ hành động → 에서.',
      '二つの用法: (1) 動作が行われる場所 — 공부하다、일하다、먹다 など動的な動詞と共起する(도서관에서 공부해요「図書館で勉強する」); (2) 出発点 — 「〜から」(부산에서 왔어요「釜山から来ました」)。\n\n에 との対比: 静的な所在・到達点は 에(도서관에 있어요「図書館にいる」)、その場所で行う動作は 에서。コツ: 動詞を 있다 に置き換えても文が成り立つなら 에、動作動詞でないと成り立たないなら 에서。',
    ),
  '와/과 · 하고 · (이)랑': L(
      'Three particles that all mean "and" or "with" connecting nouns, sorted by register: 와/과 is written/formal (와 after vowel, 과 after consonant — 친구와, 책과); 하고 is neutral and the safest spoken default (친구하고); (이)랑 is casual, friend-to-friend (이 after consonant, just 랑 after vowel — 친구랑, 책이랑).\n\nThey cover both "noun AND noun" and "with noun" (companionship) — same form, context picks the meaning. For listing more than two nouns, attach the particle only between items, not after the last one.',
      'Tres partículas que significan "y" o "con" entre sustantivos, ordenadas por registro: 와/과 es escrito/formal (와 tras vocal, 과 tras consonante — 친구와, 책과); 하고 es neutro y la opción segura en habla (친구하고); (이)랑 es coloquial entre amigos (이 tras consonante, solo 랑 tras vocal — 친구랑, 책이랑).\n\nCubren tanto "sustantivo Y sustantivo" como "con sustantivo" (compañía) — la misma forma, el contexto decide. Para listas de más de dos, la partícula va solo entre elementos, no después del último.',
      'Trois particules signifiant « et » ou « avec » entre noms, classées par registre : 와/과 est écrit/formel (와 après voyelle, 과 après consonne — 친구와, 책과) ; 하고 est neutre et le choix sûr à l\'oral (친구하고) ; (이)랑 est familier, entre amis (이 après consonne, juste 랑 après voyelle — 친구랑, 책이랑).\n\nElles couvrent à la fois « nom ET nom » et « avec un nom » (compagnie) — même forme, le contexte tranche. Pour énumérer plus de deux noms, la particule ne se place qu\'entre les éléments, pas après le dernier.',
      'Três partículas que significam "e" ou "com" entre substantivos, ordenadas por registro: 와/과 é escrita/formal (와 depois de vogal, 과 depois de consoante — 친구와, 책과); 하고 é neutra e a escolha segura na fala (친구하고); (이)랑 é casual entre amigos (이 depois de consoante, só 랑 depois de vogal — 친구랑, 책이랑).\n\nCobrem tanto "substantivo E substantivo" quanto "com substantivo" (companhia) — mesma forma, o contexto decide. Para listar mais de dois, a partícula vai só entre os itens, não depois do último.',
      'อนุภาคสามตัวที่แปลว่า "และ" หรือ "กับ" เชื่อมคำนาม เรียงตามระดับภาษา: 와/과 เป็นทางการ/เขียน (와 หลังสระ, 과 หลังพยัญชนะ — 친구와, 책과); 하고 เป็นกลาง ปลอดภัยในภาษาพูด (친구하고); (이)랑 เป็นกันเองระหว่างเพื่อน (이 หลังพยัญชนะ, 랑 หลังสระ — 친구랑, 책이랑).\n\nใช้ได้ทั้ง "คำนาม และ คำนาม" และ "กับ คำนาม" (เพื่อนคู่หู) — รูปเดียวกัน บริบทจะบอกความหมาย. ถ้าจะระบุมากกว่าสองคำ ใส่อนุภาคเฉพาะระหว่างคำ ไม่ใส่หลังคำสุดท้าย',
      'Tiga partikel yang berarti "dan" atau "dengan" antar kata benda, diurut berdasarkan register: 와/과 tulis/formal (와 setelah vokal, 과 setelah konsonan — 친구와, 책과); 하고 netral dan pilihan aman dalam percakapan (친구하고); (이)랑 santai antar teman (이 setelah konsonan, hanya 랑 setelah vokal — 친구랑, 책이랑).\n\nMencakup "kata benda DAN kata benda" maupun "dengan kata benda" (kebersamaan) — bentuk sama, konteks menentukan. Untuk lebih dari dua kata, partikelnya hanya di antara item, bukan setelah yang terakhir.',
      'Ba tiểu từ đều nghĩa "và" hoặc "với" giữa các danh từ, xếp theo cấp độ trang trọng: 와/과 trang trọng/viết (와 sau nguyên âm, 과 sau phụ âm — 친구와, 책과); 하고 trung tính, lựa chọn an toàn khi nói (친구하고); (이)랑 thân mật giữa bạn bè (이 sau phụ âm, chỉ 랑 sau nguyên âm — 친구랑, 책이랑).\n\nBao cả "danh từ VÀ danh từ" lẫn "với danh từ" (bạn đồng hành) — cùng dạng, ngữ cảnh quyết định. Khi liệt kê hơn hai danh từ, tiểu từ chỉ đặt giữa các thành phần, không sau danh từ cuối.',
      '名詞をつなぐ「と」「〜と一緒に」の3つの助詞、丁寧度順に: 와/과 は文語・フォーマル(母音後 와、子音後 과 — 친구와、책과); 하고 は中立で会話の安全牌(친구하고); (이)랑 は親しい間柄(子音後 이, 母音後そのまま 랑 — 친구랑、책이랑)。\n\n「名詞と名詞」(並列)も「名詞と一緒に」(同伴)もこの形でこなし、意味は文脈次第。3つ以上を並べるときは要素間にだけ付け、最後の要素の後には付けない。',
    ),
  '도': L(
      'Means "also / too" in positive sentences and "either / neither" in negatives. Critically, 도 REPLACES the case particles 은/는, 이/가, 을/를 — you never stack them (write 저도 not 저는도, 책도 not 책을도). It can co-exist with location/time particles like 에 and 에서 (집에서도 일해요 "I also work from home").\n\nPosition matters for meaning: 저도 책을 읽어요 "I too read books" focuses on "I"; 저는 책도 읽어요 "I also read books" focuses on "books".',
      'Significa "también" en oraciones afirmativas y "tampoco" en negativas. Importante: 도 SUSTITUYE a las partículas de caso 은/는, 이/가, 을/를 — nunca se apilan (escribe 저도, no 저는도; 책도, no 책을도). Puede coexistir con partículas de lugar/tiempo como 에 y 에서 (집에서도 일해요 "también trabajo en casa").\n\nLa posición cambia el sentido: 저도 책을 읽어요 "yo también leo libros" enfatiza "yo"; 저는 책도 읽어요 "yo también leo libros" enfatiza "libros".',
      'Signifie « aussi » en phrase affirmative et « non plus » en phrase négative. Important : 도 REMPLACE les particules de cas 은/는, 이/가, 을/를 — on ne les empile jamais (저도, pas 저는도 ; 책도, pas 책을도). Coexiste avec les particules de lieu/temps comme 에 et 에서 (집에서도 일해요 « je travaille aussi à la maison »).\n\nLa position porte le sens : 저도 책을 읽어요 « moi aussi je lis des livres » met l\'accent sur « je » ; 저는 책도 읽어요 « je lis aussi des livres » met l\'accent sur « livres ».',
      'Significa "também" em afirmativas e "tampouco" em negativas. Importante: 도 SUBSTITUI as partículas de caso 은/는, 이/가, 을/를 — nunca se empilham (escreva 저도, não 저는도; 책도, não 책을도). Convive com partículas de lugar/tempo como 에 e 에서 (집에서도 일해요 "também trabalho em casa").\n\nA posição muda o sentido: 저도 책을 읽어요 "eu também leio livros" enfatiza "eu"; 저는 책도 읽어요 "eu leio livros também" enfatiza "livros".',
      'แปลว่า "ก็... ด้วย" ในประโยคบอกเล่า และ "ก็ไม่... เหมือนกัน" ในประโยคปฏิเสธ. ที่สำคัญ: 도 จะ "แทน" อนุภาคบ่งกรณี 은/는, 이/가, 을/를 — ห้ามใส่ซ้อนกัน (เขียน 저도 ไม่ใช่ 저는도, 책도 ไม่ใช่ 책을도). ใช้คู่กับอนุภาคสถานที่/เวลา 에 และ 에서 ได้ (집에서도 일해요 "ฉันก็ทำงานที่บ้านด้วย").\n\nตำแหน่งเปลี่ยนความหมาย: 저도 책을 읽어요 เน้น "ฉันก็เหมือนกัน"; 저는 책도 읽어요 เน้น "หนังสือก็อ่านด้วย"',
      'Berarti "juga" dalam kalimat positif dan "(juga) tidak" dalam negasi. Penting: 도 MENGGANTIKAN partikel kasus 은/는, 이/가, 을/를 — tidak pernah ditumpuk (tulis 저도, bukan 저는도; 책도, bukan 책을도). Bisa berdampingan dengan partikel tempat/waktu seperti 에 dan 에서 (집에서도 일해요 "saya juga kerja di rumah").\n\nPosisi mengubah arti: 저도 책을 읽어요 "saya juga membaca buku" menekankan "saya"; 저는 책도 읽어요 "saya juga membaca buku" menekankan "buku".',
      'Có nghĩa "cũng" trong câu khẳng định và "cũng không" trong câu phủ định. Quan trọng: 도 THAY THẾ các tiểu từ chỉ cách 은/는, 이/가, 을/를 — không bao giờ chồng lên nhau (viết 저도, không phải 저는도; 책도, không phải 책을도). Có thể đi cùng tiểu từ địa điểm/thời gian như 에 và 에서 (집에서도 일해요 "tôi cũng làm việc ở nhà").\n\nVị trí đổi nghĩa: 저도 책을 읽어요 nhấn mạnh "tôi"; 저는 책도 읽어요 nhấn mạnh "sách".',
      '肯定文では「も」、否定文では「〜も(〜ない)」を表す。重要: 도 は格助詞 은/는、이/가、을/를 を「置き換える」— 重ねて使わない(저도、저는도 とは書かない; 책도、책을도 とは書かない)。에・에서 など場所・時間助詞とは共起できる(집에서도 일해요「家でも働く」)。\n\n位置で焦点が変わる: 저도 책을 읽어요「私も本を読む」(私に焦点); 저는 책도 읽어요「私は本も読む」(本に焦点)。',
    ),
  '만': L(
      'Means "only / just" — exclusivity, "X and nothing else." Like 도, it usually replaces the case particles 은/는, 이/가, 을/를 (커피만 마셔요 "I only drink coffee," not 커피를만). But unlike 도, it CAN stack with case particles for emphasis: 커피만을 마셔요 is grammatical and slightly more formal/emphatic.\n\nPairs with 에/에서/(으)로 freely (집에서만 일해요 "I only work from home"). For "only" with verbs/clauses, use the conjugated form -기만 하다 instead.',
      'Significa "solo / únicamente" — exclusividad, "X y nada más". Como 도, suele sustituir a las partículas de caso 은/는, 이/가, 을/를 (커피만 마셔요 "solo bebo café", no 커피를만). Pero a diferencia de 도, SÍ puede apilarse con las partículas de caso para enfatizar: 커피만을 마셔요 es gramatical y un poco más formal/enfático.\n\nSe combina sin problema con 에/에서/(으)로 (집에서만 일해요 "solo trabajo desde casa"). Para "solo" con verbos/cláusulas se usa la forma conjugada -기만 하다.',
      'Signifie « seulement / juste » — exclusivité, « X et rien d\'autre ». Comme 도, remplace généralement les particules de cas 은/는, 이/가, 을/를 (커피만 마셔요 « je ne bois que du café », pas 커피를만). Mais contrairement à 도, 만 PEUT s\'empiler avec les particules de cas pour insister : 커피만을 마셔요 est correct et un peu plus formel/emphatique.\n\nSe combine librement avec 에/에서/(으)로 (집에서만 일해요 « je ne travaille qu\'à la maison »). Pour « seulement » avec verbes ou propositions, employer la forme conjuguée -기만 하다.',
      'Significa "só / apenas" — exclusividade, "X e nada mais". Como 도, geralmente substitui as partículas de caso 은/는, 이/가, 을/를 (커피만 마셔요 "só bebo café", não 커피를만). Mas diferente de 도, 만 PODE se empilhar com as partículas de caso para ênfase: 커피만을 마셔요 é gramatical e um pouco mais formal/enfático.\n\nCombina sem problema com 에/에서/(으)로 (집에서만 일해요 "só trabalho de casa"). Para "só" com verbos/orações, use a forma conjugada -기만 하다.',
      'แปลว่า "เท่านั้น / แค่" — แสดงการจำกัด "X เท่านั้น ไม่มีอย่างอื่น". เหมือน 도 มันมักแทนอนุภาคบ่งกรณี 은/는, 이/가, 을/를 (커피만 마셔요 "ฉันดื่มแค่กาแฟ" ไม่ใช่ 커피를만). แต่ต่างจาก 도 ตรงที่ 만 "ซ้อน" กับอนุภาคบ่งกรณีได้เพื่อเน้น: 커피만을 마셔요 ถูกไวยากรณ์และทางการกว่าเล็กน้อย.\n\nใช้คู่กับ 에/에서/(으)로 ได้อย่างอิสระ (집에서만 일해요 "ฉันทำงานแค่ที่บ้าน"). ถ้าจะใช้ "เท่านั้น" กับกริยา/อนุประโยค ให้ใช้รูปที่ผันแล้ว -기만 하다',
      'Berarti "hanya / saja" — eksklusivitas, "X dan tidak ada lainnya". Seperti 도, biasanya menggantikan partikel kasus 은/는, 이/가, 을/를 (커피만 마셔요 "saya hanya minum kopi", bukan 커피를만). Tapi tidak seperti 도, 만 BISA ditumpuk dengan partikel kasus untuk penegasan: 커피만을 마셔요 gramatikal dan terasa lebih formal/tegas.\n\nBerdampingan bebas dengan 에/에서/(으)로 (집에서만 일해요 "saya hanya kerja dari rumah"). Untuk "hanya" dengan verba/klausa, pakai bentuk konjugasi -기만 하다.',
      'Nghĩa là "chỉ / chỉ mỗi" — sự độc quyền, "X và không gì khác". Giống 도, thường thay tiểu từ chỉ cách 은/는, 이/가, 을/를 (커피만 마셔요 "tôi chỉ uống cà phê", không phải 커피를만). Nhưng khác 도, 만 CÓ THỂ chồng với tiểu từ chỉ cách để nhấn: 커피만을 마셔요 đúng ngữ pháp và hơi trang trọng/nhấn mạnh hơn.\n\nĐi tự do với 에/에서/(으)로 (집에서만 일해요 "tôi chỉ làm việc ở nhà"). Để nói "chỉ" với động từ/mệnh đề, dùng dạng chia -기만 하다.',
      '「だけ／〜のみ」— 排他「Xだけで他はない」を表す。도 と同様、通常は格助詞 은/는・이/가・을/를 を置き換える(커피만 마셔요「コーヒーだけ飲む」、커피를만 とは言わない)。ただし 도 と違い、만 は格助詞と「重ねて」強調できる: 커피만을 마셔요 は正しく、やや文語的・強調的。\n\n에・에서・(으)로 とは自由に共起する(집에서만 일해요「家でだけ働く」)。動詞や節に「〜だけ」を付けるときは活用形 -기만 하다 を使う。',
    ),
  '의': L(
      'Possessive "of" — A의 B = "B of A" / "A\'s B". Word order is the opposite of English: 친구의 책 = "the friend\'s book", literally "friend-of book".\n\nIn speech and casual writing the 의 is very often dropped: 친구 책, 우리 어머니 (very natural), and personal pronouns even contract: 나의 → 내, 저의 → 제, 너의 → 네 (which is why "my book" is usually 내 책, not 나의 책). Keep the 의 in formal writing, fixed phrases, and when the relationship would be ambiguous without it.',
      'Posesivo "de" — A의 B = "B de A". El orden es contrario al español: 친구의 책 = "el libro del amigo", literalmente "amigo-de libro".\n\nEn habla y escritura casual la 의 se omite mucho: 친구 책, 우리 어머니 (muy natural), y los pronombres personales se contraen: 나의 → 내, 저의 → 제, 너의 → 네 (por eso "mi libro" suele ser 내 책, no 나의 책). Mantén la 의 en escritura formal, expresiones fijas y cuando la relación quedaría ambigua sin ella.',
      'Possessif « de » — A의 B = « le B de A ». L\'ordre est inverse du français : 친구의 책 = « le livre de l\'ami », littéralement « ami-de livre ».\n\nÀ l\'oral et à l\'écrit informel, le 의 tombe très souvent : 친구 책, 우리 어머니 (très naturel), et les pronoms personnels se contractent : 나의 → 내, 저의 → 제, 너의 → 네 (d\'où « mon livre » normalement 내 책, pas 나의 책). Conserver le 의 à l\'écrit soutenu, dans les expressions figées, et quand la relation serait ambiguë sans lui.',
      'Possessivo "de" — A의 B = "B de A" / "o B de A". A ordem é o oposto do português: 친구의 책 = "o livro do amigo", literalmente "amigo-de livro".\n\nNa fala e escrita casual o 의 é muito frequentemente omitido: 친구 책, 우리 어머니 (bem natural), e pronomes pessoais contraem: 나의 → 내, 저의 → 제, 너의 → 네 (por isso "meu livro" costuma ser 내 책, não 나의 책). Mantenha 의 na escrita formal, expressões fixas e quando a relação ficaria ambígua sem ele.',
      'แสดงความเป็นเจ้าของ "ของ" — A의 B = "B ของ A" (ลำดับตรงข้ามภาษาไทย/อังกฤษ): 친구의 책 = "หนังสือของเพื่อน" ตามตัวอักษรคือ "เพื่อน-ของ หนังสือ".\n\nในภาษาพูดและเขียนแบบกันเอง 의 มักถูกตัดทิ้ง: 친구 책, 우리 어머니 (เป็นธรรมชาติมาก) และคำสรรพนามจะหดเหลือสั้น: 나의 → 내, 저의 → 제, 너의 → 네 (ดังนั้น "หนังสือของฉัน" มักเป็น 내 책 ไม่ใช่ 나의 책). คง 의 ไว้ในงานเขียนทางการ สำนวนตายตัว และเมื่อตัดแล้วจะกำกวม',
      'Kepemilikan "milik" — A의 B = "B milik A" / "B-nya A". Urutan kebalikan dari bahasa Indonesia: 친구의 책 = "buku teman", harfiah "teman-milik buku".\n\nDalam percakapan dan tulisan santai, 의 sangat sering dilepas: 친구 책, 우리 어머니 (sangat alami), dan kata ganti orang menyusut: 나의 → 내, 저의 → 제, 너의 → 네 (karena itu "buku saya" biasanya 내 책, bukan 나의 책). Pertahankan 의 dalam tulisan formal, frase tetap, dan saat hubungan akan ambigu tanpanya.',
      'Sở hữu "của" — A의 B = "B của A". Trật tự ngược với tiếng Việt: 친구의 책 = "sách của bạn", nghĩa đen "bạn-của sách".\n\nTrong khẩu ngữ và viết thân mật, 의 rất hay bị lược: 친구 책, 우리 어머니 (rất tự nhiên), và đại từ nhân xưng co lại: 나의 → 내, 저의 → 제, 너의 → 네 (vì vậy "sách của tôi" thường là 내 책, không phải 나의 책). Giữ 의 trong viết trang trọng, cụm cố định, và khi nếu bỏ thì quan hệ sẽ mơ hồ.',
      '所有を表す「〜の」— A의 B = 「AのB」。語順は日本語と同じ: 친구의 책 = 「友達の本」。\n\n話し言葉やくだけた文では 의 はよく省略される: 친구 책、우리 어머니(非常に自然)。人称代名詞は短縮される: 나의 → 내、저의 → 제、너의 → 네(だから「私の本」は普通 내 책 で、나의 책 ではない)。文語、固定表現、関係が曖昧になりそうな場合は 의 を残す。',
    ),
  '에게 / 한테 / 께': L(
      'Three variants of "to/for (a person)" — Korean uses a different particle for people than for places. 에게 is written/neutral, 한테 is the spoken default (친구한테 줬어요), 께 is honorific for elders and superiors (선생님께 드렸어요 — usually paired with 드리다 not 주다).\n\nFor places, use 에 instead (학교에 가요, not 학교에게). The mirror image "from a person" is 에게서 / 한테서 / 께(서) (친구한테서 받았어요 "I received it from a friend").',
      'Tres variantes de "a / para (una persona)" — el coreano usa partículas distintas para personas y para lugares. 에게 es escrito/neutro, 한테 es lo normal hablado (친구한테 줬어요), y 께 es honorífico para mayores o superiores (선생님께 드렸어요 — suele ir con 드리다, no con 주다).\n\nPara lugares usa 에 (학교에 가요, no 학교에게). El espejo "desde una persona" es 에게서 / 한테서 / 께(서) (친구한테서 받았어요 "lo recibí de un amigo").',
      'Trois variantes de « à / pour (une personne) » — le coréen distingue les particules pour les personnes et pour les lieux. 에게 est écrit/neutre, 한테 est le choix oral courant (친구한테 줬어요), 께 est honorifique pour les aînés ou supérieurs (선생님께 드렸어요 — généralement avec 드리다, pas 주다).\n\nPour un lieu, employer 에 (학교에 가요, et non 학교에게). La forme miroir « de la part de quelqu\'un » est 에게서 / 한테서 / 께(서) (친구한테서 받았어요 « je l\'ai reçu d\'un ami »).',
      'Três variantes de "para / a (uma pessoa)" — coreano usa partículas diferentes para pessoas e lugares. 에게 é escrita/neutra, 한테 é o padrão falado (친구한테 줬어요), 께 é honorífica para mais velhos ou superiores (선생님께 드렸어요 — costuma ir com 드리다, não 주다).\n\nPara lugares use 에 (학교에 가요, não 학교에게). O espelho "de uma pessoa" é 에게서 / 한테서 / 께(서) (친구한테서 받았어요 "recebi de um amigo").',
      'สามรูปแบบของ "ให้/แก่ (คน)" — เกาหลีใช้อนุภาคต่างกันสำหรับคนและสถานที่. 에게 เป็นทางการ/กลาง, 한테 ใช้พูดทั่วไป (친구한테 줬어요), 께 เป็นรูปยกย่องสำหรับผู้อาวุโส/ผู้ใหญ่ (선생님께 드렸어요 — มักใช้คู่กับ 드리다 ไม่ใช่ 주다).\n\nสำหรับสถานที่ใช้ 에 แทน (학교에 가요 ไม่ใช่ 학교에게). รูปสวนทาง "จากคน" คือ 에게서 / 한테서 / 께(서) (친구한테서 받았어요 "ฉันได้รับจากเพื่อน")',
      'Tiga varian "kepada/untuk (orang)" — Korea memakai partikel berbeda untuk orang dan tempat. 에게 formal/netral, 한테 standar percakapan (친구한테 줬어요), 께 hormat untuk orang yang lebih tua atau atasan (선생님께 드렸어요 — biasanya dengan 드리다 bukan 주다).\n\nUntuk tempat pakai 에 (학교에 가요, bukan 학교에게). Kebalikannya "dari seseorang" adalah 에게서 / 한테서 / 께(서) (친구한테서 받았어요 "saya menerimanya dari teman").',
      'Ba biến thể của "cho/đến (người)" — tiếng Hàn dùng tiểu từ khác nhau cho người và cho địa điểm. 에게 trang trọng/trung tính, 한테 chuẩn khẩu ngữ (친구한테 줬어요), 께 kính ngữ cho người lớn tuổi hoặc cấp trên (선생님께 드렸어요 — thường đi với 드리다 chứ không phải 주다).\n\nVới địa điểm dùng 에 (학교에 가요, không phải 학교에게). Dạng ngược lại "từ ai đó" là 에게서 / 한테서 / 께(서) (친구한테서 받았어요 "tôi nhận từ bạn").',
      '人への「に」の3形式 — 韓国語は人と場所で助詞を変える。에게 は文語・中立、한테 は会話の標準(친구한테 줬어요)、께 は尊敬形で目上に使う(선생님께 드렸어요 — 通常は 주다 ではなく 드리다 と組み合わせる)。\n\n場所には 에 を使う(학교에 가요、학교에게 とは言わない)。「〜から(人)」の対になる形は 에게서 / 한테서 / 께(서)(친구한테서 받았어요「友達からもらった」)。',
    ),
  '(으)로': L(
      'Multipurpose: (1) direction — "toward" (서울로 가요 "head toward Seoul"); (2) means or vehicle — "by" (버스로, 지하철로); (3) instrument — "with" (펜으로 써요 "write with a pen"); (4) conversion or language — "into" (한국어로 말해요 "speak in Korean"). Form: 로 after a vowel or ㄹ-final (지하철로), 으로 after any other consonant (가위로 "with scissors").\n\nDistinguish from 에: 에 marks a specific endpoint or static spot, while (으)로 marks the direction or route you take to get there.',
      'Multiuso: (1) dirección — "hacia" (서울로 가요 "ir hacia Seúl"); (2) medio o vehículo — "en" (버스로, 지하철로); (3) instrumento — "con" (펜으로 써요 "escribir con un bolígrafo"); (4) conversión o idioma — "a" (한국어로 말해요 "hablar en coreano"). Forma: 로 tras vocal o ㄹ final (지하철로), 으로 tras cualquier otra consonante (가위로 "con tijeras").\n\nSe distingue de 에: 에 marca un punto final concreto o lugar estático, mientras que (으)로 marca la dirección o la ruta por la que vas.',
      'Polyvalente : (1) direction — « vers » (서울로 가요 « aller vers Séoul ») ; (2) moyen ou véhicule — « en » (버스로, 지하철로) ; (3) instrument — « avec » (펜으로 써요 « écrire avec un stylo ») ; (4) conversion ou langue — « en » (한국어로 말해요 « parler en coréen »). Forme : 로 après voyelle ou final ㄹ (지하철로), 으로 après toute autre consonne (가위로 « avec des ciseaux »).\n\nÀ distinguer de 에 : 에 marque un point d\'arrivée précis ou un lieu statique, alors que (으)로 marque la direction ou le trajet.',
      'Multifunção: (1) direção — "em direção a" (서울로 가요 "ir em direção a Seul"); (2) meio ou veículo — "de" (버스로, 지하철로); (3) instrumento — "com" (펜으로 써요 "escrever com caneta"); (4) conversão ou idioma — "em" (한국어로 말해요 "falar em coreano"). Forma: 로 depois de vogal ou final ㄹ (지하철로), 으로 depois de qualquer outra consoante (가위로 "com tesoura").\n\nDistingue-se de 에: 에 marca um ponto final específico ou local estático, enquanto (으)로 marca a direção ou o caminho.',
      'ใช้ได้หลายความหมาย: (1) ทิศทาง — "ไปทาง" (서울로 가요 "มุ่งหน้าสู่โซล"); (2) วิธี/พาหนะ — "ด้วย" (버스로, 지하철로); (3) เครื่องมือ — "ด้วย" (펜으로 써요 "เขียนด้วยปากกา"); (4) การแปลง/ภาษา — "เป็น" (한국어로 말해요 "พูดเป็นภาษาเกาหลี"). รูป: 로 หลังสระหรือพยัญชนะท้าย ㄹ (지하철로), 으로 หลังพยัญชนะอื่น (가위로 "ด้วยกรรไกร").\n\nต่างจาก 에: 에 บอกจุดปลายทางหรือที่ตั้งแบบหยุดนิ่ง ส่วน (으)로 บอกทิศทางหรือเส้นทาง',
      'Serbaguna: (1) arah — "menuju" (서울로 가요 "menuju Seoul"); (2) cara atau kendaraan — "dengan/naik" (버스로, 지하철로); (3) alat — "dengan" (펜으로 써요 "menulis dengan pena"); (4) konversi atau bahasa — "ke dalam" (한국어로 말해요 "berbicara dalam bahasa Korea"). Bentuk: 로 setelah vokal atau akhir ㄹ (지하철로), 으로 setelah konsonan lain (가위로 "dengan gunting").\n\nBeda dengan 에: 에 menandai titik akhir spesifik atau tempat statis, sedangkan (으)로 menandai arah atau rute yang ditempuh.',
      'Đa dụng: (1) hướng — "về phía" (서울로 가요 "đi về phía Seoul"); (2) phương tiện hoặc cách — "bằng" (버스로, 지하철로); (3) công cụ — "bằng" (펜으로 써요 "viết bằng bút"); (4) chuyển đổi hoặc ngôn ngữ — "thành/ra" (한국어로 말해요 "nói bằng tiếng Hàn"). Hình thức: 로 sau nguyên âm hoặc ㄹ cuối (지하철로), 으로 sau bất kỳ phụ âm nào khác (가위로 "bằng kéo").\n\nKhác với 에: 에 đánh dấu điểm đến cụ thể hoặc vị trí tĩnh, còn (으)로 đánh dấu hướng đi hoặc tuyến đường.',
      '多用途: (1) 方向 — 「〜の方へ」(서울로 가요「ソウルの方へ行く」); (2) 手段・乗り物 — 「〜で」(버스로、지하철로); (3) 道具 — 「〜で」(펜으로 써요「ペンで書く」); (4) 変換・言語 — 「〜に／で」(한국어로 말해요「韓国語で話す」)。形: 母音または ㄹ で終わる名詞には 로(지하철로)、その他の子音には 으로(가위로「ハサミで」)。\n\n에 との区別: 에 は具体的な到達点や静的な位置、(으)로 は向かう方向や経路。',
    ),
  '부터 / 까지': L(
      '부터 marks the START of a range, 까지 marks the END. Used for time (9시부터 5시까지) or space (서울에서부터 부산까지 — note the 에서부터 stack when both motion and start point apply). They show up alone too: 지금부터 "from now on", 다음 주까지 "by next week". 까지 has a secondary "even, all the way to" sense beyond range (저까지 도와줬어요 "they even helped me").\n\nDon\'t confuse 부터 with 에서: 부터 is purely a starting point on a scale, 에서 is the location of an action or geographic origin.',
      '부터 marca el INICIO de un rango, 까지 marca el FIN. Para tiempo (9시부터 5시까지) o espacio (서울에서부터 부산까지 — notá la combinación 에서부터 cuando hay tanto movimiento como punto de partida). Aparecen también solas: 지금부터 "desde ahora", 다음 주까지 "para la próxima semana". 까지 tiene un sentido extra de "incluso / hasta" más allá del rango (저까지 도와줬어요 "incluso me ayudaron").\n\nNo confundas 부터 con 에서: 부터 es puramente el punto de inicio en una escala, 에서 es el lugar de una acción o el origen geográfico.',
      '부터 marque le DÉBUT d\'une plage, 까지 la FIN. S\'emploie pour le temps (9시부터 5시까지) ou l\'espace (서울에서부터 부산까지 — noter la combinaison 에서부터 quand mouvement et point de départ coïncident). Apparaissent seuls aussi : 지금부터 « à partir de maintenant », 다음 주까지 « d\'ici la semaine prochaine ». 까지 a en plus le sens « même, jusqu\'à » au-delà d\'une plage (저까지 도와줬어요 « ils m\'ont même aidé »).\n\nNe pas confondre 부터 et 에서 : 부터 est un point de départ sur une échelle, 에서 est le lieu d\'une action ou l\'origine géographique.',
      '부터 marca o INÍCIO de um intervalo, 까지 marca o FIM. Para tempo (9시부터 5시까지) ou espaço (서울에서부터 부산까지 — note a combinação 에서부터 quando há movimento e ponto inicial juntos). Aparecem sozinhos também: 지금부터 "a partir de agora", 다음 주까지 "até a próxima semana". 까지 tem um sentido extra de "até mesmo / todo o caminho até" além de intervalo (저까지 도와줬어요 "eles até me ajudaram").\n\nNão confunda 부터 com 에서: 부터 é apenas o ponto inicial numa escala, 에서 é o lugar de uma ação ou origem geográfica.',
      '부터 บอกจุด "เริ่มต้น" ของช่วง, 까지 บอก "สิ้นสุด". ใช้กับเวลา (9시부터 5시까지) หรือพื้นที่ (서울에서부터 부산까지 — สังเกตการซ้อน 에서부터 เมื่อมีทั้งการเคลื่อนที่และจุดเริ่มต้น). ใช้เดี่ยว ๆ ก็ได้: 지금부터 "ตั้งแต่ตอนนี้", 다음 주까지 "ภายในสัปดาห์หน้า". 까지 มีความหมายเพิ่มเติม "ถึงขนาด/แม้แต่" นอกเหนือจากการบอกช่วง (저까지 도와줬어요 "เขาช่วยฉันถึงขนาดนั้น").\n\nอย่าสับสน 부터 กับ 에서: 부터 คือจุดเริ่มต้นบนสเกล ส่วน 에서 คือสถานที่เกิดการกระทำหรือต้นทางทางภูมิศาสตร์',
      '부터 menandai AWAL rentang, 까지 menandai AKHIRnya. Untuk waktu (9시부터 5시까지) atau ruang (서울에서부터 부산까지 — perhatikan tumpukan 에서부터 ketika gerakan dan titik awal bertepatan). Bisa muncul sendiri: 지금부터 "mulai sekarang", 다음 주까지 "sampai minggu depan". 까지 punya makna tambahan "bahkan / sampai sejauh itu" di luar rentang (저까지 도와줬어요 "mereka bahkan membantu saya").\n\nJangan tertukar 부터 dengan 에서: 부터 murni titik awal pada skala, 에서 adalah tempat aksi atau asal geografis.',
      '부터 đánh dấu KHỞI ĐẦU của một khoảng, 까지 đánh dấu KẾT THÚC. Dùng cho thời gian (9시부터 5시까지) hoặc không gian (서울에서부터 부산까지 — chú ý sự chồng 에서부터 khi có cả chuyển động lẫn điểm xuất phát). Đứng một mình cũng được: 지금부터 "từ bây giờ", 다음 주까지 "đến tuần sau". 까지 còn có nghĩa phụ "thậm chí / đến mức" ngoài chỉ khoảng (저까지 도와줬어요 "họ thậm chí giúp tôi").\n\nĐừng nhầm 부터 với 에서: 부터 thuần túy là điểm bắt đầu trên thang, 에서 là nơi xảy ra hành động hay nguồn gốc địa lý.',
      '부터 は範囲の「始まり」、까지 は「終わり」を示す。時間(9시부터 5시까지)にも空間(서울에서부터 부산까지 — 移動と始点が重なるときは 에서부터 と重ねる)にも使う。単独でも現れる: 지금부터「今から」、다음 주까지「来週まで」。까지 には範囲を超えた「〜まで／〜さえも」の含意もある(저까지 도와줬어요「私(のような者)まで助けてくれた」)。\n\n부터 と 에서 を混同しないこと: 부터 は尺度上の起点、에서 は動作の場所や地理的出発点。',
    ),
  '마다': L(
      'Attaches to a noun and means "every" or "each, individually" — covers both regular repetition (날마다 "every day", 주말마다 "every weekend") and distributive variation (사람마다 달라요 "it differs from person to person").\n\nVery close in meaning to the 매- prefix forms (날마다 ≈ 매일, 해마다 ≈ 매년), but 마다 attaches to native Korean roots while 매- pairs with Sino-Korean roots and forms a single word. 마다 doesn\'t require any additional case particle — don\'t stack 을/를 or 이/가 after it.',
      'Se añade a un sustantivo y significa "cada / todos los" — cubre tanto la repetición regular (날마다 "todos los días", 주말마다 "cada fin de semana") como la variación distributiva (사람마다 달라요 "varía de persona en persona").\n\nMuy cercano a las formas con prefijo 매- (날마다 ≈ 매일, 해마다 ≈ 매년), pero 마다 se pega a raíces coreanas nativas, mientras 매- va con raíces sino-coreanas formando una sola palabra. 마다 no requiere partícula de caso adicional — no apiles 을/를 o 이/가 detrás.',
      'S\'attache à un nom et signifie « chaque / tous les » — couvre la répétition régulière (날마다 « tous les jours », 주말마다 « chaque week-end ») comme la variation distributive (사람마다 달라요 « ça varie d\'une personne à l\'autre »).\n\nTrès proche des formes en préfixe 매- (날마다 ≈ 매일, 해마다 ≈ 매년), mais 마다 se rattache aux racines coréennes natives, alors que 매- s\'associe aux racines sino-coréennes et forme un seul mot. 마다 n\'a besoin d\'aucune autre particule casuelle — ne pas empiler 을/를 ni 이/가 derrière.',
      'Anexa-se a um substantivo e significa "cada / todos os" — cobre tanto a repetição regular (날마다 "todos os dias", 주말마다 "cada fim de semana") quanto a variação distributiva (사람마다 달라요 "varia de pessoa para pessoa").\n\nBem próximo das formas com prefixo 매- (날마다 ≈ 매일, 해마다 ≈ 매년), mas 마다 anexa-se a raízes coreanas nativas, enquanto 매- vai com raízes sino-coreanas formando uma única palavra. 마다 não exige partícula de caso adicional — não empilhe 을/를 ou 이/가 atrás.',
      'ใส่หลังคำนามและแปลว่า "ทุก/แต่ละ" — ครอบคลุมทั้งการเกิดซ้ำสม่ำเสมอ (날마다 "ทุกวัน", 주말마다 "ทุกสุดสัปดาห์") และความแตกต่างแบบกระจาย (사람마다 달라요 "แต่ละคนต่างกัน").\n\nใกล้กับรูปคำเติมหน้า 매- มาก (날마다 ≈ 매일, 해마다 ≈ 매년) แต่ 마다 ใช้กับรากศัพท์เกาหลีแท้ ส่วน 매- ใช้กับรากศัพท์จีน-เกาหลีและกลายเป็นคำเดียว. 마다 ไม่ต้องการอนุภาคบ่งกรณีเพิ่มเติม — ห้ามใส่ 을/를 หรือ 이/가 ตามหลัง',
      'Menempel pada kata benda dan berarti "setiap" — mencakup pengulangan teratur (날마다 "setiap hari", 주말마다 "setiap akhir pekan") dan variasi distributif (사람마다 달라요 "berbeda-beda tiap orang").\n\nSangat mirip bentuk dengan prefiks 매- (날마다 ≈ 매일, 해마다 ≈ 매년), tetapi 마다 menempel pada akar Korea asli, sedangkan 매- berpasangan dengan akar Sino-Korea dan membentuk satu kata. 마다 tidak butuh partikel kasus tambahan — jangan tumpuk 을/를 atau 이/가 setelahnya.',
      'Gắn vào danh từ và có nghĩa "mỗi / từng" — bao gồm cả lặp lại đều đặn (날마다 "mỗi ngày", 주말마다 "mỗi cuối tuần") lẫn biến thiên phân phối (사람마다 달라요 "mỗi người mỗi khác").\n\nRất gần với các dạng tiền tố 매- (날마다 ≈ 매일, 해마다 ≈ 매년), nhưng 마다 đi với gốc Hàn thuần, còn 매- đi với gốc Hán-Hàn tạo thành một từ. 마다 không cần tiểu từ chỉ cách bổ sung — đừng chồng 을/를 hay 이/가 phía sau.',
      '名詞に付いて「〜ごとに／毎〜」を表し、規則的な反復(날마다「毎日」、주말마다「週末ごとに」)も分配的な多様性(사람마다 달라요「人によって違う」)も両方カバーする。\n\n매- 接頭辞形(날마다 ≈ 매일、해마다 ≈ 매년)とほぼ同義だが、마다 は固有語の語根、매- は漢字語の語根に付いて一語化する点が違う。마다 の後ろに 을/를 や 이/가 などの格助詞を重ねる必要はない(重ねない)。',
    ),
  '(이)나': L(
      'Two distinct uses sharing one form: (1) "or" between nouns — A 또는 B in formal contexts becomes A(이)나 B in everyday speech (커피나 차 "coffee or tea"); (2) "as many/much as" with quantity expressions, signaling surprise that the number is high (사람이 백 명이나 왔어요 "as many as 100 people came"). Form: 이나 after a consonant, 나 after a vowel.\n\nFor "or" between verbs or clauses use -거나 instead (가거나 말거나 "whether you go or not"). The casual conversational alternative for "or" is 아니면 ("or else").',
      'Dos usos distintos con la misma forma: (1) "o" entre sustantivos — A 또는 B en contextos formales se vuelve A(이)나 B en habla cotidiana (커피나 차 "café o té"); (2) "hasta / nada menos que" con cantidades, expresando sorpresa porque el número es alto (사람이 백 명이나 왔어요 "vinieron nada menos que 100 personas"). Forma: 이나 tras consonante, 나 tras vocal.\n\nPara "o" entre verbos o cláusulas se usa -거나 (가거나 말거나 "vayas o no"). La alternativa coloquial para "o" es 아니면 ("o si no").',
      'Deux emplois distincts pour une même forme : (1) « ou » entre noms — A 또는 B en contexte formel devient A(이)나 B à l\'oral courant (커피나 차 « café ou thé ») ; (2) « pas moins de / autant que » avec une quantité, marquant la surprise que le chiffre soit élevé (사람이 백 명이나 왔어요 « pas moins de 100 personnes sont venues »). Forme : 이나 après consonne, 나 après voyelle.\n\nPour « ou » entre verbes ou propositions, on emploie -거나 (가거나 말거나 « que tu y ailles ou non »). L\'alternative parlée pour « ou » est 아니면 (« ou alors »).',
      'Dois usos distintos com a mesma forma: (1) "ou" entre substantivos — A 또는 B em contextos formais vira A(이)나 B na fala do dia a dia (커피나 차 "café ou chá"); (2) "uns / até" com expressões de quantidade, sinalizando surpresa porque o número é alto (사람이 백 명이나 왔어요 "vieram uns 100 pessoas/até 100 pessoas vieram"). Forma: 이나 depois de consoante, 나 depois de vogal.\n\nPara "ou" entre verbos ou orações use -거나 (가거나 말거나 "queira ir ou não"). A alternativa coloquial para "ou" é 아니면 ("ou então").',
      'มีสองความหมายต่างกันในรูปเดียว: (1) "หรือ" ระหว่างคำนาม — A 또는 B ในบริบททางการ กลายเป็น A(이)나 B ในภาษาพูดทั่วไป (커피나 차 "กาแฟหรือชา"); (2) "ตั้ง / มากถึง" กับการบอกปริมาณ บ่งบอกความรู้สึกว่าตัวเลขมากเกินคาด (사람이 백 명이나 왔어요 "คนมาตั้ง 100 คน"). รูป: 이나 หลังพยัญชนะ, 나 หลังสระ.\n\nถ้าจะแปลว่า "หรือ" ระหว่างกริยา/อนุประโยค ให้ใช้ -거나 แทน (가거나 말거나 "จะไปหรือไม่"). ทางเลือกในการพูด "หรือ" แบบกันเองคือ 아니면',
      'Dua penggunaan berbeda dalam bentuk yang sama: (1) "atau" antar kata benda — A 또는 B di konteks formal menjadi A(이)나 B di percakapan sehari-hari (커피나 차 "kopi atau teh"); (2) "sampai / sebanyak" dengan ekspresi jumlah, menyiratkan kejutan karena angkanya besar (사람이 백 명이나 왔어요 "sampai 100 orang yang datang"). Bentuk: 이나 setelah konsonan, 나 setelah vokal.\n\nUntuk "atau" antar verba atau klausa, pakai -거나 (가거나 말거나 "mau pergi atau tidak"). Alternatif percakapan untuk "atau" adalah 아니면 ("kalau tidak").',
      'Hai cách dùng riêng biệt trong cùng một dạng: (1) "hoặc" giữa danh từ — A 또는 B trong văn bản trang trọng trở thành A(이)나 B trong khẩu ngữ (커피나 차 "cà phê hay trà"); (2) "đến tận / nhiều như" với biểu thức số lượng, ngụ ý ngạc nhiên vì con số lớn (사람이 백 명이나 왔어요 "đến tận 100 người tới"). Hình thức: 이나 sau phụ âm, 나 sau nguyên âm.\n\nĐể nối "hoặc" giữa các động từ hoặc mệnh đề, dùng -거나 (가거나 말거나 "đi hay không cũng được"). Lựa chọn thân mật cho "hoặc" trong nói chuyện là 아니면.',
      '同じ形に二つの用法がある: (1) 名詞間の「〜か」— 文語の A 또는 B が日常会話では A(이)나 B になる(커피나 차「コーヒーかお茶」); (2) 数量表現に付いて「〜も」— 数の多さに対する驚きを表す(사람이 백 명이나 왔어요「100人もの人が来た」)。形: 子音の後は 이나、母音の後は 나。\n\n動詞・節を「〜か」でつなぐ場合は -거나 を使う(가거나 말거나「行くか行かないか」)。話し言葉の「あるいは」は 아니면。',
    ),
  '이다 / 아니다': L(
      'The noun copula — attaches directly to a noun to mean "to be (something)" (identity / category), NOT location (that\'s 있다). 이다 is the affirmative, 아니다 the negative. Polite forms: 이다 → 이에요 after a consonant (학생이에요), 예요 after a vowel (의자예요); formal -ㅂ니다 form is 입니다.\n\n아니다 is special: it requires the noun to take 이/가 before it (저는 학생이 아니에요 "I am not a student"), unlike 이다 which attaches directly. The formal negative is 아닙니다.',
      'Cópula nominal — se pega directamente a un sustantivo para significar "ser (algo)" (identidad / categoría), NO ubicación (para eso está 있다). 이다 es la afirmativa, 아니다 la negativa. Formas educadas: 이다 → 이에요 tras consonante (학생이에요), 예요 tras vocal (의자예요); la forma formal -ㅂ니다 es 입니다.\n\n아니다 es especial: requiere que el sustantivo lleve 이/가 antes (저는 학생이 아니에요 "no soy estudiante"), a diferencia de 이다 que se pega directo. La negativa formal es 아닙니다.',
      'Copule nominale — s\'attache directement à un nom pour signifier « être (quelque chose) » (identité / catégorie), PAS un emplacement (qui prend 있다). 이다 est l\'affirmatif, 아니다 le négatif. Formes polies : 이다 → 이에요 après consonne (학생이에요), 예요 après voyelle (의자예요) ; la forme formelle -ㅂ니다 est 입니다.\n\n아니다 est spécial : le nom doit prendre 이/가 devant lui (저는 학생이 아니에요 « je ne suis pas étudiant »), contrairement à 이다 qui s\'attache directement. Le négatif formel est 아닙니다.',
      'Cópula nominal — anexa-se diretamente a um substantivo para significar "ser (algo)" (identidade / categoria), NÃO localização (para isso é 있다). 이다 é a afirmativa, 아니다 a negativa. Formas educadas: 이다 → 이에요 depois de consoante (학생이에요), 예요 depois de vogal (의자예요); a forma formal -ㅂ니다 é 입니다.\n\n아니다 é especial: exige que o substantivo leve 이/가 antes (저는 학생이 아니에요 "não sou estudante"), diferente de 이다 que se anexa direto. A negativa formal é 아닙니다.',
      'คำกริยานุเคราะห์ของคำนาม — เกาะติดคำนามโดยตรงเพื่อแปลว่า "เป็น/คือ (อะไรบางอย่าง)" (บอกตัวตน/ประเภท) ไม่ใช่ที่อยู่ (ที่อยู่ใช้ 있다). 이다 รูปบอกเล่า, 아니다 รูปปฏิเสธ. รูปสุภาพ: 이다 → 이에요 หลังพยัญชนะ (학생이에요), 예요 หลังสระ (의자예요); รูปทางการ -ㅂ니다 คือ 입니다.\n\n아니다 พิเศษ: ต้องใส่ 이/가 หลังคำนามก่อน (저는 학생이 아니에요 "ฉันไม่ใช่นักเรียน") ต่างจาก 이다 ที่เกาะติดตรง ๆ. รูปปฏิเสธทางการคือ 아닙니다',
      'Kopula nomina — menempel langsung pada kata benda untuk berarti "menjadi/adalah (sesuatu)" (identitas / kategori), BUKAN lokasi (itu 있다). 이다 bentuk afirmatif, 아니다 negatif. Bentuk sopan: 이다 → 이에요 setelah konsonan (학생이에요), 예요 setelah vokal (의자예요); bentuk formal -ㅂ니다 adalah 입니다.\n\n아니다 istimewa: kata bendanya wajib pakai 이/가 sebelumnya (저는 학생이 아니에요 "saya bukan pelajar"), berbeda dari 이다 yang menempel langsung. Negatif formalnya 아닙니다.',
      'Hệ từ danh từ — gắn thẳng vào danh từ để nghĩa "là (cái gì)" (định danh / phân loại), KHÔNG phải vị trí (vị trí dùng 있다). 이다 dạng khẳng định, 아니다 dạng phủ định. Dạng lịch sự: 이다 → 이에요 sau phụ âm (학생이에요), 예요 sau nguyên âm (의자예요); dạng trang trọng -ㅂ니다 là 입니다.\n\n아니다 đặc biệt: danh từ trước nó phải có 이/가 (저는 학생이 아니에요 "tôi không phải là học sinh"), khác với 이다 gắn trực tiếp. Phủ định trang trọng là 아닙니다.',
      '名詞文の繋辞 — 名詞に直接付いて「〜である」(同定・分類)を表す。所在ではない(所在は 있다)。이다 が肯定、아니다 が否定。丁寧形: 이다 は子音語幹で 이에요(학생이에요)、母音語幹で 예요(의자예요)、フォーマルな -ㅂ니다 形は 입니다。\n\n아니다 は特殊で、前の名詞に 이/가 が必要(저는 학생이 아니에요「私は学生ではない」)、이다 のように直接付かない。フォーマルな否定は 아닙니다。',
    ),
  '있다 / 없다': L(
      'Double-duty verb covering both "to exist / be located" (책상 위에 책이 있어요 "there is a book on the desk") and "to have / possess" (시간이 있어요 "I have time"). 없다 is the matching negative for both senses. The thing existed-or-possessed takes 이/가, NOT 을/를 — 시간이 있어요/없어요, never 시간을.\n\nDistinguish from 이다 (noun copula, identity) and from "live/dwell" 살다 (residence). Honorific for people: 있다 → 계시다 (할아버지가 계세요 "grandfather is here / has it"); 없다 → 안 계시다.',
      'Verbo de doble función: "existir / estar (en un lugar)" (책상 위에 책이 있어요 "hay un libro sobre el escritorio") y "tener / poseer" (시간이 있어요 "tengo tiempo"). 없다 es la negativa para ambos sentidos. Lo que existe o se posee lleva 이/가, NUNCA 을/를 — 시간이 있어요/없어요, no 시간을.\n\nDistinguilo de 이다 (cópula nominal, identidad) y de 살다 (residir). Honorífico para personas: 있다 → 계시다 (할아버지가 계세요 "el abuelo está/tiene"); 없다 → 안 계시다.',
      'Verbe à double emploi : « exister / se trouver » (책상 위에 책이 있어요 « il y a un livre sur le bureau ») et « avoir / posséder » (시간이 있어요 « j\'ai du temps »). 없다 est le négatif des deux sens. Ce qui existe ou est possédé prend 이/가, PAS 을/를 — 시간이 있어요/없어요, jamais 시간을.\n\nÀ distinguer de 이다 (copule nominale, identité) et de 살다 (résider). Honorifique pour les personnes : 있다 → 계시다 (할아버지가 계세요 « grand-père est là / l\'a ») ; 없다 → 안 계시다.',
      'Verbo de função dupla: "existir / estar (em um lugar)" (책상 위에 책이 있어요 "há um livro sobre a mesa") e "ter / possuir" (시간이 있어요 "tenho tempo"). 없다 é a negativa para ambos os sentidos. O que existe ou é possuído leva 이/가, NUNCA 을/를 — 시간이 있어요/없어요, não 시간을.\n\nDistinga de 이다 (cópula nominal, identidade) e de 살다 (residir). Honorífico para pessoas: 있다 → 계시다 (할아버지가 계세요 "o avô está aqui / tem"); 없다 → 안 계시다.',
      'กริยาทำหน้าที่คู่: "มี/อยู่ (ในที่ไหน)" (책상 위에 책이 있어요 "มีหนังสืออยู่บนโต๊ะ") และ "มี/ครอบครอง" (시간이 있어요 "ฉันมีเวลา"). 없다 เป็นรูปปฏิเสธของทั้งสองความหมาย. สิ่งที่มีหรือถูกครอบครองใช้ 이/가 ห้ามใช้ 을/를 — 시간이 있어요/없어요 ไม่ใช่ 시간을.\n\nต่างจาก 이다 (กริยานุเคราะห์, ตัวตน) และจาก 살다 (อาศัย). รูปยกย่องสำหรับคน: 있다 → 계시다 (할아버지가 계세요 "คุณปู่อยู่/มี"), 없다 → 안 계시다',
      'Verba dwifungsi: "ada / berada (di suatu tempat)" (책상 위에 책이 있어요 "ada buku di atas meja") dan "punya / memiliki" (시간이 있어요 "saya punya waktu"). 없다 adalah negatif untuk kedua makna. Yang ada atau dimiliki pakai 이/가, BUKAN 을/를 — 시간이 있어요/없어요, bukan 시간을.\n\nBedakan dari 이다 (kopula nomina, identitas) dan dari 살다 (tinggal). Honorifik untuk orang: 있다 → 계시다 (할아버지가 계세요 "kakek ada / punya"); 없다 → 안 계시다.',
      'Động từ kép: "có / ở (đâu đó)" (책상 위에 책이 있어요 "có quyển sách trên bàn") và "có / sở hữu" (시간이 있어요 "tôi có thời gian"). 없다 là dạng phủ định cho cả hai nghĩa. Vật được tồn tại hay sở hữu đi với 이/가, KHÔNG đi với 을/를 — 시간이 있어요/없어요, không phải 시간을.\n\nPhân biệt với 이다 (hệ từ danh từ, định danh) và 살다 (cư trú). Kính ngữ cho người: 있다 → 계시다 (할아버지가 계세요 "ông đang ở đây / có"); 없다 → 안 계시다.',
      '二つの役割を担う動詞: 「存在する／〜にある」(책상 위에 책이 있어요「机の上に本がある」)と「持っている」(시간이 있어요「時間がある」)。없다 は両方の意味の否定。存在する／持っている対象は 이/가 で受け、을/를 ではない — 시간이 있어요/없어요、시간을 とは言わない。\n\n이다(名詞繋辞、同定)とも 살다(居住)とも区別する。人に対する尊敬形: 있다 → 계시다(할아버지가 계세요「祖父がいらっしゃる／お持ちだ」)、없다 → 안 계시다。',
    ),
  '좋아하다 / 싫어하다': L(
      'Active verbs of preference: the thing you like takes 을/를 (음악을 좋아해요), not 이/가. Don\'t confuse with the descriptive adjectives 좋다 "to be good/pleasant" and 싫다 "to be unpleasant", which take 이/가 (음악이 좋아요 ≈ "music is great / I find music nice").\n\nNative speakers shift between the two: 좋다/싫다 describe a sensation, 좋아하다/싫어하다 describe an active stance. Past forms: 좋아했어요, 싫어했어요. Tip: if your sentence would translate naturally as "X is nice/awful (to me)", reach for 좋다/싫다; if it\'s "I like/dislike X", reach for 좋아하다/싫어하다.',
      'Verbos activos de preferencia: lo que te gusta lleva 을/를 (음악을 좋아해요), no 이/가. No confundir con los adjetivos descriptivos 좋다 "ser bueno/agradable" y 싫다 "ser desagradable", que llevan 이/가 (음악이 좋아요 ≈ "la música es buena / me parece buena").\n\nLos nativos alternan los dos: 좋다/싫다 describen una sensación, 좋아하다/싫어하다 describen una postura activa. Pasados: 좋아했어요, 싫어했어요. Tip: si la frase suena natural como "X es agradable/horrible (para mí)", usa 좋다/싫다; si es "me gusta/no me gusta X", usa 좋아하다/싫어하다.',
      'Verbes actifs de préférence : ce qu\'on aime prend 을/를 (음악을 좋아해요), pas 이/가. À ne pas confondre avec les adjectifs descriptifs 좋다 « être bon/agréable » et 싫다 « être désagréable », qui prennent 이/가 (음악이 좋아요 ≈ « la musique est super / je la trouve bien »).\n\nLes natifs alternent les deux : 좋다/싫다 décrivent une sensation, 좋아하다/싫어하다 une attitude active. Passés : 좋아했어요, 싫어했어요. Astuce : si la phrase passe en « X est agréable/horrible (pour moi) », prendre 좋다/싫다 ; si c\'est « j\'aime / je n\'aime pas X », prendre 좋아하다/싫어하다.',
      'Verbos ativos de preferência: o que você gosta leva 을/를 (음악을 좋아해요), não 이/가. Não confunda com os adjetivos descritivos 좋다 "ser bom/agradável" e 싫다 "ser desagradável", que levam 이/가 (음악이 좋아요 ≈ "música é boa / acho legal").\n\nNativos alternam os dois: 좋다/싫다 descrevem uma sensação, 좋아하다/싫어하다 descrevem uma postura ativa. Passado: 좋아했어요, 싫어했어요. Dica: se a frase soa natural como "X é agradável/horrível (para mim)", vá de 좋다/싫다; se for "eu gosto/não gosto de X", vá de 좋아하다/싫어하다.',
      'กริยาแสดงความชอบเชิงกระทำ: สิ่งที่ชอบใส่ 을/를 (음악을 좋아해요) ไม่ใช่ 이/가. อย่าสับสนกับคำคุณศัพท์เชิงพรรณนา 좋다 "ดี/น่าพอใจ" และ 싫다 "ไม่ชอบ/ไม่น่าพอใจ" ซึ่งใช้ 이/가 (음악이 좋아요 ≈ "ดนตรีนี้ดี/ฉันชอบ").\n\nคนเกาหลีสลับใช้สองชุดนี้: 좋다/싫다 บอกความรู้สึก ส่วน 좋아하다/싫어하다 บอกท่าทีเชิงกระทำ. รูปอดีต: 좋아했어요, 싫어했어요. เคล็ดลับ: ถ้าประโยคแปลเป็น "X ดี/แย่ (สำหรับฉัน)" ใช้ 좋다/싫다; ถ้าเป็น "ฉันชอบ/ไม่ชอบ X" ใช้ 좋아하다/싫어하다',
      'Verba aktif preferensi: yang disukai pakai 을/를 (음악을 좋아해요), bukan 이/가. Jangan tertukar dengan adjektiva deskriptif 좋다 "bagus/menyenangkan" dan 싫다 "tidak menyenangkan", yang pakai 이/가 (음악이 좋아요 ≈ "musiknya bagus / saya senang").\n\nPenutur asli berganti-ganti: 좋다/싫다 melukiskan rasa, 좋아하다/싫어하다 sikap aktif. Bentuk lampau: 좋아했어요, 싫어했어요. Tips: kalau kalimat terasa wajar sebagai "X bagus/jelek (bagi saya)", pakai 좋다/싫다; kalau "saya suka/tidak suka X", pakai 좋아하다/싫어하다.',
      'Động từ chủ động chỉ sở thích: cái bạn thích đi với 을/를 (음악을 좋아해요), không phải 이/가. Đừng nhầm với tính từ miêu tả 좋다 "tốt/dễ chịu" và 싫다 "khó chịu/ghét", vốn đi với 이/가 (음악이 좋아요 ≈ "âm nhạc tuyệt / tôi thấy hay").\n\nNgười Hàn dùng xen kẽ: 좋다/싫다 tả cảm giác, 좋아하다/싫어하다 tả thái độ chủ động. Quá khứ: 좋아했어요, 싫어했어요. Mẹo: nếu câu hợp lý khi dịch "X dễ chịu/khó chịu (với tôi)", dùng 좋다/싫다; nếu là "tôi thích / không thích X", dùng 좋아하다/싫어하다.',
      '能動的な好悪動詞: 好きな対象は 을/를 で受ける(음악을 좋아해요)、이/가 ではない。これと対になる描写形容詞の 좋다「良い／好ましい」と 싫다「いやだ」は 이/가 で受ける(음악이 좋아요 ≈「音楽がいい／私は好き」)。\n\nネイティブはこの二系統を使い分ける: 좋다/싫다 は感覚を描写、좋아하다/싫어하다 は能動的な態度を述べる。過去形: 좋아했어요、싫어했어요。コツ: 「(私にとって)Xは良い／いやだ」と訳して自然なら 좋다/싫다、「Xが好きだ／嫌いだ」と訳して自然なら 좋아하다/싫어하다。',
    ),
  '-아/어요': L(
      "The default polite register (해요체) — used in almost every adult conversation: with strangers, colleagues, anyone slightly older. Pick the vowel by harmony: 아요 if the stem's last vowel is ㅏ or ㅗ (받다 → 받아요), 어요 otherwise (먹다 → 먹어요).\n\nVowel contractions: 가다 → 가요 (not 가아요), 오다 → 와요, 마시다 → 마셔요, 배우다 → 배워요, 되다 → 돼요. 하다 verbs become 해요 (공부하다 → 공부해요). Watch for irregulars: ㅂ-verbs (춥다 → 추워요), ㅡ-elision (바쁘다 → 바빠요, 예쁘다 → 예뻐요), 르-doubling (모르다 → 몰라요, 빠르다 → 빨라요).",
      'El registro educado por defecto (해요체) — el que usás en casi toda conversación adulta: con desconocidos, compañeros de trabajo, alguien apenas mayor. La vocal sale por armonía: 아요 si la última vocal del raíz es ㅏ o ㅗ (받다 → 받아요), 어요 en cualquier otro caso (먹다 → 먹어요).\n\nContracciones de vocales: 가다 → 가요 (no 가아요), 오다 → 와요, 마시다 → 마셔요, 배우다 → 배워요, 되다 → 돼요. Los verbos 하다 → 해요 (공부하다 → 공부해요). Cuidado con irregulares: ㅂ-verbos (춥다 → 추워요), elisión de ㅡ (바쁘다 → 바빠요, 예쁘다 → 예뻐요), doblado 르 (모르다 → 몰라요, 빠르다 → 빨라요).',
      'Le registre poli par défaut (해요체) — celui qu\'on emploie dans presque toute conversation adulte : inconnus, collègues, personne légèrement plus âgée. La voyelle suit l\'harmonie : 아요 si la dernière voyelle de la racine est ㅏ ou ㅗ (받다 → 받아요), 어요 sinon (먹다 → 먹어요).\n\nContractions vocaliques : 가다 → 가요 (et non 가아요), 오다 → 와요, 마시다 → 마셔요, 배우다 → 배워요, 되다 → 돼요. Les verbes en 하다 → 해요 (공부하다 → 공부해요). Attention aux irréguliers : verbes en ㅂ (춥다 → 추워요), élision de ㅡ (바쁘다 → 바빠요, 예쁘다 → 예뻐요), doublement 르 (모르다 → 몰라요, 빠르다 → 빨라요).',
      'O registro educado padrão (해요체) — o que se usa em quase toda conversa adulta: estranhos, colegas, alguém ligeiramente mais velho. A vogal sai por harmonia: 아요 se a última vogal do radical é ㅏ ou ㅗ (받다 → 받아요), 어요 nos outros casos (먹다 → 먹어요).\n\nContrações de vogais: 가다 → 가요 (não 가아요), 오다 → 와요, 마시다 → 마셔요, 배우다 → 배워요, 되다 → 돼요. Verbos em 하다 → 해요 (공부하다 → 공부해요). Cuidado com irregulares: verbos em ㅂ (춥다 → 추워요), elisão de ㅡ (바쁘다 → 바빠요, 예쁘다 → 예뻐요), duplicação 르 (모르다 → 몰라요, 빠르다 → 빨라요).',
      'รูปสุภาพมาตรฐาน (해요체) — ใช้ในการสนทนาผู้ใหญ่เกือบทุกแบบ: คนแปลกหน้า เพื่อนร่วมงาน ผู้ที่อายุมากกว่าเล็กน้อย. เลือกสระตามความกลมกลืน: 아요 ถ้าสระสุดท้ายของรากเป็น ㅏ หรือ ㅗ (받다 → 받아요), 어요 ในกรณีอื่น (먹다 → 먹어요).\n\nการหดของสระ: 가다 → 가요 (ไม่ใช่ 가아요), 오다 → 와요, 마시다 → 마셔요, 배우다 → 배워요, 되다 → 돼요. กริยา 하다 → 해요 (공부하다 → 공부해요). ระวังกลุ่มไม่ปกติ: กริยา ㅂ (춥다 → 추워요), การละ ㅡ (바쁘다 → 바빠요, 예쁘다 → 예뻐요), 르 ซ้ำตัว (모르다 → 몰라요, 빠르다 → 빨라요).',
      'Register sopan default (해요체) — yang dipakai di hampir semua percakapan orang dewasa: orang asing, rekan kerja, orang yang sedikit lebih tua. Vokal mengikuti harmoni: 아요 kalau vokal terakhir akar adalah ㅏ atau ㅗ (받다 → 받아요), 어요 selainnya (먹다 → 먹어요).\n\nKontraksi vokal: 가다 → 가요 (bukan 가아요), 오다 → 와요, 마시다 → 마셔요, 배우다 → 배워요, 되다 → 돼요. Verba 하다 → 해요 (공부하다 → 공부해요). Hati-hati pengecualian: verba ㅂ (춥다 → 추워요), elisi ㅡ (바쁘다 → 바빠요, 예쁘다 → 예뻐요), 르 berlipat (모르다 → 몰라요, 빠르다 → 빨라요).',
      'Cấp độ lịch sự mặc định (해요체) — dùng trong gần như mọi hội thoại người lớn: người lạ, đồng nghiệp, người lớn hơn một chút. Nguyên âm theo hài hòa: 아요 nếu nguyên âm cuối của gốc là ㅏ hoặc ㅗ (받다 → 받아요), 어요 trong các trường hợp khác (먹다 → 먹어요).\n\nCo rút nguyên âm: 가다 → 가요 (không phải 가아요), 오다 → 와요, 마시다 → 마셔요, 배우다 → 배워요, 되다 → 돼요. Động từ 하다 → 해요 (공부하다 → 공부해요). Lưu ý bất quy tắc: động từ ㅂ (춥다 → 추워요), tỉnh lược ㅡ (바쁘다 → 바빠요, 예쁘다 → 예뻐요), 르 nhân đôi (모르다 → 몰라요, 빠르다 → 빨라요).',
      '日常で最もよく使う丁寧体(해요체) — 知らない人、職場の同僚、少し年上の相手など、ほぼすべての大人の会話で標準。母音は調和規則で選ぶ: 語幹末母音が ㅏ・ㅗ なら 아요(받다 → 받아요)、それ以外は 어요(먹다 → 먹어요)。\n\n母音縮約: 가다 → 가요(가아요 ではない)、오다 → 와요、마시다 → 마셔요、배우다 → 배워요、되다 → 돼요。하다 動詞は 해요(공부하다 → 공부해요)。不規則に注意: ㅂ 不規則(춥다 → 추워요)、ㅡ 脱落(바쁘다 → 바빠요、예쁘다 → 예뻐요)、르 二重化(모르다 → 몰라요、빠르다 → 빨라요)。',
    ),
  '-았/었어요': L(
      'Past tense built on top of the -아/어요 stem: same vowel-harmony rule (받다 → 받았어요, 먹다 → 먹었어요) and the same contractions you already know (가다 → 갔어요, 보다 → 봤어요, 마시다 → 마셨어요, 배우다 → 배웠어요, 되다 → 됐어요). 하다 verbs become 했어요.\n\nCovers both completed actions (어제 책을 읽었어요 "I read a book yesterday") and resulting states still relevant now (결혼했어요 "I am married" — Korean uses past where English uses present). For the copula 이다, the past is -이었어요/였어요 (학생이었어요, 친구였어요). Formal version: -았/었습니다.',
      'Pasado construido sobre la raíz de -아/어요: misma regla de armonía vocálica (받다 → 받았어요, 먹다 → 먹었어요) y las mismas contracciones que ya conocés (가다 → 갔어요, 보다 → 봤어요, 마시다 → 마셨어요, 배우다 → 배웠어요, 되다 → 됐어요). Los verbos 하다 → 했어요.\n\nCubre tanto acciones completadas (어제 책을 읽었어요 "ayer leí un libro") como estados resultantes todavía vigentes (결혼했어요 "estoy casado/a" — el coreano usa pasado donde el español usa presente). Para la cópula 이다, el pasado es -이었어요/였어요 (학생이었어요, 친구였어요). Versión formal: -았/었습니다.',
      'Passé construit sur la racine de -아/어요 : même règle d\'harmonie vocalique (받다 → 받았어요, 먹다 → 먹었어요) et mêmes contractions déjà connues (가다 → 갔어요, 보다 → 봤어요, 마시다 → 마셨어요, 배우다 → 배웠어요, 되다 → 됐어요). Les verbes en 하다 → 했어요.\n\nCouvre les actions accomplies (어제 책을 읽었어요 « hier j\'ai lu un livre ») comme les états résultants encore valables (결혼했어요 « je suis marié(e) » — le coréen emploie le passé là où le français préfère le présent). Pour la copule 이다, le passé est -이었어요/였어요 (학생이었어요, 친구였어요). Version formelle : -았/었습니다.',
      'Passado construído sobre o radical de -아/어요: mesma regra de harmonia vocálica (받다 → 받았어요, 먹다 → 먹었어요) e as mesmas contrações que você já conhece (가다 → 갔어요, 보다 → 봤어요, 마시다 → 마셨어요, 배우다 → 배웠어요, 되다 → 됐어요). Verbos 하다 → 했어요.\n\nCobre tanto ações concluídas (어제 책을 읽었어요 "ontem li um livro") quanto estados resultantes ainda válidos (결혼했어요 "sou casado/a" — coreano usa passado onde português usaria presente). Para a cópula 이다, o passado é -이었어요/였어요 (학생이었어요, 친구였어요). Versão formal: -았/었습니다.',
      'รูปอดีตสร้างจากรากของ -아/어요: ใช้กฎความกลมกลืนของสระเดียวกัน (받다 → 받았어요, 먹다 → 먹었어요) และการหดเหมือนเดิม (가다 → 갔어요, 보다 → 봤어요, 마시다 → 마셨어요, 배우다 → 배웠어요, 되다 → 됐어요). กริยา 하다 → 했어요.\n\nใช้กับการกระทำที่จบแล้ว (어제 책을 읽었어요 "เมื่อวานอ่านหนังสือ") และสภาพผลลัพธ์ที่ยังคงอยู่ (결혼했어요 "ฉันแต่งงานแล้ว" — เกาหลีใช้รูปอดีตในที่ที่ภาษาไทยใช้ปัจจุบัน). สำหรับ 이다 รูปอดีตคือ -이었어요/였어요 (학생이었어요, 친구였어요). รูปทางการ: -았/었습니다',
      'Bentuk lampau dibangun di atas akar -아/어요: aturan harmoni vokal yang sama (받다 → 받았어요, 먹다 → 먹었어요) dan kontraksi yang sama (가다 → 갔어요, 보다 → 봤어요, 마시다 → 마셨어요, 배우다 → 배웠어요, 되다 → 됐어요). Verba 하다 → 했어요.\n\nMencakup aksi yang sudah selesai (어제 책을 읽었어요 "kemarin saya baca buku") dan keadaan hasil yang masih berlaku (결혼했어요 "saya sudah menikah" — Korea memakai lampau di tempat Indonesia memakai bentuk kini). Untuk kopula 이다, lampaunya -이었어요/였어요 (학생이었어요, 친구였어요). Versi formal: -았/었습니다.',
      'Quá khứ xây trên gốc -아/어요: cùng quy tắc hài hòa nguyên âm (받다 → 받았어요, 먹다 → 먹었어요) và cùng các co rút bạn đã biết (가다 → 갔어요, 보다 → 봤어요, 마시다 → 마셨어요, 배우다 → 배웠어요, 되다 → 됐어요). Động từ 하다 → 했어요.\n\nDiễn tả cả hành động đã hoàn tất (어제 책을 읽었어요 "hôm qua tôi đã đọc sách") lẫn trạng thái kết quả vẫn còn hiệu lực (결혼했어요 "tôi đã kết hôn / tôi có gia đình" — tiếng Hàn dùng quá khứ ở chỗ tiếng Việt thường dùng hiện tại). Với hệ từ 이다, quá khứ là -이었어요/였어요 (학생이었어요, 친구였어요). Dạng trang trọng: -았/었습니다.',
      '過去形は -아/어요 の語幹に乗せて作る: 同じ母音調和規則(받다 → 받았어요、먹다 → 먹었어요)、同じ縮約(가다 → 갔어요、보다 → 봤어요、마시다 → 마셨어요、배우다 → 배웠어요、되다 → 됐어요)。하다 動詞は 했어요。\n\n完了した動作(어제 책을 읽었어요「昨日本を読んだ」)も、現在まで続く結果状態(결혼했어요「結婚している」— 日本語の現在形に当たる)も両方カバーする。繋辞 이다 の過去は -이었어요/였어요(학생이었어요、친구였어요)。フォーマル形: -았/었습니다。',
    ),
  '-(으)ㄹ 거예요': L(
      'Two meanings the form shares: (1) future intention in 1st person — "I plan to / will" (저는 갈 거예요 "I\'ll go"); (2) supposition about a third party — "they probably will / it must be" (그분이 한국 사람일 거예요 "they\'re probably Korean"). Form: vowel-ending stem → -ㄹ 거예요 (가다 → 갈 거예요); consonant-ending stem → -을 거예요 (먹다 → 먹을 거예요). ㄹ-stems behave like vowel stems (살다 → 살 거예요).\n\nCompare neighbors: -(으)ㄹ게요 commits "I\'ll definitely" (a promise to the listener), -겠- is more abrupt or formal future, -(으)ㄹ 것 같다 hedges as "I think / probably". Formal version: -(으)ㄹ 겁니다.',
      'La misma forma tiene dos sentidos: (1) intención futura en 1ª persona — "voy a / pienso" (저는 갈 거예요 "voy a ir"); (2) suposición sobre tercera persona — "probablemente / debe de" (그분이 한국 사람일 거예요 "esa persona probablemente es coreana"). Forma: raíz terminada en vocal → -ㄹ 거예요 (가다 → 갈 거예요); raíz en consonante → -을 거예요 (먹다 → 먹을 거예요). Las raíces en ㄹ se comportan como las en vocal (살다 → 살 거예요).\n\nComparalo con sus parientes: -(으)ㄹ게요 expresa compromiso "voy a, te lo prometo" (al oyente), -겠- es futuro más cortado o formal, -(으)ㄹ 것 같다 matiza "creo que / probablemente". Versión formal: -(으)ㄹ 겁니다.',
      'Une même forme, deux emplois : (1) intention future à la 1ʳᵉ personne — « je vais / je compte » (저는 갈 거예요 « j\'irai ») ; (2) supposition sur un tiers — « probablement / sans doute » (그분이 한국 사람일 거예요 « cette personne doit être coréenne »). Forme : racine en voyelle → -ㄹ 거예요 (가다 → 갈 거예요) ; racine en consonne → -을 거예요 (먹다 → 먹을 거예요). Les racines en ㄹ se comportent comme celles en voyelle (살다 → 살 거예요).\n\nÀ comparer aux voisins : -(으)ㄹ게요 engage le locuteur envers son interlocuteur (« je vais le faire, promis »), -겠- est plus brusque ou formel, -(으)ㄹ 것 같다 nuance en « je crois / sans doute ». Version formelle : -(으)ㄹ 겁니다.',
      'A mesma forma cobre dois sentidos: (1) intenção futura na 1ª pessoa — "vou / pretendo" (저는 갈 거예요 "vou ir"); (2) suposição sobre terceira pessoa — "provavelmente / deve" (그분이 한국 사람일 거예요 "essa pessoa provavelmente é coreana"). Forma: radical em vogal → -ㄹ 거예요 (가다 → 갈 거예요); radical em consoante → -을 거예요 (먹다 → 먹을 거예요). Radicais em ㄹ se comportam como os em vogal (살다 → 살 거예요).\n\nCompare com os primos: -(으)ㄹ게요 compromisso "vou fazer, prometo" (com o ouvinte), -겠- futuro mais cortante ou formal, -(으)ㄹ 것 같다 atenua para "acho que / provavelmente". Versão formal: -(으)ㄹ 겁니다.',
      'รูปเดียวสองความหมาย: (1) เจตนาในอนาคต บุรุษที่ 1 — "จะ / ตั้งใจจะ" (저는 갈 거예요 "ฉันจะไป"); (2) การคาดเดาเกี่ยวกับบุรุษที่ 3 — "คงจะ / น่าจะ" (그분이 한국 사람일 거예요 "เขาน่าจะเป็นคนเกาหลี"). รูป: ราก末สระ → -ㄹ 거예요 (가다 → 갈 거예요); ราก末พยัญชนะ → -을 거예요 (먹다 → 먹을 거예요). รากที่ลงท้าย ㄹ ปฏิบัติเหมือนลงสระ (살다 → 살 거예요).\n\nเทียบกับเพื่อนบ้าน: -(으)ㄹ게요 คือคำมั่น "จะทำให้ดู" (กับผู้ฟัง), -겠- เป็นอนาคตที่ห้วน/ทางการกว่า, -(으)ㄹ 것 같다 เป็น "คิดว่า / น่าจะ" แบบเลี่ยง. รูปทางการ: -(으)ㄹ 겁니다',
      'Satu bentuk, dua makna: (1) niat masa depan orang pertama — "akan / berencana" (저는 갈 거예요 "saya akan pergi"); (2) dugaan tentang orang ketiga — "mungkin / kira-kira" (그분이 한국 사람일 거예요 "dia mungkin orang Korea"). Bentuk: akar berakhir vokal → -ㄹ 거예요 (가다 → 갈 거예요); akar berakhir konsonan → -을 거예요 (먹다 → 먹을 거예요). Akar ㄹ berperilaku seperti vokal (살다 → 살 거예요).\n\nBandingkan dengan tetangga: -(으)ㄹ게요 janji "saya akan, pasti" (kepada lawan bicara), -겠- masa depan lebih ringkas/formal, -(으)ㄹ 것 같다 melembutkan jadi "saya pikir / mungkin". Versi formal: -(으)ㄹ 겁니다.',
      'Cùng một dạng có hai nghĩa: (1) dự định tương lai ngôi thứ nhất — "sẽ / dự định" (저는 갈 거예요 "tôi sẽ đi"); (2) suy đoán về ngôi thứ ba — "chắc / hẳn là" (그분이 한국 사람일 거예요 "người đó chắc là người Hàn"). Hình thức: gốc kết nguyên âm → -ㄹ 거예요 (가다 → 갈 거예요); gốc kết phụ âm → -을 거예요 (먹다 → 먹을 거예요). Gốc ㄹ hành xử như gốc nguyên âm (살다 → 살 거예요).\n\nSo với hàng xóm: -(으)ㄹ게요 cam kết "tôi sẽ, hứa đó" (với người nghe), -겠- tương lai dứt khoát/trang trọng hơn, -(으)ㄹ 것 같다 giảm nhẹ thành "tôi nghĩ / có lẽ". Dạng trang trọng: -(으)ㄹ 겁니다.',
      '一つの形で二つの意味: (1) 一人称の意志・予定 — 「〜するつもり／〜する」(저는 갈 거예요「行きます」); (2) 三人称への推量 — 「たぶん〜だろう／〜のはずだ」(그분이 한국 사람일 거예요「あの方は韓国人でしょう」)。形: 母音語幹 → -ㄹ 거예요(가다 → 갈 거예요)、子音語幹 → -을 거예요(먹다 → 먹을 거예요)。ㄹ 語幹は母音語幹と同じ扱い(살다 → 살 거예요)。\n\n仲間との対比: -(으)ㄹ게요 は聞き手への約束「〜しますね」、-겠- はより硬い／改まった未来、-(으)ㄹ 것 같다 は「〜だと思う／たぶん〜」と婉曲化する。フォーマル: -(으)ㄹ 겁니다。',
    ),
  '-(으)세요': L(
      'Two functions, same form: (1) polite request to the listener — "please ~" (앉으세요 "please sit"); (2) honorific present statement about a respected subject — (할아버지가 책을 읽으세요 "grandfather is reading"). Form: vowel/ㄹ stem → -세요 (가다 → 가세요, 살다 → 사세요 with ㄹ dropping); consonant stem → -으세요 (앉다 → 앉으세요). Some verbs replace the stem with a special honorific root: 먹다 → 드시다 → 드세요, 자다 → 주무시다 → 주무세요, 있다 → 계시다 → 계세요, 죽다 → 돌아가시다 → 돌아가세요.\n\nNegative request: -지 마세요 ("please don\'t"). Even more formal: -(으)십시오 (announcements, signage).',
      'Una misma forma cumple dos funciones: (1) petición educada al oyente — "por favor..." (앉으세요 "siéntese, por favor"); (2) presente honorífico de un sujeto al que respetás — (할아버지가 책을 읽으세요 "el abuelo está leyendo"). Forma: raíz en vocal o ㄹ → -세요 (가다 → 가세요, 살다 → 사세요 con ㄹ que cae); raíz en consonante → -으세요 (앉다 → 앉으세요). Algunos verbos cambian la raíz por una honorífica especial: 먹다 → 드시다 → 드세요, 자다 → 주무시다 → 주무세요, 있다 → 계시다 → 계세요, 죽다 → 돌아가시다 → 돌아가세요.\n\nPetición negativa: -지 마세요 ("no haga..., por favor"). Más formal aún: -(으)십시오 (anuncios, carteles).',
      'Une même forme remplit deux fonctions : (1) demande polie à l\'interlocuteur — « s\'il vous plaît, ~ » (앉으세요 « asseyez-vous, s\'il vous plaît ») ; (2) présent honorifique pour un sujet qu\'on respecte — (할아버지가 책을 읽으세요 « grand-père lit »). Forme : racine en voyelle ou ㄹ → -세요 (가다 → 가세요, 살다 → 사세요 avec chute du ㄹ) ; racine en consonne → -으세요 (앉다 → 앉으세요). Certains verbes remplacent la racine par une forme honorifique : 먹다 → 드시다 → 드세요, 자다 → 주무시다 → 주무세요, 있다 → 계시다 → 계세요, 죽다 → 돌아가시다 → 돌아가세요.\n\nDemande négative : -지 마세요 (« ne ~ pas, s\'il vous plaît »). Plus formel encore : -(으)십시오 (annonces, signalisation).',
      'Mesma forma, duas funções: (1) pedido educado ao ouvinte — "por favor, ~" (앉으세요 "por favor, sente-se"); (2) presente honorífico sobre um sujeito respeitado — (할아버지가 책을 읽으세요 "o avô está lendo"). Forma: radical em vogal ou ㄹ → -세요 (가다 → 가세요, 살다 → 사세요 com ㄹ caindo); radical em consoante → -으세요 (앉다 → 앉으세요). Alguns verbos trocam o radical por uma raiz honorífica especial: 먹다 → 드시다 → 드세요, 자다 → 주무시다 → 주무세요, 있다 → 계시다 → 계세요, 죽다 → 돌아가시다 → 돌아가세요.\n\nPedido negativo: -지 마세요 ("por favor não ~"). Ainda mais formal: -(으)십시오 (anúncios, placas).',
      'รูปเดียวสองหน้าที่: (1) คำขอสุภาพต่อผู้ฟัง — "กรุณา / โปรด" (앉으세요 "เชิญนั่ง"); (2) ปัจจุบันยกย่องสำหรับประธานที่เคารพ — (할아버지가 책을 읽으세요 "คุณปู่กำลังอ่านหนังสือ"). รูป: รากลงสระหรือ ㄹ → -세요 (가다 → 가세요, 살다 → 사세요 ㄹ หล่น); รากลงพยัญชนะ → -으세요 (앉다 → 앉으세요). บางคำเปลี่ยนรากเป็นรูปยกย่องพิเศษ: 먹다 → 드시다 → 드세요, 자다 → 주무시다 → 주무세요, 있다 → 계시다 → 계세요, 죽다 → 돌아가시다 → 돌아가세요.\n\nคำขอเชิงปฏิเสธ: -지 마세요 ("กรุณาอย่า ~"). ทางการมากขึ้น: -(으)십시오 (ประกาศ ป้าย)',
      'Bentuk yang sama, dua fungsi: (1) permintaan sopan kepada lawan bicara — "tolong / silakan" (앉으세요 "silakan duduk"); (2) kala kini hormat tentang subjek yang dihormati — (할아버지가 책을 읽으세요 "kakek sedang membaca"). Bentuk: akar vokal/ㄹ → -세요 (가다 → 가세요, 살다 → 사세요 dengan ㄹ jatuh); akar konsonan → -으세요 (앉다 → 앉으세요). Beberapa verba menggantikan akarnya dengan akar hormat khusus: 먹다 → 드시다 → 드세요, 자다 → 주무시다 → 주무세요, 있다 → 계시다 → 계세요, 죽다 → 돌아가시다 → 돌아가세요.\n\nPermintaan negatif: -지 마세요 ("tolong jangan ~"). Lebih formal lagi: -(으)십시오 (pengumuman, papan).',
      'Một dạng, hai chức năng: (1) yêu cầu lịch sự với người nghe — "xin / vui lòng ~" (앉으세요 "mời ngồi"); (2) hiện tại kính ngữ về một chủ thể được tôn trọng — (할아버지가 책을 읽으세요 "ông đang đọc sách"). Hình thức: gốc nguyên âm hoặc ㄹ → -세요 (가다 → 가세요, 살다 → 사세요 với ㄹ rụng); gốc phụ âm → -으세요 (앉다 → 앉으세요). Một số động từ thay gốc bằng gốc kính ngữ riêng: 먹다 → 드시다 → 드세요, 자다 → 주무시다 → 주무세요, 있다 → 계시다 → 계세요, 죽다 → 돌아가시다 → 돌아가세요.\n\nYêu cầu phủ định: -지 마세요 ("xin đừng ~"). Trang trọng hơn nữa: -(으)십시오 (thông báo, biển báo).',
      '一つの形で二つの機能: (1) 聞き手への丁寧な依頼 — 「お〜ください」(앉으세요「どうぞお座りください」); (2) 尊敬する主語に対する尊敬現在 — (할아버지가 책을 읽으세요「祖父が本を読んでいらっしゃる」)。形: 母音または ㄹ 語幹 → -세요(가다 → 가세요、살다 → 사세요 で ㄹ が脱落); 子音語幹 → -으세요(앉다 → 앉으세요)。一部の動詞は語幹自体を尊敬語に置き換える: 먹다 → 드시다 → 드세요、자다 → 주무시다 → 주무세요、있다 → 계시다 → 계세요、죽다 → 돌아가시다 → 돌아가세요。\n\n否定の依頼: -지 마세요(「〜しないでください」)。さらに改まった形: -(으)십시오(アナウンス、掲示)。',
    ),
  '-ㅂ/습니다': L(
      'The high-formality register (합쇼체) — news broadcasts, presentations, first-meeting business, customer service, military, public announcements. Form: vowel-ending or ㄹ-ending stem → -ㅂ니다 (가다 → 갑니다, 살다 → 삽니다 with ㄹ dropping); consonant-ending stem → -습니다 (먹다 → 먹습니다). Question form: -ㅂ/습니까? (먹습니까? "do you eat?"). Past: -았/었습니다 (갔습니다).\n\nCompared with -아/어요 (also polite), -ㅂ/습니다 is more impersonal and authoritative — a news anchor uses -습니다; you and a colleague at lunch use -아/어요. Native speakers code-switch between them sentence by sentence to control distance.',
      'El registro de alta formalidad (합쇼체) — noticieros, presentaciones, primera reunión de negocios, atención al cliente, militar, anuncios públicos. Forma: raíz en vocal o en ㄹ → -ㅂ니다 (가다 → 갑니다, 살다 → 삽니다 con ㄹ que cae); raíz en consonante → -습니다 (먹다 → 먹습니다). Forma interrogativa: -ㅂ/습니까? (먹습니까? "¿come?"). Pasado: -았/었습니다 (갔습니다).\n\nComparado con -아/어요 (también educado), -ㅂ/습니다 suena más impersonal y autoritario — un periodista usa -습니다; vos con un colega almorzando usás -아/어요. Los nativos alternan entre los dos oración por oración para controlar la distancia.',
      'Le registre de haute formalité (합쇼체) — journaux télévisés, présentations, première rencontre professionnelle, service clientèle, armée, annonces publiques. Forme : racine en voyelle ou en ㄹ → -ㅂ니다 (가다 → 갑니다, 살다 → 삽니다 avec chute du ㄹ) ; racine en consonne → -습니다 (먹다 → 먹습니다). Interrogatif : -ㅂ/습니까? (먹습니까? « mangez-vous ? »). Passé : -았/었습니다 (갔습니다).\n\nComparé à -아/어요 (poli également), -ㅂ/습니다 sonne plus impersonnel et autoritaire — un présentateur utilise -습니다 ; vous et un collègue à la cantine utilisez -아/어요. Les natifs alternent les deux phrase par phrase pour gérer la distance.',
      'O registro de alta formalidade (합쇼체) — telejornais, apresentações, primeira reunião de negócios, atendimento ao cliente, militar, avisos públicos. Forma: radical em vogal ou em ㄹ → -ㅂ니다 (가다 → 갑니다, 살다 → 삽니다 com ㄹ caindo); radical em consoante → -습니다 (먹다 → 먹습니다). Interrogativa: -ㅂ/습니까? (먹습니까? "você come?"). Passado: -았/었습니다 (갔습니다).\n\nComparado com -아/어요 (também educado), -ㅂ/습니다 soa mais impessoal e autoritário — um jornalista usa -습니다; você e um colega almoçando usam -아/어요. Os nativos alternam frase a frase para regular a distância.',
      'รูปทางการระดับสูง (합쇼체) — รายการข่าว การนำเสนอ การประชุมแรกพบ บริการลูกค้า ทหาร ประกาศสาธารณะ. รูป: รากลงสระหรือ ㄹ → -ㅂ니다 (가다 → 갑니다, 살다 → 삽니다 ㄹ หล่น); รากลงพยัญชนะ → -습니다 (먹다 → 먹습니다). รูปคำถาม: -ㅂ/습니까? (먹습니까? "ทานไหมครับ?"). อดีต: -았/었습니다 (갔습니다).\n\nเทียบกับ -아/어요 (สุภาพเหมือนกัน), -ㅂ/습니다 ฟังดูเป็นทางการ ไม่ใช่ส่วนตัว และมีน้ำหนัก — ผู้ประกาศข่าวใช้ -습니다 ส่วนคุณกับเพื่อนร่วมงานตอนเที่ยงใช้ -아/어요. คนเกาหลีสลับใช้สองรูปประโยคต่อประโยคเพื่อควบคุมระยะห่าง',
      'Register sangat formal (합쇼체) — siaran berita, presentasi, pertemuan bisnis pertama, layanan pelanggan, militer, pengumuman publik. Bentuk: akar berakhir vokal atau ㄹ → -ㅂ니다 (가다 → 갑니다, 살다 → 삽니다 dengan ㄹ jatuh); akar berakhir konsonan → -습니다 (먹다 → 먹습니다). Bentuk tanya: -ㅂ/습니까? (먹습니까? "apakah Anda makan?"). Lampau: -았/었습니다 (갔습니다).\n\nDibanding -아/어요 (juga sopan), -ㅂ/습니다 terdengar lebih impersonal dan berwibawa — pembawa berita memakai -습니다; Anda dan kolega saat makan siang pakai -아/어요. Penutur asli berganti antara keduanya tiap kalimat untuk mengatur jarak.',
      'Cấp độ cực kỳ trang trọng (합쇼체) — bản tin, thuyết trình, cuộc gặp kinh doanh đầu tiên, chăm sóc khách hàng, quân đội, thông báo công cộng. Hình thức: gốc kết nguyên âm hoặc ㄹ → -ㅂ니다 (가다 → 갑니다, 살다 → 삽니다 với ㄹ rụng); gốc kết phụ âm → -습니다 (먹다 → 먹습니다). Dạng hỏi: -ㅂ/습니까? (먹습니까? "bạn ăn không?"). Quá khứ: -았/었습니다 (갔습니다).\n\nSo với -아/어요 (cũng lịch sự), -ㅂ/습니다 nghe trang nghiêm, không cá nhân hơn — phát thanh viên dùng -습니다, còn bạn và đồng nghiệp ăn trưa dùng -아/어요. Người Hàn chuyển đổi giữa hai dạng câu này sang câu khác để điều chỉnh khoảng cách.',
      '高フォーマルの語尾(합쇼체) — ニュース、プレゼン、初対面のビジネス、接客、軍隊、公的アナウンスで用いる。形: 母音または ㄹ 語幹 → -ㅂ니다(가다 → 갑니다、살다 → 삽니다 で ㄹ が脱落); 子音語幹 → -습니다(먹다 → 먹습니다)。疑問形: -ㅂ/습니까?(먹습니까?「召し上がりますか」)。過去: -았/었습니다(갔습니다)。\n\n同じ丁寧体の -아/어요 と比べると、-ㅂ/습니다 はより非個人的で重い — ニュースキャスターは -습니다、同僚との昼食では -아/어요。ネイティブは距離感を調整するため、文ごとにこの二つを切り替える。',
    ),
  '안 + V / -지 않다': L(
      'Two ways to negate by choice ("not", "do not"): short-form 안 sits BEFORE the verb (안 가요 "don\'t go"); long-form -지 않다 attaches to the stem (가지 않아요). They\'re interchangeable in most situations, but the long form is preferred in writing, formal speech, and longer/compound verbs.\n\nCritical trap for 하다 verbs: place 안 INSIDE — 공부 안 해요 (NOT 안 공부해요); the noun and 하다 split for negation. There are also lexical negatives that ignore both: 있다 → 없다, 알다 → 모르다, 좋다 → 싫다 (don\'t say 안 있다 or 안 알다 — use the dedicated negative verb).',
      'Dos formas de negar por elección ("no", "no hacer"): corta 안 va ANTES del verbo (안 가요 "no voy"); larga -지 않다 se pega a la raíz (가지 않아요). Son intercambiables casi siempre, pero la larga se prefiere en escritura, habla formal y verbos largos/compuestos.\n\nTrampa crítica con los verbos 하다: 안 va EN MEDIO — 공부 안 해요 (NO 안 공부해요); el sustantivo y 하다 se separan para la negación. Hay además negativos léxicos que ignoran ambas formas: 있다 → 없다, 알다 → 모르다, 좋다 → 싫다 (no digas 안 있다 ni 안 알다 — usá el verbo negativo dedicado).',
      'Deux moyens de nier par choix (« ne pas ») : la forme courte 안 précède le verbe (안 가요 « je n\'y vais pas ») ; la forme longue -지 않다 s\'attache à la racine (가지 않아요). Interchangeables dans la plupart des contextes, mais la longue est préférée à l\'écrit, à l\'oral formel et avec les verbes longs ou composés.\n\nPiège majeur des verbes en 하다 : 안 se place À L\'INTÉRIEUR — 공부 안 해요 (PAS 안 공부해요) ; le nom et 하다 se séparent pour la négation. Il existe aussi des négatifs lexicaux qui ignorent les deux formes : 있다 → 없다, 알다 → 모르다, 좋다 → 싫다 (on ne dit pas 안 있다 ni 안 알다 — on emploie le verbe négatif dédié).',
      'Duas formas de negar por escolha ("não / não fazer"): curta 안 vem ANTES do verbo (안 가요 "não vou"); longa -지 않다 se anexa ao radical (가지 않아요). Intercambiáveis na maioria das situações, mas a longa é preferida em escrita, fala formal e verbos longos/compostos.\n\nArmadilha crítica com verbos em 하다: 안 vai NO MEIO — 공부 안 해요 (NÃO 안 공부해요); o substantivo e 하다 se separam para a negação. Há também negativos lexicais que ignoram ambas: 있다 → 없다, 알다 → 모르다, 좋다 → 싫다 (não diga 안 있다 nem 안 알다 — use o verbo negativo dedicado).',
      'สองวิธีปฏิเสธโดยเลือก ("ไม่ / ไม่ทำ"): รูปสั้น 안 วางไว้ "ข้างหน้า" กริยา (안 가요 "ไม่ไป"); รูปยาว -지 않다 เกาะติดราก (가지 않아요). ใช้แทนกันได้เกือบทุกบริบท แต่รูปยาวเป็นที่นิยมในงานเขียน ภาษาทางการ และกริยายาว/ประกอบ.\n\nกับดักสำคัญของกริยา 하다: ต้องใส่ 안 "ระหว่าง" คำนามกับ 하다 — 공부 안 해요 (ห้าม 안 공부해요); คำนามและ 하다 แยกออกเพื่อปฏิเสธ. ยังมีคำปฏิเสธเฉพาะที่ไม่ใช้ทั้งสองรูป: 있다 → 없다, 알다 → 모르다, 좋다 → 싫다 (อย่าพูด 안 있다 หรือ 안 알다 — ใช้คำกริยาปฏิเสธเฉพาะแทน)',
      'Dua cara menegasi karena pilihan ("tidak / tidak ~"): bentuk pendek 안 ditaruh SEBELUM verba (안 가요 "tidak pergi"); bentuk panjang -지 않다 menempel pada akar (가지 않아요). Bisa saling menggantikan di kebanyakan situasi, tapi bentuk panjang lebih dipakai dalam tulisan, percakapan formal, dan verba panjang/majemuk.\n\nJebakan penting verba 하다: 안 ditaruh DI TENGAH — 공부 안 해요 (BUKAN 안 공부해요); kata benda dan 하다 dipisah saat dinegasikan. Ada juga negasi leksikal yang mengabaikan keduanya: 있다 → 없다, 알다 → 모르다, 좋다 → 싫다 (jangan ucapkan 안 있다 atau 안 알다 — pakai verba negatif khusus).',
      'Hai cách phủ định do chọn ("không / không ~"): dạng ngắn 안 đứng TRƯỚC động từ (안 가요 "không đi"); dạng dài -지 않다 gắn vào gốc (가지 않아요). Có thể thay thế nhau trong hầu hết tình huống, nhưng dạng dài được ưa chuộng trong viết, nói trang trọng, và động từ dài/ghép.\n\nBẫy quan trọng với động từ 하다: 안 đặt VÀO GIỮA — 공부 안 해요 (KHÔNG phải 안 공부해요); danh từ và 하다 tách ra để phủ định. Ngoài ra có những phủ định từ vựng bỏ qua cả hai dạng: 있다 → 없다, 알다 → 모르다, 좋다 → 싫다 (đừng nói 안 있다 hay 안 알다 — dùng động từ phủ định riêng).',
      '意志による否定の二系統: 短形 안 は動詞の「前」に置く(안 가요「行かない」); 長形 -지 않다 は語幹に付ける(가지 않아요)。ほとんどの状況で互換だが、書き言葉・フォーマルな会話・長い／複合動詞では長形が好まれる。\n\n하다 動詞の落とし穴: 안 は「間」に挟む — 공부 안 해요(안 공부해요 ではない); 否定時には名詞と 하다 を分ける。さらに、どちらの形式も使わない語彙的否定がある: 있다 → 없다、알다 → 모르다、좋다 → 싫다(안 있다、안 알다 とは言わず、専用の否定動詞を使う)。',
    ),
  '못 + V / -지 못하다': L(
      'The inability negative — "can\'t" because of circumstance, ability, or external limit, NOT a choice. Two structures parallel 안: short-form 못 sits before the verb (못 가요 "can\'t go"), long-form -지 못하다 attaches to the stem (가지 못해요). Same trap for 하다 verbs: 못 splits the noun and 하다 — 수영 못 해요 (NOT 못 수영해요).\n\nDoesn\'t pair with stative adjectives the same way (you don\'t usually say 못 예뻐요 "can\'t be pretty"); for adjectives, choice/state is what matters, so 안 covers it. Pronunciation note: 못 + vowel often surfaces as [몯/모s] (못 와요 sounds like [모더요]).',
      'La negativa de incapacidad — "no poder" por circunstancia, habilidad o limitación externa, NO por elección. Dos estructuras paralelas a 안: la corta 못 va antes del verbo (못 가요 "no puedo ir"); la larga -지 못하다 se pega a la raíz (가지 못해요). Mismo truco con los verbos 하다: 못 separa al sustantivo y 하다 — 수영 못 해요 (NO 못 수영해요).\n\nNo se combina igual con adjetivos descriptivos (no se dice usualmente 못 예뻐요 "no puedo ser linda"); para adjetivos lo que importa es elección/estado, así que 안 ya cubre. Nota de pronunciación: 못 + vocal suele resilabificar [몯/모s] (못 와요 suena [모더요]).',
      'La négation d\'incapacité — « ne pas pouvoir » par circonstance, aptitude ou contrainte extérieure, et NON par choix. Deux structures parallèles à 안 : la courte 못 précède le verbe (못 가요 « je ne peux pas y aller ») ; la longue -지 못하다 se rattache à la racine (가지 못해요). Même piège pour les verbes en 하다 : 못 sépare le nom et 하다 — 수영 못 해요 (PAS 못 수영해요).\n\nNe se combine pas de la même manière avec les adjectifs descriptifs (on ne dit guère 못 예뻐요 « je ne peux pas être jolie ») ; pour les adjectifs, c\'est le choix/l\'état qui compte, donc 안 suffit. Note de prononciation : 못 + voyelle se resyllabe souvent en [몯/모s] (못 와요 sonne [모더요]).',
      'A negação de incapacidade — "não poder" por circunstância, habilidade ou limitação externa, NÃO por escolha. Duas estruturas paralelas a 안: a curta 못 vem antes do verbo (못 가요 "não consigo ir"); a longa -지 못하다 anexa ao radical (가지 못해요). Mesma armadilha com verbos em 하다: 못 separa o substantivo e 하다 — 수영 못 해요 (NÃO 못 수영해요).\n\nNão combina da mesma forma com adjetivos descritivos (normalmente não se diz 못 예뻐요 "não posso ser bonita"); para adjetivos importa a escolha/estado, então 안 já cobre. Nota de pronúncia: 못 + vogal costuma re-silabar como [몯/모s] (못 와요 soa [모더요]).',
      'รูปปฏิเสธของความไม่สามารถ — "ทำไม่ได้" เพราะข้อจำกัด ความสามารถ หรือสถานการณ์ภายนอก ไม่ใช่จากเจตนา. มีสองโครงสร้างคู่ขนานกับ 안: รูปสั้น 못 อยู่หน้ากริยา (못 가요 "ไปไม่ได้"); รูปยาว -지 못하다 เกาะติดราก (가지 못해요). กับดักเดียวกันกับ 하다: 못 แยกคำนามกับ 하다 — 수영 못 해요 (ห้าม 못 수영해요).\n\nกับคำคุณศัพท์ใช้ต่างกัน (โดยทั่วไปไม่พูด 못 예뻐요 "สวยไม่ได้"); สำหรับคุณศัพท์ใช้ 안 พอ เพราะเป็นเรื่องของเจตนา/สภาพ. หมายเหตุการออกเสียง: 못 + สระมักจะรวมพยางค์เป็น [몯/모s] (못 와요 ออกเสียง [모더요])',
      'Negasi ketakmampuan — "tidak bisa" karena keadaan, kemampuan, atau pembatas eksternal, BUKAN karena pilihan. Dua struktur paralel dengan 안: bentuk pendek 못 di depan verba (못 가요 "tidak bisa pergi"); bentuk panjang -지 못하다 menempel pada akar (가지 못해요). Jebakan yang sama untuk verba 하다: 못 memisahkan kata benda dan 하다 — 수영 못 해요 (BUKAN 못 수영해요).\n\nTidak berpasangan dengan adjektiva deskriptif dengan cara yang sama (umumnya tidak diucapkan 못 예뻐요 "tidak bisa cantik"); untuk adjektiva, yang penting adalah pilihan/keadaan, jadi 안 cukup. Catatan pelafalan: 못 + vokal sering disilabikan ulang menjadi [몯/모s] (못 와요 terdengar [모더요]).',
      'Phủ định bất khả — "không thể" do hoàn cảnh, năng lực, hoặc giới hạn bên ngoài, KHÔNG phải do chọn lựa. Hai cấu trúc song song với 안: dạng ngắn 못 đứng trước động từ (못 가요 "không thể đi"); dạng dài -지 못하다 gắn vào gốc (가지 못해요). Bẫy giống với 하다: 못 tách danh từ và 하다 — 수영 못 해요 (KHÔNG phải 못 수영해요).\n\nKhông kết hợp với tính từ miêu tả theo cùng cách (thường không nói 못 예뻐요 "không thể đẹp được"); với tính từ, chọn lựa/trạng thái là điều quan trọng, nên 안 đã đủ. Lưu ý phát âm: 못 + nguyên âm thường nối âm thành [몯/모s] (못 와요 nghe như [모더요]).',
      '不可能の否定 — 「〜できない」: 状況や能力、外的制約による不可能で、意志による拒否ではない。안 と並行する二系統: 短形 못 は動詞の前に置く(못 가요「行けない」); 長形 -지 못하다 は語幹に付ける(가지 못해요)。하다 動詞での落とし穴は同じで、못 が名詞と 하다 を割る — 수영 못 해요(못 수영해요 とは言わない)。\n\n状態を描く形容詞とは同じようには組まない(못 예뻐요「きれいになれない」とは普通言わない); 形容詞は意志・状態の問題なので 안 で十分。発音上の注意: 못 + 母音は再音節化して [몯／모s] のように現れる(못 와요 は [모더요] のように聞こえる)。',
    ),
  '안 vs 못 (비교)': L(
      "Decide which one to use by asking: did the speaker DECIDE not to, or were they UNABLE to? 안 = decline / not do (volition); 못 = couldn't / blocked (ability or external constraint). Two tells the textbook examples lean on: (1) physical/skill capacity → 못 (수영 못 해요 \"can't swim\"); (2) commitment/refusal → 안 (오늘은 일 안 해요 \"I'm not working today\").\n\nPolite request to NOT do something almost always uses neither — it uses -지 마세요. Watch native usage: a doctor asking why you stopped exercising might use 못 to assume circumstance (왜 운동을 못 하세요? feels gentler than 왜 운동을 안 하세요? which can sound like an accusation).",
      'Decidí entre los dos preguntándote: ¿el hablante decidió no hacerlo o no pudo? 안 = no quiero / no lo hago (voluntad); 못 = no pude / me lo impide algo (capacidad o restricción externa). Dos pistas que usan los manuales: (1) capacidad física o habilidad → 못 (수영 못 해요 "no sé nadar"); (2) compromiso/rechazo → 안 (오늘은 일 안 해요 "hoy no trabajo").\n\nPara pedir que alguien NO haga algo casi siempre usás -지 마세요. Mirá el uso nativo: un médico que te pregunta por qué dejaste de entrenar usaría 못 para asumir circunstancia (왜 운동을 못 하세요? suena más suave que 왜 운동을 안 하세요?, que puede sonar a reproche).',
      'Pour choisir, demande-toi : le locuteur a-t-il décidé de ne pas le faire, ou en était-il incapable ? 안 = ne pas vouloir / refuser (volonté) ; 못 = ne pas pouvoir / être empêché (capacité ou contrainte extérieure). Deux indices : (1) capacité physique ou compétence → 못 (수영 못 해요 « je ne sais pas nager ») ; (2) engagement / refus → 안 (오늘은 일 안 해요 « aujourd\'hui je ne travaille pas »).\n\nPour demander à quelqu\'un de NE PAS faire quelque chose, on emploie quasi toujours -지 마세요. Observation d\'usage : un médecin demandant pourquoi tu as arrêté le sport préférera 못 pour présumer une cause extérieure (왜 운동을 못 하세요? paraît plus doux que 왜 운동을 안 하세요?, qui peut sonner comme un reproche).',
      'Escolha entre os dois perguntando: o falante DECIDIU não fazer ou NÃO CONSEGUIU? 안 = não querer / recusar (volição); 못 = não conseguiu / barrado (capacidade ou restrição externa). Duas dicas que os manuais usam: (1) capacidade física/habilidade → 못 (수영 못 해요 "não sei nadar"); (2) compromisso/recusa → 안 (오늘은 일 안 해요 "hoje não trabalho").\n\nPara pedir que alguém NÃO faça algo, quase sempre você usa -지 마세요. Repare no uso nativo: um médico perguntando por que você parou de se exercitar usaria 못 para presumir circunstância (왜 운동을 못 하세요? soa mais delicado que 왜 운동을 안 하세요?, que pode soar como acusação).',
      'เลือกใช้ตัวไหนด้วยการถาม: ผู้พูด "เลือก" ไม่ทำ หรือ "ทำไม่ได้"? 안 = ปฏิเสธ/ไม่ทำ (เจตนา); 못 = ทำไม่ได้/ถูกขัด (ความสามารถหรือข้อจำกัดภายนอก). สองสัญญาณที่หนังสือใช้: (1) ความสามารถทางร่างกาย/ทักษะ → 못 (수영 못 해요 "ว่ายน้ำไม่เป็น"); (2) คำมั่น/การปฏิเสธ → 안 (오늘은 일 안 해요 "วันนี้ฉันไม่ทำงาน").\n\nคำขอแบบสุภาพให้ "ไม่ทำ" บางอย่าง เกือบทั้งหมดใช้ -지 마세요 ไม่ใช่สองตัวนี้. สังเกตการใช้ของเจ้าของภาษา: คุณหมอถามว่าทำไมหยุดออกกำลังกาย ใช้ 못 เพื่อสันนิษฐานสถานการณ์ (왜 운동을 못 하세요? ฟังนุ่มกว่า 왜 운동을 안 하세요? ที่อาจฟังเหมือนตำหนิ)',
      'Pilih dengan bertanya: penuturnya MEMILIH tidak melakukan, atau TIDAK SANGGUP? 안 = menolak/tidak mau (kemauan); 못 = tidak bisa/dihalangi (kemampuan atau pembatas eksternal). Dua petunjuk standar buku ajar: (1) kapasitas fisik/keterampilan → 못 (수영 못 해요 "tidak bisa berenang"); (2) komitmen/penolakan → 안 (오늘은 일 안 해요 "hari ini saya tidak kerja").\n\nUntuk meminta orang TIDAK melakukan sesuatu, hampir selalu pakai -지 마세요 — bukan dua bentuk ini. Lihat penggunaan asli: dokter menanyakan kenapa Anda berhenti olahraga lebih memilih 못 untuk berasumsi situasi (왜 운동을 못 하세요? terasa lebih lembut dibanding 왜 운동을 안 하세요?, yang bisa terdengar menyalahkan).',
      'Chọn bằng cách tự hỏi: người nói "quyết định" không làm, hay "không thể" làm? 안 = từ chối / không làm (ý chí); 못 = không thể / bị cản (năng lực hoặc giới hạn ngoài). Hai gợi ý sách giáo khoa: (1) năng lực thể chất/kỹ năng → 못 (수영 못 해요 "không biết bơi"); (2) cam kết / từ chối → 안 (오늘은 일 안 해요 "hôm nay tôi không làm việc").\n\nYêu cầu ai đó ĐỪNG làm gì thì gần như luôn dùng -지 마세요 chứ không phải hai dạng này. Quan sát người bản ngữ: bác sĩ hỏi tại sao bạn ngừng tập thể dục thường chọn 못 để giả định hoàn cảnh (왜 운동을 못 하세요? nghe nhẹ nhàng hơn 왜 운동을 안 하세요?, dễ nghe như trách móc).',
      'どちらを使うかは「話し手が選んでやらないのか／できないのか」で決まる: 안 = しない／拒む(意志)、못 = できない／妨げられている(能力・外的制約)。教科書がよく出す二つの目印: (1) 体力・技能 → 못(수영 못 해요「泳げない」); (2) 約束・拒否 → 안(오늘은 일 안 해요「今日は働きません」)。\n\n「〜しないでください」と頼むときはこの二つではなく -지 마세요 を使う。ネイティブの使い分け: 運動をやめた理由を尋ねる医師は 못 を選んで状況を慮る(왜 운동을 못 하세요? は 왜 운동을 안 하세요? より柔らかく、後者は責めているように聞こえることがある)。',
    ),
  '-고': L(
      'Bare-stem connector "and (then)" — attach 고 directly to the verb/adjective stem (먹다 → 먹고, 좋다 → 좋고). Tense and politeness sit ONLY on the final clause; don\'t conjugate the first one (숙제를 하고 잤어요, not 했고). It can mean a simple list of states (방이 크고 깨끗해요 "the room is big and clean") or a loose temporal sequence of actions (먹고 자요 "I eat and then sleep").\n\nDiffers from -아/어서: -고 is neutral about cause, and unlike -아/어서 it allows imperatives or proposals on the second clause (집에 가고 쉬세요 "go home and rest").',
      'Conector "y (luego)" sobre la raíz desnuda — pegá 고 directo a la raíz del verbo/adjetivo (먹다 → 먹고, 좋다 → 좋고). El tiempo y la cortesía van SOLO en la cláusula final; no conjugues la primera (숙제를 하고 잤어요, no 했고). Puede ser una lista simple de estados (방이 크고 깨끗해요 "el cuarto es grande y limpio") o una secuencia temporal floja de acciones (먹고 자요 "como y después duermo").\n\nSe diferencia de -아/어서: -고 es neutro respecto a la causa y, a diferencia de -아/어서, sí admite imperativos o propuestas en la segunda cláusula (집에 가고 쉬세요 "andate a casa y descansá").',
      'Connecteur « et (puis) » sur racine nue — colle 고 directement à la racine du verbe/adjectif (먹다 → 먹고, 좋다 → 좋고). Le temps et la politesse ne portent QUE sur la dernière proposition ; ne conjugue pas la première (숙제를 하고 잤어요, pas 했고). Peut indiquer une simple liste d\'états (방이 크고 깨끗해요 « la chambre est grande et propre ») ou une suite temporelle souple d\'actions (먹고 자요 « je mange puis je dors »).\n\nDiffère de -아/어서 : -고 est neutre quant à la cause et, contrairement à -아/어서, accepte un impératif ou une proposition dans la 2ᵈᵉ proposition (집에 가고 쉬세요 « rentre et repose-toi »).',
      'Conector "e (depois)" sobre o radical nu — anexe 고 direto ao radical do verbo/adjetivo (먹다 → 먹고, 좋다 → 좋고). Tempo e cortesia ficam SÓ na última oração; não conjugue a primeira (숙제를 하고 잤어요, não 했고). Pode ser uma lista simples de estados (방이 크고 깨끗해요 "o quarto é grande e limpo") ou uma sequência temporal frouxa de ações (먹고 자요 "como e depois durmo").\n\nDiferente de -아/어서: -고 é neutro quanto a causa e, ao contrário de -아/어서, aceita imperativo ou proposta na segunda oração (집에 가고 쉬세요 "vá para casa e descanse").',
      'คำเชื่อม "แล้ว/และ" บนรากเปล่า — เกาะ 고 ตรงรากของกริยา/คำคุณศัพท์ (먹다 → 먹고, 좋다 → 좋고). กาลและความสุภาพอยู่ "เฉพาะ" ที่ประโยคสุดท้าย อย่าผันประโยคแรก (숙제를 하고 잤어요 ไม่ใช่ 했고). อาจเป็นการแจกแจงสภาพ (방이 크고 깨끗해요 "ห้องใหญ่และสะอาด") หรือลำดับเหตุการณ์แบบหลวม (먹고 자요 "กินแล้วก็นอน").\n\nต่างจาก -아/어서: -고 เป็นกลางเรื่องเหตุ และต่างจาก -아/어서 ตรงที่อนุญาตคำสั่ง/ข้อเสนอในประโยคที่สอง (집에 가고 쉬세요 "กลับบ้านแล้วพัก")',
      'Penghubung "lalu / dan" pada akar telanjang — tempelkan 고 langsung pada akar verba/adjektiva (먹다 → 먹고, 좋다 → 좋고). Kala dan kesopanan HANYA di klausa terakhir; jangan konjugasi klausa pertama (숙제를 하고 잤어요, bukan 했고). Bisa berupa daftar keadaan sederhana (방이 크고 깨끗해요 "kamarnya besar dan bersih") atau urutan waktu longgar dari aksi (먹고 자요 "saya makan lalu tidur").\n\nBerbeda dari -아/어서: -고 netral terhadap sebab dan, tidak seperti -아/어서, mengizinkan imperatif atau usulan di klausa kedua (집에 가고 쉬세요 "pulang lalu istirahat").',
      'Liên từ "và (rồi)" trên gốc trần — gắn 고 trực tiếp vào gốc động từ/tính từ (먹다 → 먹고, 좋다 → 좋고). Thì và mức lịch sự CHỈ đặt ở vế cuối; đừng chia vế đầu (숙제를 하고 잤어요, không phải 했고). Có thể là danh sách trạng thái đơn giản (방이 크고 깨끗해요 "phòng rộng và sạch") hoặc chuỗi hành động lỏng theo thứ tự (먹고 자요 "ăn rồi ngủ").\n\nKhác với -아/어서: -고 trung tính về nguyên nhân và, khác -아/어서, cho phép mệnh lệnh hoặc đề nghị ở vế hai (집에 가고 쉬세요 "về nhà rồi nghỉ").',
      '裸の語幹に付く接続「〜して」— 動詞・形容詞の語幹に 고 を直接付ける(먹다 → 먹고、좋다 → 좋고)。時制と丁寧度は「最後の節だけ」に置く; 前節は活用しない(숙제를 하고 잤어요、했고 ではない)。状態の単なる列挙(방이 크고 깨끗해요「部屋が広くてきれい」)、動作のゆるい時間的順序(먹고 자요「食べて寝る」)に用いる。\n\n-아/어서 との違い: -고 は因果に対して中立で、-아/어서 と違い後節に命令や提案も置ける(집에 가고 쉬세요「家に帰って休んでください」)。',
    ),
  '-아/어서': L(
      'Cause-and-effect "because / so" with an inseparable bond between the two clauses — what happens in the second clause naturally follows from the first. Form: take the -아/어 stem (same harmony and contractions as -아/어요) and add 서 (배고프다 → 배고파서, 먹다 → 먹어서, 하다 → 해서).\n\nTwo HARD rules: (1) the first clause stays present-tense in form even when meaning is past — never write 갔어서, 먹었어서 (the past is implied by context or the second clause); (2) the second clause cannot be an imperative, proposal, or commitment — for those, use -(으)니까 instead (배가 고프니까 같이 먹어요 "let\'s eat because I\'m hungry"). For "thank you / sorry because", 감사해서 / 미안해서 is also the standard form.',
      'Causa-efecto "porque / así que" con un vínculo inseparable entre las dos cláusulas — lo del segundo nace naturalmente de lo del primero. Forma: tomá la raíz -아/어 (misma armonía y contracciones que -아/어요) y agregale 서 (배고프다 → 배고파서, 먹다 → 먹어서, 하다 → 해서).\n\nDos reglas DURAS: (1) la primera cláusula queda en presente aunque el sentido sea pasado — nunca escribas 갔어서, 먹었어서 (el pasado se infiere por el contexto o la segunda cláusula); (2) la segunda cláusula no puede ser imperativo, propuesta ni compromiso — para esos casos usá -(으)니까 (배가 고프니까 같이 먹어요 "comamos porque tengo hambre"). Para "gracias por / perdón por", 감사해서 / 미안해서 es la forma estándar.',
      'Cause-conséquence « parce que / donc » avec un lien inséparable entre les deux propositions — ce qui se passe dans la deuxième découle naturellement de la première. Forme : on prend la racine -아/어 (mêmes harmonies et contractions qu\'avec -아/어요) et on ajoute 서 (배고프다 → 배고파서, 먹다 → 먹어서, 하다 → 해서).\n\nDeux règles STRICTES : (1) la première proposition reste au présent dans la forme même quand le sens est passé — jamais 갔어서, 먹었어서 (le passé est implicite) ; (2) la deuxième proposition ne peut pas être un impératif, une proposition ou un engagement — dans ce cas, employer -(으)니까 à la place (배가 고프니까 같이 먹어요 « mangeons puisque j\'ai faim »). Pour « merci de / désolé de », 감사해서 / 미안해서 est la forme standard.',
      'Causa-efeito "porque / então" com vínculo inseparável entre as duas orações — o que acontece na segunda nasce naturalmente da primeira. Forma: pegue a raiz -아/어 (mesma harmonia e contrações de -아/어요) e some 서 (배고프다 → 배고파서, 먹다 → 먹어서, 하다 → 해서).\n\nDuas regras DURAS: (1) a primeira oração fica no presente mesmo quando o sentido é passado — nunca escreva 갔어서, 먹었어서 (o passado está implícito); (2) a segunda oração não pode ser imperativa, proposta nem compromisso — nesses casos use -(으)니까 (배가 고프니까 같이 먹어요 "vamos comer porque estou com fome"). Para "obrigado por / desculpa por", 감사해서 / 미안해서 é a forma padrão.',
      'เหตุ-ผลแบบ "เพราะ/เลย" ที่ผูกสองประโยคไว้แน่น — สิ่งที่เกิดในประโยคสองตามมาจากประโยคหนึ่งโดยธรรมชาติ. รูป: เอารากของ -아/어 (กฎสระและการหดเหมือน -아/어요) แล้วเติม 서 (배고프다 → 배고파서, 먹다 → 먹어서, 하다 → 해서).\n\nกฎเข้มสองข้อ: (1) ประโยคแรกต้องอยู่ในรูปปัจจุบันแม้ความหมายเป็นอดีต — ห้ามเขียน 갔어서, 먹었어서 (อดีตอนุมานจากบริบทหรือประโยคหลัง); (2) ประโยคสองห้ามเป็นคำสั่ง ข้อเสนอ หรือคำมั่น — กรณีนี้ใช้ -(으)니까 แทน (배가 고프니까 같이 먹어요 "หิวอยู่กินด้วยกันเถอะ"). สำหรับ "ขอบคุณที่ / ขอโทษที่" รูปมาตรฐานคือ 감사해서 / 미안해서',
      'Sebab-akibat "karena / jadi" dengan ikatan tak terpisahkan antara dua klausa — yang terjadi di klausa kedua mengalir alami dari klausa pertama. Bentuk: ambil akar -아/어 (harmoni dan kontraksi sama dengan -아/어요), tambahkan 서 (배고프다 → 배고파서, 먹다 → 먹어서, 하다 → 해서).\n\nDua aturan KERAS: (1) klausa pertama tetap bentuk kini meski maknanya lampau — jangan menulis 갔어서, 먹었어서 (kelampauan tersirat); (2) klausa kedua tidak boleh imperatif, usulan, atau komitmen — untuk itu pakai -(으)니까 (배가 고프니까 같이 먹어요 "ayo makan karena saya lapar"). Untuk "terima kasih sudah / maaf telah", bentuk bakunya 감사해서 / 미안해서.',
      'Nguyên nhân-kết quả "vì / nên" với liên hệ không tách rời giữa hai vế — chuyện vế hai bắt nguồn tự nhiên từ vế một. Hình thức: lấy gốc -아/어 (hài hòa và co rút như -아/어요) rồi thêm 서 (배고프다 → 배고파서, 먹다 → 먹어서, 하다 → 해서).\n\nHai quy tắc KHẮT KHE: (1) vế đầu giữ hình thức hiện tại dù nghĩa là quá khứ — đừng viết 갔어서, 먹었어서 (quá khứ được suy từ ngữ cảnh); (2) vế hai không được là mệnh lệnh, đề nghị hay cam kết — khi cần dùng -(으)니까 (배가 고프니까 같이 먹어요 "đói rồi nên mình cùng ăn"). Để nói "cảm ơn vì / xin lỗi vì", dạng chuẩn là 감사해서 / 미안해서.',
      '前後の節が「自然に結びつく」因果接続「〜して／〜なので」。形: -아/어 語幹(-아/어요 と同じ調和・縮約)に 서 を付ける(배고프다 → 배고파서、먹다 → 먹어서、하다 → 해서)。\n\n「硬い」二つのルール: (1) 前節は意味が過去でも形は現在 — 갔어서・먹었어서 は不可(過去は文脈や後節で示す); (2) 後節に命令・勧誘・意志は置けない — そうしたい場合は -(으)니까 を使う(배가 고프니까 같이 먹어요「お腹空いたから一緒に食べよう」)。「〜してくれてありがとう／ごめんなさい」は 감사해서／미안해서 が標準形。',
    ),
  '-지만': L(
      'Bare-stem adversative — attach 지만 directly to the verb/adjective stem (어렵다 → 어렵지만, 가다 → 가지만). Works at ANY tense, in either clause, with no restrictions: past is fine on the first clause (학교에 갔지만 친구가 없었어요 "I went to school but my friend wasn\'t there"), and unlike -아/어서 there\'s no ban on imperatives or proposals on the second clause (좀 비싸지만 한번 사 보세요 "it\'s a bit pricey but try buying one").\n\nFor sentence-initial "but / however", use 하지만, 그렇지만, or the more formal 그러나. -지만 is the inside-the-sentence connector — those three are the standalone version.',
      'Adversativo sobre la raíz desnuda — pegá 지만 directo a la raíz del verbo/adjetivo (어렵다 → 어렵지만, 가다 → 가지만). Funciona con CUALQUIER tiempo en cualquier cláusula, sin restricciones: el pasado va bien en la primera (학교에 갔지만 친구가 없었어요 "fui a la escuela pero mi amigo no estaba"), y a diferencia de -아/어서 no hay prohibición de imperativos o propuestas en la segunda (좀 비싸지만 한번 사 보세요 "es un poco caro pero probá comprarlo").\n\nPara "pero / sin embargo" al inicio de oración usá 하지만, 그렇지만 o el más formal 그러나. -지만 conecta dentro de la misma oración; esos tres son la versión suelta.',
      'Adversatif sur racine nue — colle 지만 directement à la racine du verbe/adjectif (어렵다 → 어렵지만, 가다 → 가지만). Fonctionne à TOUS les temps dans chaque proposition, sans restriction : le passé est libre dans la première (학교에 갔지만 친구가 없었어요 « je suis allé à l\'école mais mon ami n\'y était pas »), et contrairement à -아/어서 aucun blocage de l\'impératif ou de la proposition dans la deuxième (좀 비싸지만 한번 사 보세요 « c\'est un peu cher mais essayez d\'en acheter »).\n\nPour « mais / cependant » en début de phrase, employer 하지만, 그렇지만, ou le plus formel 그러나. -지만 est le connecteur intraphrastique ; ces trois sont les autonomes.',
      'Adversativo sobre o radical nu — anexe 지만 direto ao radical do verbo/adjetivo (어렵다 → 어렵지만, 가다 → 가지만). Funciona com QUALQUER tempo em qualquer oração, sem restrição: passado na primeira está OK (학교에 갔지만 친구가 없었어요 "fui à escola mas meu amigo não estava"), e diferente de -아/어서 não há proibição de imperativo ou proposta na segunda (좀 비싸지만 한번 사 보세요 "é meio caro mas experimente comprar").\n\nPara "mas / porém" no começo da frase, use 하지만, 그렇지만 ou o mais formal 그러나. -지만 conecta dentro da mesma oração; esses três são as versões soltas.',
      'คำเชื่อมแสดงความขัดแย้งบนรากเปล่า — เกาะ 지만 ตรงรากของกริยา/คำคุณศัพท์ (어렵다 → 어렵지만, 가다 → 가지만). ใช้ได้ทุกกาลในประโยคใดก็ได้ ไม่มีข้อจำกัด: ใส่อดีตในประโยคแรกได้ (학교에 갔지만 친구가 없었어요 "ไปโรงเรียนแต่เพื่อนไม่อยู่") และต่างจาก -아/어서 ไม่ห้ามคำสั่ง/ข้อเสนอในประโยคหลัง (좀 비싸지만 한번 사 보세요 "แพงนิดหน่อยแต่ลองซื้อดูสิ").\n\nสำหรับ "แต่/อย่างไรก็ตาม" ต้นประโยคใช้ 하지만, 그렇지만 หรือทางการกว่า 그러나. -지만 ใช้ในประโยคเดียวกัน; สามตัวข้างบนเป็นแบบยืนเดี่ยว',
      'Adversatif pada akar telanjang — tempelkan 지만 langsung pada akar verba/adjektiva (어렵다 → 어렵지만, 가다 → 가지만). Bekerja di SEGALA kala di mana saja, tanpa larangan: lampau di klausa pertama oke (학교에 갔지만 친구가 없었어요 "saya ke sekolah tapi teman saya tidak ada"), dan tidak seperti -아/어서, tidak ada larangan imperatif atau usulan di klausa kedua (좀 비싸지만 한번 사 보세요 "agak mahal tapi cobalah membeli").\n\nUntuk "tapi / namun" di awal kalimat, gunakan 하지만, 그렇지만, atau yang lebih formal 그러나. -지만 menghubungkan di dalam satu kalimat; tiga itu versi berdiri sendiri.',
      'Liên từ tương phản trên gốc trần — gắn 지만 trực tiếp vào gốc động từ/tính từ (어렵다 → 어렵지만, 가다 → 가지만). Hoạt động ở MỌI thì, ở vế nào cũng được, không bị hạn chế: quá khứ ở vế đầu thoải mái (학교에 갔지만 친구가 없었어요 "tôi đến trường nhưng bạn không có ở đó"), và khác với -아/어서, không cấm mệnh lệnh hay đề nghị ở vế hai (좀 비싸지만 한번 사 보세요 "hơi đắt nhưng thử mua một lần xem").\n\nĐể nói "nhưng / tuy nhiên" đầu câu, dùng 하지만, 그렇지만, hoặc trang trọng hơn 그러나. -지만 nối trong cùng một câu; ba liên từ đầu kia là dạng đứng riêng.',
      '裸の語幹に付く逆接 — 動詞・形容詞の語幹に 지만 を直接付ける(어렵다 → 어렵지만、가다 → 가지만)。どの時制でも、どちらの節でも制約なし: 前節に過去も自由(학교에 갔지만 친구가 없었어요「学校に行ったけど友達がいなかった」)、-아/어서 と違って後節に命令・勧誘の禁止もない(좀 비싸지만 한번 사 보세요「ちょっと高いけど一度買ってみて」)。\n\n文頭の「しかし／でも」には 하지만、그렇지만、よりフォーマルな 그러나 を使う。-지만 は一文内の接続、これら3つは独立した接続詞。',
    ),
  '-(으)면': L(
      'Conditional / temporal "if" or "when" — covers hypothetical ("if it rains, I\'ll stay home") AND habitual time ("when I drink coffee, I get jittery"). Form: vowel or ㄹ stem → -면 (가다 → 가면, 살다 → 살면 with ㄹ kept); consonant stem → -으면 (먹다 → 먹으면).\n\nFor past contrary-to-fact regret ("if I had..."), use -았/었으면 (일찍 갔으면 좋았을 텐데 "it would have been better if I\'d gone early"). The combo -았/었으면 좋겠다 is the standard "I wish / I hope" pattern (빨리 끝났으면 좋겠어요 "I hope it ends soon"). For "only if / as long as", layer 만 onto it: -(으)면만.',
      'Condicional/temporal "si" o "cuando" — cubre lo hipotético ("si llueve, me quedo en casa") Y lo habitual ("cuando tomo café, me pongo nervioso"). Forma: raíz en vocal o ㄹ → -면 (가다 → 가면, 살다 → 살면, ㄹ se mantiene); raíz en consonante → -으면 (먹다 → 먹으면).\n\nPara arrepentimiento contrafáctico en pasado ("si hubiera..."), usá -았/었으면 (일찍 갔으면 좋았을 텐데 "habría sido mejor si me hubiera ido temprano"). La combinación -았/었으면 좋겠다 es el patrón estándar de "ojalá / espero que" (빨리 끝났으면 좋겠어요 "espero que termine pronto"). Para "solo si / siempre que", añadí 만: -(으)면만.',
      'Conditionnel / temporel « si » ou « quand » — couvre l\'hypothèse (« s\'il pleut, je reste à la maison ») ET l\'habituel (« quand je bois du café, je suis nerveux »). Forme : racine en voyelle ou ㄹ → -면 (가다 → 가면, 살다 → 살면, ㄹ conservé) ; racine en consonne → -으면 (먹다 → 먹으면).\n\nPour le regret contrefactuel au passé (« si j\'avais... »), employer -았/었으면 (일찍 갔으면 좋았을 텐데 « ça aurait été mieux si j\'étais parti tôt »). La combinaison -았/었으면 좋겠다 est la formule standard pour « j\'espère / j\'aimerais » (빨리 끝났으면 좋겠어요 « j\'espère que ça finira vite »). Pour « seulement si / pourvu que », ajouter 만 : -(으)면만.',
      'Condicional/temporal "se" ou "quando" — cobre o hipotético ("se chover, fico em casa") E o habitual ("quando tomo café, fico agitado"). Forma: radical em vogal ou ㄹ → -면 (가다 → 가면, 살다 → 살면, ㄹ mantido); radical em consoante → -으면 (먹다 → 먹으면).\n\nPara arrependimento contrafactual no passado ("se eu tivesse..."), use -았/었으면 (일찍 갔으면 좋았을 텐데 "teria sido melhor se eu tivesse ido cedo"). A combinação -았/었으면 좋겠다 é a fórmula padrão de "tomara que / espero que" (빨리 끝났으면 좋겠어요 "espero que termine logo"). Para "só se / contanto que", junte 만: -(으)면만.',
      'รูปเงื่อนไข/เวลา "ถ้า/เมื่อ" — ครอบคลุมทั้งสมมุติฐาน ("ถ้าฝนตก ฉันจะอยู่บ้าน") และความเคยชิน ("เมื่อดื่มกาแฟ ฉันใจสั่น"). รูป: รากลงสระหรือ ㄹ → -면 (가다 → 가면, 살다 → 살면 ㄹ คงไว้); รากลงพยัญชนะ → -으면 (먹다 → 먹으면).\n\nถ้าจะเสียดายแบบขัดข้อเท็จจริงในอดีต ("ถ้าฉันได้..."), ใช้ -았/었으면 (일찍 갔으면 좋았을 텐데 "น่าจะดีกว่านี้ถ้าไปเร็วกว่านี้"). คู่ -았/었으면 좋겠다 เป็นรูปมาตรฐานของ "หวังว่า/อยากให้" (빨리 끝났으면 좋겠어요 "หวังว่าจะจบเร็ว ๆ"). ถ้าจะแปลว่า "ก็ต่อเมื่อ" ให้เติม 만: -(으)면만',
      'Bersyarat / waktu "kalau" atau "ketika" — mencakup hipotetik ("kalau hujan, saya di rumah") DAN habitual ("kalau saya minum kopi, jadi gugup"). Bentuk: akar vokal atau ㄹ → -면 (가다 → 가면, 살다 → 살면 dengan ㄹ tetap); akar konsonan → -으면 (먹다 → 먹으면).\n\nUntuk penyesalan kontrafaktual lampau ("kalau saja saya..."), pakai -았/었으면 (일찍 갔으면 좋았을 텐데 "akan lebih baik kalau saya pergi lebih awal"). Kombinasi -았/었으면 좋겠다 adalah pola standar "semoga / berharap" (빨리 끝났으면 좋겠어요 "semoga cepat selesai"). Untuk "hanya kalau / asalkan", tambahkan 만: -(으)면만.',
      'Điều kiện/thời gian "nếu" hoặc "khi" — bao quát giả định ("nếu trời mưa, tôi ở nhà") VÀ thói quen ("khi uống cà phê, tôi bồn chồn"). Hình thức: gốc nguyên âm hoặc ㄹ → -면 (가다 → 가면, 살다 → 살면 ㄹ giữ); gốc phụ âm → -으면 (먹다 → 먹으면).\n\nĐể tiếc nuối ngược-thực-tế ở quá khứ ("giá mà tôi đã..."), dùng -았/었으면 (일찍 갔으면 좋았을 텐데 "sẽ tốt hơn nếu tôi đi sớm"). Kết hợp -았/었으면 좋겠다 là mẫu chuẩn "ước gì / mong rằng" (빨리 끝났으면 좋겠어요 "mong sớm kết thúc"). Để nói "chỉ khi / miễn là", thêm 만: -(으)면만.',
      '条件・時の「もし／〜たら／〜と」— 仮定(「雨が降ったら家にいる」)も習慣的時間(「コーヒーを飲むと落ち着かない」)もカバーする。形: 母音または ㄹ 語幹 → -면(가다 → 가면、살다 → 살면 で ㄹ 保持); 子音語幹 → -으면(먹다 → 먹으면)。\n\n事実に反する過去への悔恨(「もし〜していたら」)には -았/었으면 を使う(일찍 갔으면 좋았을 텐데「早く行っていればよかったのに」)。-았/었으면 좋겠다 は「〜だったらいいな／〜したい」の定番(빨리 끝났으면 좋겠어요「早く終わってほしい」)。「〜さえすれば」と限定するときは 만 を重ねる: -(으)면만。',
    ),
  '-ㄴ/는데': L(
      "One of the most-used Korean connectors — sets up background context, softens a request, or signals mild contrast. Don't translate as a hard \"but\": often it just means \"the situation is X, so...\". Form changes by part of speech: present action verb → -는데 (가다 → 가는데, 먹다 → 먹는데); present adjective → -ㄴ/은데 (예쁘다 → 예쁜데, 좋다 → 좋은데, 작다 → 작은데); past (any) → -았/었는데 (갔는데, 좋았는데); copula → -ㄴ/인데 (학생인데).\n\nOften left dangling at the end of a sentence as a soft hedge: 비가 오는데요... (\"it's raining though...\"). The non-dangling sentence-initial counterpart is 그런데 (\"by the way / but\").",
      'Uno de los conectores más usados — pone contexto de fondo, suaviza un pedido o marca contraste leve. No lo traduzcas como un "pero" duro: muchas veces es solo "la cosa es que X, así que...". La forma cambia según la palabra: verbo de acción presente → -는데 (가다 → 가는데, 먹다 → 먹는데); adjetivo presente → -ㄴ/은데 (예쁘다 → 예쁜데, 좋다 → 좋은데, 작다 → 작은데); pasado (cualquiera) → -았/었는데 (갔는데, 좋았는데); cópula → -ㄴ/인데 (학생인데).\n\nMuchas veces queda colgando al final como matiz suave: 비가 오는데요... ("es que está lloviendo..."). El equivalente al inicio de oración (no colgante) es 그런데 ("por cierto / pero").',
      'Un des connecteurs les plus employés — pose le contexte, adoucit une demande ou marque un contraste léger. Ne le traduis pas par un « mais » fort : très souvent il dit juste « la situation est X, donc... ». Forme selon la nature du mot : verbe d\'action au présent → -는데 (가다 → 가는데, 먹다 → 먹는데) ; adjectif au présent → -ㄴ/은데 (예쁘다 → 예쁜데, 좋다 → 좋은데, 작다 → 작은데) ; passé (tout cas) → -았/었는데 (갔는데, 좋았는데) ; copule → -ㄴ/인데 (학생인데).\n\nSouvent laissé en suspens en fin de phrase comme atténuation : 비가 오는데요... (« il pleut, voyez... »). L\'équivalent en début de phrase est 그런데 (« au fait / mais »).',
      'Um dos conectores mais usados — apresenta contexto de fundo, suaviza um pedido ou marca contraste leve. Não traduza como um "mas" duro: muitas vezes é só "acontece que X, então...". A forma muda pela classe da palavra: verbo de ação presente → -는데 (가다 → 가는데, 먹다 → 먹는데); adjetivo presente → -ㄴ/은데 (예쁘다 → 예쁜데, 좋다 → 좋은데, 작다 → 작은데); passado (qualquer) → -았/었는데 (갔는데, 좋았는데); cópula → -ㄴ/인데 (학생인데).\n\nFrequentemente fica solto no fim como hedge: 비가 오는데요... ("é que está chovendo..."). O equivalente no início de frase é 그런데 ("aliás / mas").',
      'หนึ่งในคำเชื่อมที่ใช้บ่อยที่สุด — เกริ่นบริบท ทำให้คำขออ่อนลง หรือบอกความขัดแย้งเบา ๆ. อย่าแปลเป็น "แต่" แบบแข็ง: หลายครั้งหมายแค่ "คือว่า X เลย...". รูปเปลี่ยนตามชนิดของคำ: กริยาแสดงการกระทำปัจจุบัน → -는데 (가다 → 가는데, 먹다 → 먹는데); คำคุณศัพท์ปัจจุบัน → -ㄴ/은데 (예쁘다 → 예쁜데, 좋다 → 좋은데, 작다 → 작은데); อดีต (ทุกแบบ) → -았/었는데 (갔는데, 좋았는데); กริยานุเคราะห์ → -ㄴ/인데 (학생인데).\n\nมักทิ้งค้างท้ายประโยคเป็นการสื่อความนุ่มนวล: 비가 오는데요... ("คือว่าฝนตกอยู่..."). รูปเทียบที่ใช้ต้นประโยคคือ 그런데 ("เอ้อ/แต่")',
      'Salah satu penghubung paling sering dipakai — menyiapkan latar, melembutkan permintaan, atau menandai kontras lembut. Jangan terjemahkan sebagai "tapi" yang keras: sering hanya "situasinya begini, jadi...". Bentuk berubah menurut jenis kata: verba aksi kini → -는데 (가다 → 가는데, 먹다 → 먹는데); adjektiva kini → -ㄴ/은데 (예쁘다 → 예쁜데, 좋다 → 좋은데, 작다 → 작은데); lampau (apa pun) → -았/었는데 (갔는데, 좋았는데); kopula → -ㄴ/인데 (학생인데).\n\nSering dibiarkan menggantung di akhir kalimat sebagai pelembut: 비가 오는데요... ("ini sedang hujan..."). Padanan untuk awal kalimat adalah 그런데 ("ngomong-ngomong / tapi").',
      'Một trong những liên từ được dùng nhiều nhất — đặt bối cảnh, làm dịu yêu cầu, hoặc đánh dấu tương phản nhẹ. Đừng dịch thành "nhưng" mạnh: nhiều khi chỉ có nghĩa "tình hình là X, nên...". Hình thức thay đổi theo loại từ: động từ hành động hiện tại → -는데 (가다 → 가는데, 먹다 → 먹는데); tính từ hiện tại → -ㄴ/은데 (예쁘다 → 예쁜데, 좋다 → 좋은데, 작다 → 작은데); quá khứ (mọi loại) → -았/었는데 (갔는데, 좋았는데); hệ từ → -ㄴ/인데 (학생인데).\n\nThường để lửng ở cuối câu như nói giảm: 비가 오는데요... ("trời đang mưa mà..."). Bản đầu câu là 그런데 ("nhân tiện / nhưng").',
      '韓国語で最もよく使われる接続の一つ — 背景の前置き、依頼の和らげ、軽い対比などを表す。「強い『しかし』」と訳さないこと: 多くの場合「実は〜なので…」というニュアンス。品詞で形が変わる: 現在の動作動詞 → -는데(가다 → 가는데、먹다 → 먹는데); 現在の形容詞 → -ㄴ/은데(예쁘다 → 예쁜데、좋다 → 좋은데、작다 → 작은데); 過去(動詞・形容詞共通) → -았/었는데(갔는데、좋았는데); 繋辞 → -ㄴ/인데(학생인데)。\n\n文末に言いさし的に残すこともよくある: 비가 오는데요…「雨が降ってるんですけど…」。文頭で立てる対応形は 그런데(「ところで／でも」)。',
    ),
  '-고 싶다': L(
      'Expresses desire to do something. Attach -고 싶다 directly to the verb stem (보다 → 보고 싶다, 먹다 → 먹고 싶다, 가다 → 가고 싶다). The object usually takes 을/를 in textbooks (드라마를 보고 싶어요), but native speakers very often switch to 이/가 with this pattern (드라마가 보고 싶어요) — both are fine and very common.\n\nCrucial restriction: -고 싶다 is for 1st person (I) or 2nd person in questions (do YOU want?). For describing a 3rd person\'s desire, switch to -고 싶어하다 (동생이 드라마를 보고 싶어해요 "my sibling wants to watch a drama"). Past form: -고 싶었어요 ("I wanted to"). Negative is the regular 안 / -지 않다 on 싶다 (가고 싶지 않아요 "I don\'t want to go").',
      'Expresa el deseo de hacer algo. Pegá -고 싶다 directo a la raíz del verbo (보다 → 보고 싶다, 먹다 → 먹고 싶다, 가다 → 가고 싶다). El objeto suele llevar 을/를 en los libros (드라마를 보고 싶어요), pero los nativos muchas veces lo cambian a 이/가 con este patrón (드라마가 보고 싶어요) — ambos son correctos y muy comunes.\n\nRestricción clave: -고 싶다 se usa en 1ª persona (yo) o en 2ª persona en preguntas (¿querés vos?). Para describir el deseo de una 3ª persona, cambiá a -고 싶어하다 (동생이 드라마를 보고 싶어해요 "mi hermanito quiere ver un drama"). Pasado: -고 싶었어요 ("quería"). La negación va con el habitual 안 / -지 않다 sobre 싶다 (가고 싶지 않아요 "no quiero ir").',
      'Exprime le désir de faire quelque chose. Colle -고 싶다 directement à la racine du verbe (보다 → 보고 싶다, 먹다 → 먹고 싶다, 가다 → 가고 싶다). L\'objet prend habituellement 을/를 dans les manuels (드라마를 보고 싶어요), mais les natifs basculent très souvent vers 이/가 avec ce modèle (드라마가 보고 싶어요) — les deux sont corrects et très courants.\n\nRestriction essentielle : -고 싶다 s\'emploie à la 1ʳᵉ personne (je) ou à la 2ᵉ dans les questions (veux-tu ?). Pour décrire le désir d\'une 3ᵉ personne, on passe à -고 싶어하다 (동생이 드라마를 보고 싶어해요 « mon frère/ma sœur veut regarder un drama »). Passé : -고 싶었어요 (« je voulais »). La négation utilise les classiques 안 / -지 않다 sur 싶다 (가고 싶지 않아요 « je ne veux pas y aller »).',
      'Expressa o desejo de fazer algo. Anexe -고 싶다 direto ao radical do verbo (보다 → 보고 싶다, 먹다 → 먹고 싶다, 가다 → 가고 싶다). Nos livros o objeto costuma levar 을/를 (드라마를 보고 싶어요), mas os nativos muitas vezes mudam para 이/가 com este padrão (드라마가 보고 싶어요) — ambos são corretos e muito comuns.\n\nRestrição crucial: -고 싶다 é para 1ª pessoa (eu) ou 2ª em perguntas (você quer?). Para descrever o desejo de uma 3ª pessoa, mude para -고 싶어하다 (동생이 드라마를 보고 싶어해요 "meu irmão/irmã quer ver um drama"). Passado: -고 싶었어요 ("eu queria"). A negação vai com o habitual 안 / -지 않다 sobre 싶다 (가고 싶지 않아요 "não quero ir").',
      'แสดงความปรารถนาที่จะทำบางสิ่ง. เกาะ -고 싶다 ตรงกับรากของกริยา (보다 → 보고 싶다, 먹다 → 먹고 싶다, 가다 → 가고 싶다). ในตำราเรียนกรรมมักใส่ 을/를 (드라마를 보고 싶어요) แต่เจ้าของภาษาพูดมักเปลี่ยนเป็น 이/가 กับโครงสร้างนี้ (드라마가 보고 싶어요) — ใช้ได้ทั้งสองแบบและพบบ่อยมาก.\n\nข้อจำกัดสำคัญ: -고 싶다 ใช้กับบุรุษที่ 1 (ฉัน) หรือบุรุษที่ 2 ในคำถาม (คุณอยาก...ไหม). ถ้าจะบอกความปรารถนาของบุรุษที่ 3 ให้เปลี่ยนเป็น -고 싶어하다 (동생이 드라마를 보고 싶어해요 "น้องอยากดูซีรีส์"). รูปอดีต: -고 싶었어요 ("อยากแล้ว"). การปฏิเสธใช้ 안 / -지 않다 ปกติบน 싶다 (가고 싶지 않아요 "ไม่อยากไป")',
      'Mengungkapkan keinginan untuk melakukan sesuatu. Tempelkan -고 싶다 langsung pada akar verba (보다 → 보고 싶다, 먹다 → 먹고 싶다, 가다 → 가고 싶다). Di buku ajar, objeknya biasanya pakai 을/를 (드라마를 보고 싶어요), tapi penutur asli sering berganti ke 이/가 dengan pola ini (드라마가 보고 싶어요) — keduanya benar dan sangat umum.\n\nPembatas penting: -고 싶다 untuk orang pertama (saya) atau orang kedua dalam pertanyaan (apakah kamu mau?). Untuk menggambarkan keinginan orang ketiga, ganti ke -고 싶어하다 (동생이 드라마를 보고 싶어해요 "adik saya ingin menonton drama"). Bentuk lampau: -고 싶었어요 ("saya ingin"). Negasi memakai 안 / -지 않다 biasa pada 싶다 (가고 싶지 않아요 "saya tidak mau pergi").',
      'Diễn tả mong muốn làm điều gì đó. Gắn -고 싶다 trực tiếp vào gốc động từ (보다 → 보고 싶다, 먹다 → 먹고 싶다, 가다 → 가고 싶다). Trong sách giáo khoa, tân ngữ thường đi với 을/를 (드라마를 보고 싶어요), nhưng người bản ngữ rất hay chuyển sang 이/가 với mẫu này (드라마가 보고 싶어요) — cả hai đều đúng và rất phổ biến.\n\nGiới hạn quan trọng: -고 싶다 dùng cho ngôi thứ nhất (tôi) hoặc ngôi thứ hai trong câu hỏi (bạn có muốn không?). Để mô tả mong muốn của ngôi thứ ba, đổi thành -고 싶어하다 (동생이 드라마를 보고 싶어해요 "em tôi muốn xem phim"). Quá khứ: -고 싶었어요 ("tôi đã muốn"). Phủ định dùng 안 / -지 않다 thông thường trên 싶다 (가고 싶지 않아요 "tôi không muốn đi").',
      '「〜したい」という願望を表す。動詞の語幹に -고 싶다 を直接付ける(보다 → 보고 싶다、먹다 → 먹고 싶다、가다 → 가고 싶다)。目的語は教科書では 을/를(드라마를 보고 싶어요)が標準だが、ネイティブはこの形と組むときにしばしば 이/가 に切り替える(드라마가 보고 싶어요)— どちらも正しく非常によく使われる。\n\n重要な制約: -고 싶다 は一人称(私)、または二人称への疑問(〜したいですか?)で使う。三人称の願望を表すときは -고 싶어하다 に切り替える(동생이 드라마를 보고 싶어해요「弟／妹はドラマを見たがっている」)。過去形は -고 싶었어요(「〜したかった」)。否定は通常通り 안 / -지 않다 を 싶다 に付ける(가고 싶지 않아요「行きたくない」)。',
    ),
  '-고 있다': L(
      'Marks an action that\'s currently in progress — "is/are ~ing". Attach -고 있다 directly to the verb stem (먹다 → 먹고 있다, 보다 → 보고 있다, 하다 → 하고 있다). Past: -고 있었다 (그때 자고 있었어요 "I was sleeping then"). The honorific form is -고 계시다 (할머니가 책을 읽고 계세요 "grandma is reading").\n\nNot every English "-ing" maps here: state verbs like 결혼하다 ("to marry") use -고 있다 for the resulting STATE — 결혼했어요 "I am married" uses simple past, but 결혼하고 있어요 sounds odd. For wearing clothes Korean prefers -고 있다 over -아/어요 (옷을 입고 있어요 "I\'m wearing clothes"). Don\'t confuse with -아/어 있다, which is for the resulting state of a completed change (앉아 있어요 "I am seated", not "I am sitting down").',
      'Marca una acción en progreso en este momento — "estoy / estás ~ndo". Pegá -고 있다 directo a la raíz del verbo (먹다 → 먹고 있다, 보다 → 보고 있다, 하다 → 하고 있다). Pasado: -고 있었다 (그때 자고 있었어요 "estaba durmiendo en ese momento"). La forma honorífica es -고 계시다 (할머니가 책을 읽고 계세요 "la abuela está leyendo").\n\nNo todo "-ndo" del español calza acá: verbos de estado como 결혼하다 ("casarse") usan -고 있다 para el ESTADO resultante — 결혼했어요 "estoy casado/a" se dice con pasado simple, mientras que 결혼하고 있어요 suena raro. Para "estar usando ropa", el coreano prefiere -고 있다 antes que -아/어요 (옷을 입고 있어요 "tengo ropa puesta"). No lo confundas con -아/어 있다, que marca el estado resultante de un cambio completado (앉아 있어요 "estoy sentado", no "me estoy sentando").',
      'Marque une action en cours — « être en train de ~ ». Colle -고 있다 directement à la racine du verbe (먹다 → 먹고 있다, 보다 → 보고 있다, 하다 → 하고 있다). Passé : -고 있었다 (그때 자고 있었어요 « je dormais à ce moment-là »). La forme honorifique est -고 계시다 (할머니가 책을 읽고 계세요 « grand-mère est en train de lire »).\n\nTous les « -ant » du français ne s\'y prêtent pas : des verbes d\'état comme 결혼하다 (« se marier ») emploient -고 있다 pour l\'ÉTAT résultant — 결혼했어요 « je suis marié(e) » se dit au passé simple, alors que 결혼하고 있어요 sonne bizarre. Pour « être habillé en », le coréen préfère -고 있다 à -아/어요 (옷을 입고 있어요 « je porte des vêtements »). À ne pas confondre avec -아/어 있다, qui marque l\'état résultant d\'un changement accompli (앉아 있어요 « je suis assis », pas « je m\'assois »).',
      'Marca uma ação em andamento neste momento — "estou / está ~ndo". Anexe -고 있다 direto ao radical do verbo (먹다 → 먹고 있다, 보다 → 보고 있다, 하다 → 하고 있다). Passado: -고 있었다 (그때 자고 있었어요 "estava dormindo naquele momento"). A forma honorífica é -고 계시다 (할머니가 책을 읽고 계세요 "a vovó está lendo").\n\nNem todo "-ndo" do português cabe aqui: verbos de estado como 결혼하다 ("casar-se") usam -고 있다 para o ESTADO resultante — 결혼했어요 "sou casado/a" usa passado simples, enquanto 결혼하고 있어요 soa estranho. Para "estar vestindo", o coreano prefere -고 있다 a -아/어요 (옷을 입고 있어요 "estou usando roupa"). Não confunda com -아/어 있다, que marca o estado resultante de uma mudança concluída (앉아 있어요 "estou sentado", não "estou me sentando").',
      'แสดงการกระทำที่กำลังดำเนินอยู่ในขณะนั้น — "กำลัง ~". เกาะ -고 있다 ตรงรากของกริยา (먹다 → 먹고 있다, 보다 → 보고 있다, 하다 → 하고 있다). อดีต: -고 있었다 (그때 자고 있었어요 "ตอนนั้นกำลังนอนอยู่"). รูปยกย่องคือ -고 계시다 (할머니가 책을 읽고 계세요 "คุณยายกำลังอ่านหนังสือ").\n\n"กำลัง" ในภาษาไทยไม่ตรงทุกกรณี: กริยาบอกสภาพอย่าง 결혼하다 ("แต่งงาน") ใช้ -고 있다 สำหรับ "สภาพ" ผลลัพธ์ — 결혼했어요 "ฉันแต่งงานแล้ว/มีคู่แล้ว" ใช้รูปอดีต ส่วน 결혼하고 있어요 ฟังดูแปลก. สำหรับการใส่เสื้อผ้า เกาหลีนิยมใช้ -고 있다 มากกว่า -아/어요 (옷을 입고 있어요 "ใส่เสื้อผ้าอยู่"). อย่าสับสนกับ -아/어 있다 ซึ่งบอกสภาพผลลัพธ์ของการเปลี่ยนแปลงที่จบแล้ว (앉아 있어요 "นั่งอยู่" ไม่ใช่ "กำลังนั่งลง")',
      'Menandai aksi yang sedang berlangsung saat ini — "sedang ~". Tempelkan -고 있다 langsung pada akar verba (먹다 → 먹고 있다, 보다 → 보고 있다, 하다 → 하고 있다). Lampau: -고 있었다 (그때 자고 있었어요 "saat itu saya sedang tidur"). Bentuk hormatnya -고 계시다 (할머니가 책을 읽고 계세요 "nenek sedang membaca").\n\nTidak semua "sedang" Indonesia cocok di sini: verba keadaan seperti 결혼하다 ("menikah") pakai -고 있다 untuk KEADAAN hasilnya — 결혼했어요 "saya sudah menikah" pakai bentuk lampau sederhana, sedangkan 결혼하고 있어요 terdengar aneh. Untuk "memakai pakaian", Korea lebih suka -고 있다 daripada -아/어요 (옷을 입고 있어요 "saya sedang memakai pakaian"). Jangan tertukar dengan -아/어 있다, yang menandai keadaan hasil dari perubahan yang sudah selesai (앉아 있어요 "saya sedang duduk", bukan "saya sedang duduk turun").',
      'Đánh dấu hành động đang diễn ra ngay lúc này — "đang ~". Gắn -고 있다 trực tiếp vào gốc động từ (먹다 → 먹고 있다, 보다 → 보고 있다, 하다 → 하고 있다). Quá khứ: -고 있었다 (그때 자고 있었어요 "lúc đó tôi đang ngủ"). Dạng kính ngữ là -고 계시다 (할머니가 책을 읽고 계세요 "bà đang đọc sách").\n\nKhông phải mọi "đang" của tiếng Việt đều khớp ở đây: động từ trạng thái như 결혼하다 ("kết hôn") dùng -고 있다 cho TRẠNG THÁI kết quả — 결혼했어요 "tôi đã kết hôn / có gia đình" dùng quá khứ đơn, còn 결혼하고 있어요 nghe lạ tai. Để diễn tả "đang mặc quần áo", tiếng Hàn ưu tiên -고 있다 hơn -아/어요 (옷을 입고 있어요 "tôi đang mặc đồ"). Đừng nhầm với -아/어 있다 vốn đánh dấu trạng thái kết quả của một thay đổi đã hoàn tất (앉아 있어요 "tôi đang ngồi", không phải "tôi đang ngồi xuống").',
      '今この瞬間に進行中の動作を表す「〜している」。動詞の語幹に -고 있다 を直接付ける(먹다 → 먹고 있다、보다 → 보고 있다、하다 → 하고 있다)。過去形は -고 있었다(그때 자고 있었어요「あのとき寝ていました」)。尊敬形は -고 계시다(할머니가 책을 읽고 계세요「祖母が本を読んでいらっしゃる」)。\n\n日本語の「〜ている」がすべてこの形に対応するわけではない: 結婚するなどの状態動詞は結果状態に -고 있다 を使う — 결혼했어요「結婚しています」は単純過去形で表すのが普通で、결혼하고 있어요 は不自然。「服を着ている」は韓国語では -고 있다 が好まれる(옷을 입고 있어요)。-아/어 있다 と混同しないこと: そちらは完了した変化の結果状態を表す(앉아 있어요「座っている」であって「座りつつある」ではない)。',
    ),
  '-(으)러 가다/오다': L(
      'Expresses the purpose of going or coming — "to (do something)". Form: vowel-ending or ㄹ-ending stem → -러 (사다 → 사러, 살다 → 살러); consonant-ending stem → -으러 (먹다 → 먹으러). The second verb is RESTRICTED to motion: 가다, 오다, 다니다 ("commute"), 나가다, 들어오다 and a few similar — not 일하다, 공부하다 on their own.\n\nFor a purpose with non-motion verbs, use -(으)려고 instead (한국어를 배우려고 책을 샀어요 "I bought a book in order to learn Korean"). Quick mental test: if your sentence ends with "go/come/leave/return", reach for -(으)러; if it ends with any other verb, reach for -(으)려고.',
      'Expresa el propósito de ir o venir — "a (hacer)". Forma: raíz en vocal o en ㄹ → -러 (사다 → 사러, 살다 → 살러); raíz en consonante → -으러 (먹다 → 먹으러). El segundo verbo está RESTRINGIDO a movimiento: 가다, 오다, 다니다 ("frecuentar"), 나가다, 들어오다 y unos pocos similares — no 일하다 ni 공부하다 por sí solos.\n\nPara un propósito con verbos que no son de movimiento, usá -(으)려고 (한국어를 배우려고 책을 샀어요 "compré un libro para aprender coreano"). Test mental: si la frase termina en "ir/venir/salir/volver", usá -(으)러; si termina con cualquier otro verbo, usá -(으)려고.',
      'Exprime le but d\'aller ou de venir — « pour (faire) ». Forme : racine en voyelle ou en ㄹ → -러 (사다 → 사러, 살다 → 살러) ; racine en consonne → -으러 (먹다 → 먹으러). Le second verbe est RESTREINT aux verbes de mouvement : 가다, 오다, 다니다 (« fréquenter »), 나가다, 들어오다 et quelques autres — pas 일하다 ni 공부하다 seuls.\n\nPour un but avec un verbe qui n\'est pas de mouvement, employer -(으)려고 (한국어를 배우려고 책을 샀어요 « j\'ai acheté un livre pour apprendre le coréen »). Test rapide : si la phrase se termine par « aller / venir / sortir / rentrer », prendre -(으)러 ; sinon, prendre -(으)려고.',
      'Expressa o propósito de ir ou vir — "para (fazer)". Forma: radical em vogal ou em ㄹ → -러 (사다 → 사러, 살다 → 살러); radical em consoante → -으러 (먹다 → 먹으러). O segundo verbo é RESTRITO a movimento: 가다, 오다, 다니다 ("frequentar"), 나가다, 들어오다 e alguns similares — não 일하다 nem 공부하다 sozinhos.\n\nPara um propósito com verbos que não sejam de movimento, use -(으)려고 (한국어를 배우려고 책을 샀어요 "comprei um livro para aprender coreano"). Teste rápido: se a frase termina com "ir/vir/sair/voltar", use -(으)러; se termina com outro verbo, use -(으)려고.',
      'แสดงจุดประสงค์ของการไป/มา — "ไป/มาเพื่อ (ทำบางอย่าง)". รูป: รากลงสระหรือ ㄹ → -러 (사다 → 사러, 살다 → 살러); รากลงพยัญชนะ → -으러 (먹다 → 먹으러). กริยาตัวที่สอง "จำกัด" เฉพาะกริยาเคลื่อนที่: 가다, 오다, 다니다 ("ไป-มาเป็นประจำ"), 나가다, 들어오다 และไม่กี่ตัวที่คล้ายกัน — ใช้ 일하다 หรือ 공부하다 เดี่ยว ๆ ไม่ได้\n\nถ้าจะบอกจุดประสงค์กับกริยาที่ไม่ใช่เคลื่อนที่ ให้ใช้ -(으)려고 แทน (한국어를 배우려고 책을 샀어요 "ฉันซื้อหนังสือเพื่อเรียนภาษาเกาหลี"). เทคนิคจำง่าย: ถ้าจบประโยคด้วย "ไป/มา/ออก/กลับ" ใช้ -(으)러; ถ้าจบด้วยกริยาอื่น ใช้ -(으)려고',
      'Mengungkapkan tujuan pergi atau datang — "untuk (melakukan)". Bentuk: akar berakhir vokal atau ㄹ → -러 (사다 → 사러, 살다 → 살러); akar berakhir konsonan → -으러 (먹다 → 먹으러). Verba kedua DIBATASI pada verba gerak: 가다, 오다, 다니다 ("rutin pergi"), 나가다, 들어오다, dan beberapa yang mirip — bukan 일하다 atau 공부하다 sendirian.\n\nUntuk tujuan dengan verba non-gerak, pakai -(으)려고 (한국어를 배우려고 책을 샀어요 "saya beli buku untuk belajar bahasa Korea"). Trik cepat: kalau kalimat berakhir dengan "pergi/datang/keluar/pulang", pakai -(으)러; kalau berakhir dengan verba lain, pakai -(으)려고.',
      'Diễn tả mục đích đi hoặc đến — "đi/đến để (làm gì)". Hình thức: gốc kết nguyên âm hoặc ㄹ → -러 (사다 → 사러, 살다 → 살러); gốc kết phụ âm → -으러 (먹다 → 먹으러). Động từ thứ hai BỊ GIỚI HẠN trong nhóm chuyển động: 가다, 오다, 다니다 ("đi lui tới"), 나가다, 들어오다 và vài động từ tương tự — không phải 일하다 hay 공부하다 đứng riêng.\n\nĐể nói mục đích với động từ không chuyển động, dùng -(으)려고 (한국어를 배우려고 책을 샀어요 "tôi mua sách để học tiếng Hàn"). Mẹo nhanh: nếu câu kết bằng "đi/đến/ra/về", chọn -(으)러; nếu kết bằng động từ khác, chọn -(으)려고.',
      '行く・来るの目的を表す「〜しに行く／来る」。形: 母音または ㄹ で終わる語幹 → -러(사다 → 사러、살다 → 살러)、子音で終わる語幹 → -으러(먹다 → 먹으러)。後ろの動詞は移動動詞に「限定」される: 가다、오다、다니다(「通う」)、나가다、들어오다 など — 일하다 や 공부하다 を単独で後ろに置くことはできない。\n\n移動以外の動詞で目的を述べたいときは -(으)려고 を使う(한국어를 배우려고 책을 샀어요「韓国語を学ぶために本を買った」)。簡単な目安: 文末が「行く／来る／出る／戻る」なら -(으)러、それ以外の動詞なら -(으)려고。',
    ),
  '-(으)ㄴ 적이 있다/없다': L(
      'Expresses past experience — "have / have never (done)". Form: take the modifier -(으)ㄴ on a verb (vowel/ㄹ → -ㄴ, consonant → -은) and follow with 적이 있다/없다 (먹다 → 먹은 적이 있다, 가다 → 간 적이 있다, 살다 → 산 적이 있다). Very common with the auxiliary -아/어 보다 ("try"): 가 본 적이 있어요? "have you ever tried going?".\n\nDifferent from simple past: 한국에 갔어요 "I went to Korea" reports a specific event, while 한국에 간 적이 있어요 "I have been to Korea (at some point)" frames it as a life experience. Past form: -(으)ㄴ 적이 있었다 ("had ever"). With negation use 없다, not -지 않다: 가 본 적이 없어요 "I\'ve never gone".',
      'Expresa experiencia pasada — "haber / no haber + participio". Forma: tomá el modificador -(으)ㄴ sobre un verbo (vocal/ㄹ → -ㄴ, consonante → -은) y seguilo con 적이 있다/없다 (먹다 → 먹은 적이 있다, 가다 → 간 적이 있다, 살다 → 산 적이 있다). Muy común con el auxiliar -아/어 보다 ("probar"): 가 본 적이 있어요? "¿probaste ir alguna vez?".\n\nDistinto del pasado simple: 한국에 갔어요 "fui a Corea" reporta un evento específico, mientras que 한국에 간 적이 있어요 "he estado en Corea (alguna vez)" lo enmarca como experiencia de vida. Pasado: -(으)ㄴ 적이 있었다 ("había ido alguna vez"). Con negación se usa 없다, no -지 않다: 가 본 적이 없어요 "nunca fui".',
      'Exprime une expérience passée — « avoir déjà / ne jamais fait ». Forme : on prend le modificateur -(으)ㄴ sur le verbe (voyelle/ㄹ → -ㄴ, consonne → -은) puis 적이 있다/없다 (먹다 → 먹은 적이 있다, 가다 → 간 적이 있다, 살다 → 산 적이 있다). Très souvent combiné à l\'auxiliaire -아/어 보다 (« essayer ») : 가 본 적이 있어요? « as-tu déjà essayé d\'y aller ? ».\n\nÀ distinguer du passé simple : 한국에 갔어요 « je suis allé en Corée » rapporte un événement précis, alors que 한국에 간 적이 있어요 « il m\'est arrivé d\'aller en Corée » présente l\'événement comme une expérience de vie. Passé : -(으)ㄴ 적이 있었다 (« avais déjà fait »). Pour la négation, on utilise 없다, pas -지 않다 : 가 본 적이 없어요 « je n\'y suis jamais allé ».',
      'Expressa experiência passada — "já / nunca fiz". Forma: pegue o modificador -(으)ㄴ no verbo (vogal/ㄹ → -ㄴ, consoante → -은) e siga com 적이 있다/없다 (먹다 → 먹은 적이 있다, 가다 → 간 적이 있다, 살다 → 산 적이 있다). Muito comum com o auxiliar -아/어 보다 ("tentar"): 가 본 적이 있어요? "você já tentou ir?".\n\nDiferente do passado simples: 한국에 갔어요 "fui à Coreia" relata um evento específico, enquanto 한국에 간 적이 있어요 "eu já estive na Coreia (em algum momento)" enquadra como experiência de vida. Passado: -(으)ㄴ 적이 있었다 ("tinha ido alguma vez"). Na negação usa-se 없다, não -지 않다: 가 본 적이 없어요 "nunca fui".',
      'แสดงประสบการณ์ในอดีต — "เคย / ไม่เคยทำ". รูป: ใส่ -(으)ㄴ บนกริยา (สระ/ㄹ → -ㄴ, พยัญชนะ → -은) ตามด้วย 적이 있다/없다 (먹다 → 먹은 적이 있다, 가다 → 간 적이 있다, 살다 → 산 적이 있다). มักใช้คู่กับกริยาช่วย -아/어 보다 ("ลอง"): 가 본 적이 있어요? "เคยลองไปไหม?"\n\nต่างจากรูปอดีตธรรมดา: 한국에 갔어요 "ฉันไปเกาหลี" รายงานเหตุการณ์เฉพาะ ส่วน 한국에 간 적이 있어요 "ฉันเคยไปเกาหลี (สักครั้ง)" บอกในฐานะประสบการณ์ชีวิต. รูปอดีต: -(으)ㄴ 적이 있었다 ("เคยไป (ก่อนหน้านี้)"). การปฏิเสธใช้ 없다 ไม่ใช่ -지 않다: 가 본 적이 없어요 "ไม่เคยไป"',
      'Mengungkapkan pengalaman lampau — "pernah / belum pernah". Bentuk: ambil pemodifikasi -(으)ㄴ pada verba (vokal/ㄹ → -ㄴ, konsonan → -은) lalu lanjutkan dengan 적이 있다/없다 (먹다 → 먹은 적이 있다, 가다 → 간 적이 있다, 살다 → 산 적이 있다). Sangat sering dipadukan dengan auxiliary -아/어 보다 ("mencoba"): 가 본 적이 있어요? "pernahkah kamu mencoba pergi?".\n\nBeda dari lampau sederhana: 한국에 갔어요 "saya pergi ke Korea" melaporkan kejadian spesifik, sedangkan 한국에 간 적이 있어요 "saya pernah ke Korea" menempatkannya sebagai pengalaman hidup. Lampau: -(으)ㄴ 적이 있었다 ("pernah pergi"). Untuk negasi pakai 없다, bukan -지 않다: 가 본 적이 없어요 "belum pernah ke sana".',
      'Diễn tả kinh nghiệm quá khứ — "đã từng / chưa từng". Hình thức: lấy bổ ngữ -(으)ㄴ trên động từ (nguyên âm/ㄹ → -ㄴ, phụ âm → -은) rồi nối với 적이 있다/없다 (먹다 → 먹은 적이 있다, 가다 → 간 적이 있다, 살다 → 산 적이 있다). Rất hay đi cùng trợ động từ -아/어 보다 ("thử"): 가 본 적이 있어요? "bạn đã thử đến đó chưa?".\n\nKhác với quá khứ đơn: 한국에 갔어요 "tôi đã đến Hàn Quốc" báo cáo sự kiện cụ thể, còn 한국에 간 적이 있어요 "tôi đã từng đến Hàn Quốc" đặt nó như một trải nghiệm sống. Quá khứ: -(으)ㄴ 적이 있었다 ("đã từng (trước đó)"). Phủ định dùng 없다, không phải -지 않다: 가 본 적이 없어요 "tôi chưa từng đến đó".',
      '過去の経験を表す「〜したことがある／ない」。形: 動詞に修飾形 -(으)ㄴ を付け(母音／ㄹ → -ㄴ、子音 → -은)、後ろに 적이 있다/없다 を続ける(먹다 → 먹은 적이 있다、가다 → 간 적이 있다、살다 → 산 적이 있다)。補助動詞 -아/어 보다(「試す」)と組み合わせて使うことが非常に多い: 가 본 적이 있어요?「行ってみたことがありますか?」。\n\n単純過去との違い: 한국에 갔어요「韓国に行った」は具体的な出来事の報告、한국에 간 적이 있어요「韓国に行ったことがある(いつかの時点で)」は人生の経験としての枠付け。過去形: -(으)ㄴ 적이 있었다(「(その時点で)行ったことがあった」)。否定は -지 않다 ではなく 없다 を使う: 가 본 적이 없어요「行ったことがない」。',
    ),
  '-겠어요': L(
      'Versatile suffix with three main flavors. (1) Supposition based on what you see/sense — 맛있겠어요! "that must be tasty!", 추웠겠어요 "it must have been cold" (with past: -았/었겠어요). (2) Firm 1st-person intention — 제가 하겠습니다 "I\'ll do it" (more formal/decisive than -(으)ㄹ 거예요). (3) Set phrases where it\'s baked in: 잘 먹겠습니다 (before eating), 잘 부탁드리겠습니다 (asking for kind treatment), 알겠습니다 ("understood").\n\nForm is straightforward: attach -겠- to any verb/adjective stem, then your ending of choice (-어요, -습니다, -니까). Polite: -겠어요. Formal: -겠습니다. Compare neighbors: -(으)ㄹ 거예요 is everyday future/supposition (softer), -(으)ㄹ게요 is a promise to the listener, -겠어요 is sharper and more decisive — perfect for formal commitments and reactions to fresh observations.',
      'Sufijo versátil con tres usos principales. (1) Suposición a partir de lo que ves o sentís — 맛있겠어요! "¡debe estar rico!", 추웠겠어요 "habrá hecho frío" (con pasado: -았/었겠어요). (2) Intención firme en 1ª persona — 제가 하겠습니다 "lo haré yo" (más formal/decisivo que -(으)ㄹ 거예요). (3) Frases fijas donde viene incorporado: 잘 먹겠습니다 (antes de comer), 잘 부탁드리겠습니다 (pidiendo buen trato), 알겠습니다 ("entendido").\n\nLa forma es simple: pegá -겠- a cualquier raíz de verbo/adjetivo y después tu terminación (-어요, -습니다, -니까). Educada: -겠어요. Formal: -겠습니다. Comparalo con los vecinos: -(으)ㄹ 거예요 es futuro/suposición cotidiano (más blando), -(으)ㄹ게요 es una promesa al oyente, -겠어요 es más cortante y decidido — perfecto para compromisos formales y reacciones a observaciones nuevas.',
      'Suffixe polyvalent à trois usages principaux. (1) Supposition fondée sur ce qu\'on voit / perçoit — 맛있겠어요! « ça doit être délicieux ! », 추웠겠어요 « ça a dû être froid » (avec passé : -았/었겠어요). (2) Volonté ferme à la 1ʳᵉ personne — 제가 하겠습니다 « je le ferai » (plus formel / décidé que -(으)ㄹ 거예요). (3) Expressions figées où il est inclus : 잘 먹겠습니다 (avant de manger), 잘 부탁드리겠습니다 (pour demander une bonne réception), 알겠습니다 (« compris »).\n\nForme simple : -겠- s\'attache à n\'importe quel radical de verbe/adjectif, puis la terminaison choisie (-어요, -습니다, -니까). Poli : -겠어요. Formel : -겠습니다. Voisins comparés : -(으)ㄹ 거예요 est un futur/supposition de la vie courante (plus doux), -(으)ㄹ게요 une promesse à l\'interlocuteur, -겠어요 est plus tranchant et décidé — parfait pour des engagements formels et des réactions à des observations nouvelles.',
      'Sufixo versátil com três usos principais. (1) Suposição com base no que você vê/sente — 맛있겠어요! "deve estar uma delícia!", 추웠겠어요 "deve ter feito frio" (com passado: -았/었겠어요). (2) Intenção firme em 1ª pessoa — 제가 하겠습니다 "eu farei" (mais formal/decidido que -(으)ㄹ 거예요). (3) Frases fixas onde já vem embutido: 잘 먹겠습니다 (antes de comer), 잘 부탁드리겠습니다 (pedindo bom tratamento), 알겠습니다 ("entendido").\n\nA forma é simples: anexe -겠- a qualquer radical de verbo/adjetivo e depois sua terminação (-어요, -습니다, -니까). Polida: -겠어요. Formal: -겠습니다. Compare com os primos: -(으)ㄹ 거예요 é futuro/suposição do dia a dia (mais suave), -(으)ㄹ게요 é uma promessa ao ouvinte, -겠어요 é mais cortante e decidido — perfeito para compromissos formais e reações a observações recentes.',
      'คำต่อท้ายที่ใช้ได้หลายแบบ มีสามหน้าที่หลัก. (1) การคาดเดาจากสิ่งที่เห็นหรือสัมผัส — 맛있겠어요! "น่าจะอร่อย!", 추웠겠어요 "คงหนาวมากแน่ ๆ" (กับอดีต: -았/었겠어요). (2) ความตั้งใจหนักแน่นในบุรุษที่ 1 — 제가 하겠습니다 "ผม/ฉันจะทำเอง" (ทางการ/เด็ดขาดกว่า -(으)ㄹ 거예요). (3) สำนวนตายตัวที่มีอยู่ในตัว: 잘 먹겠습니다 (ก่อนกิน), 잘 부탁드리겠습니다 (ขอฝากเนื้อฝากตัว), 알겠습니다 ("เข้าใจครับ/ค่ะ").\n\nรูปง่าย: เกาะ -겠- ตรงรากของกริยา/คำคุณศัพท์ แล้วเติมท้ายที่ต้องการ (-어요, -습니다, -니까). สุภาพ: -겠어요. ทางการ: -겠습니다. เทียบกับเพื่อนบ้าน: -(으)ㄹ 거예요 เป็นรูปอนาคต/คาดเดาในชีวิตประจำวัน (นุ่มกว่า), -(으)ㄹ게요 เป็นคำสัญญากับผู้ฟัง, -겠어요 ดูเด็ดขาดกว่า — เหมาะกับคำมั่นทางการและการแสดงปฏิกิริยาต่อสิ่งที่เพิ่งสังเกตเห็น',
      'Sufiks serbaguna dengan tiga fungsi utama. (1) Dugaan berdasarkan apa yang dilihat/dirasakan — 맛있겠어요! "pasti enak!", 추웠겠어요 "pasti dingin tadi" (dengan lampau: -았/었겠어요). (2) Niat tegas orang pertama — 제가 하겠습니다 "saya akan melakukannya" (lebih formal/menentukan dari -(으)ㄹ 거예요). (3) Frasa baku yang sudah melekat: 잘 먹겠습니다 (sebelum makan), 잘 부탁드리겠습니다 (memohon kebaikan), 알겠습니다 ("paham").\n\nBentuk gampang: tempelkan -겠- pada akar verba/adjektiva apa saja, lalu akhiran pilihan (-어요, -습니다, -니까). Sopan: -겠어요. Formal: -겠습니다. Banding tetangga: -(으)ㄹ 거예요 adalah masa depan/dugaan sehari-hari (lebih lembut), -(으)ㄹ게요 janji kepada lawan bicara, -겠어요 lebih tegas dan menentukan — pas untuk komitmen formal dan reaksi terhadap pengamatan baru.',
      'Hậu tố linh hoạt với ba chức năng chính. (1) Phỏng đoán dựa trên những gì bạn thấy/cảm — 맛있겠어요! "trông ngon thật!", 추웠겠어요 "chắc lúc đó lạnh lắm" (với quá khứ: -았/었겠어요). (2) Ý chí mạnh ngôi thứ nhất — 제가 하겠습니다 "tôi sẽ làm" (trang trọng/dứt khoát hơn -(으)ㄹ 거예요). (3) Cụm cố định đã có sẵn: 잘 먹겠습니다 (trước khi ăn), 잘 부탁드리겠습니다 (xin được giúp đỡ), 알겠습니다 ("đã hiểu").\n\nHình thức đơn giản: gắn -겠- vào bất kỳ gốc động từ/tính từ nào rồi thêm đuôi mong muốn (-어요, -습니다, -니까). Lịch sự: -겠어요. Trang trọng: -겠습니다. So với hàng xóm: -(으)ㄹ 거예요 là tương lai/phỏng đoán hằng ngày (nhẹ hơn), -(으)ㄹ게요 là lời hứa với người nghe, -겠어요 dứt khoát hơn — phù hợp cho cam kết trang trọng và phản ứng với điều vừa quan sát.',
      '三つの使い方がある汎用接尾辞。(1) 目にした／感じ取った状況からの推量 — 맛있겠어요!「おいしそう!」、추웠겠어요「寒かったでしょうね」(過去と組むと -았/었겠어요)。(2) 一人称の強い意志 — 제가 하겠습니다「私がやります」(-(으)ㄹ 거예요 より硬く決然)。(3) 定型表現の中に組み込まれた使い方: 잘 먹겠습니다(食事前)、잘 부탁드리겠습니다(よろしくお願いします)、알겠습니다(「承知しました」)。\n\n形は単純: 動詞・形容詞のどんな語幹にも -겠- を付け、好みの語尾(-어요、-습니다、-니까)を続ける。丁寧形: -겠어요。フォーマル形: -겠습니다。仲間との対比: -(으)ㄹ 거예요 は日常の未来・推量(柔らかい)、-(으)ㄹ게요 は聞き手への約束、-겠어요 はもっと鋭く決然 — フォーマルな誓約や、目にした事柄への反応にぴったり。',
    ),
  '-(으)ㄹ래요?': L(
      'Conversational suffix with two faces. As a question (?), it offers an option to the listener — "do you want to / shall we ~?" (같이 갈래요? "want to go together?"). As a statement (.), it expresses your own preference or soft commitment — 저는 안 갈래요 "I won\'t go / I\'d rather not". Form: vowel/ㄹ stem → -ㄹ래요 (가다 → 갈래요, 살다 → 살래요); consonant stem → -을래요 (먹다 → 먹을래요).\n\nClose neighbors with subtle differences. -(으)ㄹ까요? "shall we?" (asking for your preference / opinion) is more about consulting than offering. -(으)ㄹ게요 "I\'ll do it" is a promise made to the listener. -고 싶다 is desire ("want"). -(으)ㄹ래요? lands between an invitation and a check-in — friendly, casual, very useful in everyday speech but limited to polite-informal; for formal contexts switch to -(으)시겠어요? or a politer phrasing.',
      'Sufijo conversacional con dos caras. Como pregunta (?) ofrece una opción al oyente — "¿querés / vamos a ~?" (같이 갈래요? "¿vamos juntos?"). Como afirmación (.) expresa tu preferencia o compromiso suave — 저는 안 갈래요 "yo no voy / no quiero ir". Forma: raíz en vocal o ㄹ → -ㄹ래요 (가다 → 갈래요, 살다 → 살래요); raíz en consonante → -을래요 (먹다 → 먹을래요).\n\nVecinos cercanos con matices: -(으)ㄹ까요? "¿hacemos...?" (te consulto tu opinión) es más consulta que oferta. -(으)ㄹ게요 "voy a hacerlo" es promesa al oyente. -고 싶다 es deseo ("quiero"). -(으)ㄹ래요? cae en el medio: entre invitación y check-in — amigable, casual, muy útil en habla cotidiana pero limitado a registro educado-informal; para contextos formales pasá a -(으)시겠어요? o a una fórmula más cortés.',
      'Suffixe de conversation à deux visages. En question (?) il propose une option à l\'interlocuteur — « tu veux / on ~ ? » (같이 갈래요? « tu veux y aller avec moi ? »). En affirmation (.) il exprime ta préférence ou un engagement léger — 저는 안 갈래요 « moi, je n\'y vais pas / je préfère pas ». Forme : racine en voyelle ou ㄹ → -ㄹ래요 (가다 → 갈래요, 살다 → 살래요) ; racine en consonne → -을래요 (먹다 → 먹을래요).\n\nVoisins très proches, nuances subtiles. -(으)ㄹ까요? « on ~ ? » (je te demande ton avis) consulte plutôt qu\'il ne propose. -(으)ㄹ게요 « je vais le faire » est une promesse à l\'interlocuteur. -고 싶다 marque le désir (« je veux »). -(으)ㄹ래요? se place entre invitation et vérification — amical, décontracté, très utile à l\'oral, mais limité au poli-familier ; en contexte formel, passe à -(으)시겠어요? ou à une tournure plus polie.',
      'Sufixo conversacional com duas faces. Como pergunta (?), oferece uma opção ao ouvinte — "quer / vamos ~?" (같이 갈래요? "quer ir junto?"). Como afirmação (.), expressa sua preferência ou compromisso suave — 저는 안 갈래요 "eu não vou / prefiro não". Forma: radical em vogal ou ㄹ → -ㄹ래요 (가다 → 갈래요, 살다 → 살래요); radical em consoante → -을래요 (먹다 → 먹을래요).\n\nVizinhos próximos com diferenças sutis. -(으)ㄹ까요? "vamos ~?" (te consulto a opinião) é mais consulta que oferta. -(으)ㄹ게요 "vou fazer" é promessa ao ouvinte. -고 싶다 é desejo ("quero"). -(으)ㄹ래요? fica entre convite e check-in — amistoso, casual, muito útil na fala diária mas limitado a registro educado-informal; em contextos formais troque por -(으)시겠어요? ou por uma fórmula mais polida.',
      'คำต่อท้ายแบบสนทนาที่มีสองหน้า. แบบคำถาม (?) เป็นการเสนอตัวเลือกให้ผู้ฟัง — "อยาก/ไป ~ ไหม?" (같이 갈래요? "ไปด้วยกันไหม?"). แบบบอกเล่า (.) บอกความชอบหรือคำมั่นเบา ๆ ของตัวเอง — 저는 안 갈래요 "ฉันไม่ไป/ไม่อยากไปดีกว่า". รูป: รากสระ/ㄹ → -ㄹ래요 (가다 → 갈래요, 살다 → 살래요); รากพยัญชนะ → -을래요 (먹다 → 먹을래요).\n\nเพื่อนบ้านที่ต้องแยกให้ดี. -(으)ㄹ까요? "ไป...ไหม?" (ขอความเห็น) เน้นการปรึกษามากกว่าการเสนอ. -(으)ㄹ게요 "จะทำ" คือคำสัญญากับผู้ฟัง. -고 싶다 คือความปรารถนา ("อยาก"). -(으)ㄹ래요? อยู่ระหว่างคำเชิญกับการเช็คความสนใจ — เป็นกันเอง สบาย ใช้บ่อยในการพูด แต่จำกัดที่ระดับสุภาพ-ไม่ทางการ; ในบริบททางการให้เปลี่ยนเป็น -(으)시겠어요? หรือสำนวนสุภาพกว่า',
      'Sufiks percakapan dengan dua wajah. Sebagai pertanyaan (?), menawarkan opsi kepada lawan bicara — "mau / yuk ~?" (같이 갈래요? "mau pergi bareng?"). Sebagai pernyataan (.), mengungkap preferensi atau komitmen lembut diri sendiri — 저는 안 갈래요 "saya tidak akan pergi / tidak mau". Bentuk: akar vokal/ㄹ → -ㄹ래요 (가다 → 갈래요, 살다 → 살래요); akar konsonan → -을래요 (먹다 → 먹을래요).\n\nTetangga dekat dengan perbedaan halus. -(으)ㄹ까요? "kita ~?" (meminta pendapat) lebih konsultatif daripada menawarkan. -(으)ㄹ게요 "saya akan" adalah janji kepada lawan bicara. -고 싶다 keinginan ("ingin"). -(으)ㄹ래요? berada di antara undangan dan basa-basi — akrab, santai, sangat berguna dalam percakapan tapi terbatas pada register sopan-santai; di konteks formal ganti ke -(으)시겠어요? atau ungkapan yang lebih sopan.',
      'Hậu tố hội thoại có hai chức năng. Là câu hỏi (?), nó đề nghị một lựa chọn cho người nghe — "bạn có muốn / mình ~ không?" (같이 갈래요? "đi cùng nhau không?"). Là câu khẳng định (.), nó thể hiện sở thích hoặc cam kết nhẹ của bản thân — 저는 안 갈래요 "tôi không đi / tôi không muốn". Hình thức: gốc nguyên âm/ㄹ → -ㄹ래요 (가다 → 갈래요, 살다 → 살래요); gốc phụ âm → -을래요 (먹다 → 먹을래요).\n\nHàng xóm gần với sắc thái khác nhau. -(으)ㄹ까요? "mình ~ nhé?" (xin ý kiến) thiên về tham khảo hơn là đề nghị. -(으)ㄹ게요 "tôi sẽ làm" là lời hứa với người nghe. -고 싶다 là khao khát ("muốn"). -(으)ㄹ래요? nằm giữa lời mời và việc thăm dò — thân thiện, thoải mái, rất hữu dụng trong khẩu ngữ nhưng giới hạn ở mức lịch sự-thân mật; trong bối cảnh trang trọng hãy chuyển sang -(으)시겠어요? hoặc cách diễn đạt lịch sự hơn.',
      '会話で多用される、二つの顔をもつ語尾。疑問(?)では聞き手に選択肢を差し出す「〜しませんか／〜する?」(같이 갈래요?「一緒に行きませんか?」)。叙述(.)では自分の意向や軽い約束を表す「私は〜します／しません」(저는 안 갈래요「私は行きません」)。形: 母音または ㄹ 語幹 → -ㄹ래요(가다 → 갈래요、살다 → 살래요); 子音語幹 → -을래요(먹다 → 먹을래요)。\n\n近隣との微差。-(으)ㄹ까요?「〜しましょうか?」は相手の意見を伺うニュアンスが強い。-(으)ㄹ게요「〜しますね」は聞き手への約束。-고 싶다 は願望(「〜したい」)。-(으)ㄹ래요? は誘いと意向確認の中間 — 親しみやすく日常会話で大活躍するが、丁寧体・カジュアル寄りに限られる。フォーマルな場面では -(으)시겠어요? や、より丁寧な言い回しに切り替える。',
    ),
  '-네요': L(
      'Marks something you\'ve just noticed or are reacting to in the moment — discovery, mild surprise, or sympathy. Attach -네요 directly to the stem of verbs, adjectives, and 있다/없다 (예쁘다 → 예쁘네요, 비가 오다 → 비가 오네요, 맛있다 → 맛있네요). Past: -았/었네요 (어제 비 왔네요 "oh, it rained yesterday"). Casual drop-the-요 form is just -네 (예쁘네!) among friends.\n\nThe nuance lives in immediacy: -네요 reacts to fresh information, while plain -아/어요 is more neutral. Tasting soup: 맛있어요 "it\'s tasty" reports the fact; 맛있네요 "oh, this is tasty!" sounds like you just noticed. Don\'t use -네요 for things you already knew or for sentences about yourself in a non-reactive way — it would sound oddly performative. Excellent for compliments and small-talk: 한국말 잘하시네요! ("you speak Korean well, I see!").',
      'Marca algo que acabás de notar o a lo que estás reaccionando en el momento — descubrimiento, sorpresa suave o empatía. Pegá -네요 directo a la raíz de verbos, adjetivos y 있다/없다 (예쁘다 → 예쁘네요, 비가 오다 → 비가 오네요, 맛있다 → 맛있네요). Pasado: -았/었네요 (어제 비 왔네요 "anda, ayer llovió"). La versión casual sin -요 queda en -네 (예쁘네!) entre amigos.\n\nLa diferencia está en la inmediatez: -네요 reacciona a información fresca, mientras que -아/어요 es más neutro. Probando sopa: 맛있어요 "está rica" reporta el hecho; 맛있네요 "¡anda, qué rica!" suena a que recién lo notaste. No uses -네요 para algo que ya sabías o para hablar de vos mismo en modo no reactivo — sonaría performativo. Excelente para cumplidos y small-talk: 한국말 잘하시네요! ("¡hablás bien coreano!", como descubriéndolo).',
      'Marque ce qu\'on vient juste de remarquer ou ce à quoi on réagit sur le moment — découverte, légère surprise ou sympathie. Colle -네요 directement à la racine des verbes, adjectifs et de 있다/없다 (예쁘다 → 예쁘네요, 비가 오다 → 비가 오네요, 맛있다 → 맛있네요). Passé : -았/었네요 (어제 비 왔네요 « tiens, il a plu hier »). En version familière, on laisse tomber le -요 : -네 (예쁘네!) entre amis.\n\nLa nuance tient à l\'immédiateté : -네요 réagit à une information fraîche, alors que -아/어요 reste plus neutre. En goûtant la soupe : 맛있어요 « c\'est bon » constate le fait ; 맛있네요 « ah, c\'est bon ! » donne l\'impression qu\'on vient de le découvrir. À éviter pour des choses qu\'on savait déjà ou pour parler de soi sans réelle réaction — l\'effet est étrangement théâtral. Excellent pour les compliments et la small-talk : 한국말 잘하시네요! (« tiens, vous parlez bien coréen ! »).',
      'Marca algo que você acabou de notar ou está reagindo no momento — descoberta, surpresa leve ou empatia. Anexe -네요 direto ao radical de verbos, adjetivos e 있다/없다 (예쁘다 → 예쁘네요, 비가 오다 → 비가 오네요, 맛있다 → 맛있네요). Passado: -았/었네요 (어제 비 왔네요 "olha, ontem choveu"). Versão casual sem -요 fica em -네 (예쁘네!) entre amigos.\n\nA nuance está na imediatidade: -네요 reage a informação fresca, enquanto -아/어요 é mais neutro. Provando sopa: 맛있어요 "está bom" reporta o fato; 맛있네요 "nossa, está gostoso!" soa como se você tivesse acabado de notar. Não use -네요 para coisas que já sabia ou para falar de si mesmo sem reação — soa estranhamente teatral. Ótimo para elogios e small-talk: 한국말 잘하시네요! ("nossa, você fala bem coreano!").',
      'แสดงสิ่งที่เพิ่งสังเกตเห็นหรือกำลังตอบสนองในตอนนั้น — การค้นพบ ประหลาดใจเบา ๆ หรือเห็นอกเห็นใจ. เกาะ -네요 ตรงรากของกริยา คำคุณศัพท์ และ 있다/없다 (예쁘다 → 예쁘네요, 비가 오다 → 비가 오네요, 맛있다 → 맛있네요). อดีต: -았/었네요 (어제 비 왔네요 "อ้าว เมื่อวานฝนตกแฮะ"). รูปกันเองตัด -요 เหลือ -네 (예쁘네!) ระหว่างเพื่อน\n\nความต่างอยู่ที่ความสด: -네요 ตอบสนองต่อข้อมูลที่เพิ่งรับรู้ ส่วน -아/어요 เป็นกลางกว่า. ตอนชิมซุป: 맛있어요 "อร่อย" รายงานข้อเท็จจริง ส่วน 맛있네요 "อ้าว อร่อยจัง!" ฟังเหมือนเพิ่งสังเกต. อย่าใช้ -네요 กับสิ่งที่รู้อยู่แล้ว หรือพูดถึงตัวเองโดยไม่มีปฏิกิริยา — จะฟังเฟกตลก. ใช้ดีกับคำชมและสมอลทอล์ก: 한국말 잘하시네요! ("เก่งภาษาเกาหลีมากเลยนะคะ!")',
      'Menandai sesuatu yang baru saja kamu sadari atau yang sedang kamu tanggapi saat itu — penemuan, kaget ringan, atau empati. Tempelkan -네요 langsung pada akar verba, adjektiva, dan 있다/없다 (예쁘다 → 예쁘네요, 비가 오다 → 비가 오네요, 맛있다 → 맛있네요). Lampau: -았/었네요 (어제 비 왔네요 "wah, kemarin hujan ya"). Versi santai tanpa -요 jadi -네 (예쁘네!) di antara teman.\n\nNuansanya soal kesegaran: -네요 menanggapi informasi yang baru, sedangkan -아/어요 lebih netral. Saat mencicip sup: 맛있어요 "enak" melaporkan fakta; 맛있네요 "wah, enak!" terasa seperti baru sadar. Jangan pakai -네요 untuk hal yang sudah kamu tahu atau untuk membicarakan dirimu tanpa reaksi — kesannya jadi seperti pura-pura. Pas untuk pujian dan obrolan ringan: 한국말 잘하시네요! ("oh, kamu jago berbahasa Korea!").',
      'Đánh dấu điều bạn vừa nhận ra hoặc đang phản ứng ngay lúc đó — phát hiện, ngạc nhiên nhẹ hoặc đồng cảm. Gắn -네요 trực tiếp vào gốc động từ, tính từ và 있다/없다 (예쁘다 → 예쁘네요, 비가 오다 → 비가 오네요, 맛있다 → 맛있네요). Quá khứ: -았/었네요 (어제 비 왔네요 "ồ, hôm qua mưa nhỉ"). Dạng thân mật bỏ -요 thành -네 (예쁘네!) giữa bạn bè.\n\nSắc thái nằm ở sự tươi mới: -네요 phản ứng với thông tin vừa tiếp nhận, còn -아/어요 trung tính hơn. Khi nếm canh: 맛있어요 "ngon" chỉ thông báo sự thật; 맛있네요 "ồ, ngon thật!" nghe như vừa nhận ra. Đừng dùng -네요 cho điều đã biết trước hay nói về bản thân theo cách không phản ứng — sẽ nghe diễn xuất kỳ kỳ. Rất hợp cho khen ngợi và trò chuyện nhẹ: 한국말 잘하시네요! ("anh/chị nói tiếng Hàn giỏi quá nhỉ!").',
      'いま気づいたこと、あるいはその場で反応していることを示す — 発見、軽い驚き、共感。動詞・形容詞・있다/없다 の語幹に -네요 を直接付ける(예쁘다 → 예쁘네요、비가 오다 → 비가 오네요、맛있다 → 맛있네요)。過去形は -았/었네요(어제 비 왔네요「あ、昨日雨降ったんですね」)。친구同士のカジュアル形は -요 を落として -네(예쁘네!)。\n\nニュアンスは即時性。-네요 は新しく知った情報への反応、-아/어요 はもっと中立。スープを味見して: 맛있어요「おいしいです」は事実を述べる、맛있네요「あ、これおいしい!」は今気づいたような響き。すでに知っていたことや、自分のことを反応抜きで語る場面で使うと演技じみて聞こえるので避けたい。褒め言葉や雑談で大活躍: 한국말 잘하시네요!(「韓国語、お上手なんですね!」)。',
    ),
  '-지요? / -죠?': L(
      'Asks for confirmation of something you already assume to be true — "~, right?". Form: attach -지요? to the verb/adjective/copula stem (가다 → 가지요?, 좋다 → 좋지요?, 학생이다 → 학생이지요?). In casual speech this contracts to -죠? (좋죠? "it\'s good, right?"). Past: -았/었지요? (어제 갔지요? "you went yesterday, right?").\n\nDifferent from a plain question with -아요? Asking 한국 사람이에요? is a neutral open question ("are you Korean?"); 한국 사람이지요? assumes the answer is yes and invites confirmation ("you\'re Korean, right?"). Also lands often as a soft self-confirmation (그렇지요 "yeah, that\'s right") or as exclamatory agreement. Don\'t pair with brand-new info — it would feel like you\'re putting words in the other person\'s mouth.',
      'Pide confirmación de algo que ya asumís cierto — "~, ¿verdad?". Forma: pegá -지요? a la raíz del verbo/adjetivo/cópula (가다 → 가지요?, 좋다 → 좋지요?, 학생이다 → 학생이지요?). En el habla coloquial se contrae a -죠? (좋죠? "está bien, ¿no?"). Pasado: -았/었지요? (어제 갔지요? "fuiste ayer, ¿no?").\n\nDistinto de una pregunta neutra con -아요? Preguntar 한국 사람이에요? es abierto ("¿sos coreano?"); 한국 사람이지요? asume que la respuesta es sí e invita a confirmar ("sos coreano, ¿no?"). También funciona como auto-confirmación suave (그렇지요 "sí, así es") o como acuerdo enfático. No lo uses con información completamente nueva — sonaría a que estás poniendo palabras en la boca del otro.',
      'Demande la confirmation de quelque chose qu\'on tient déjà pour acquis — « ~, n\'est-ce pas ? ». Forme : colle -지요? à la racine du verbe / adjectif / copule (가다 → 가지요?, 좋다 → 좋지요?, 학생이다 → 학생이지요?). À l\'oral, contraction en -죠? (좋죠? « c\'est bien, non ? »). Passé : -았/었지요? (어제 갔지요? « tu y es allé hier, hein ? »).\n\nÀ distinguer d\'une question neutre en -아요? Demander 한국 사람이에요? est ouvert (« êtes-vous coréen ? ») ; 한국 사람이지요? suppose le oui et invite à confirmer (« vous êtes coréen, n\'est-ce pas ? »). Sert aussi d\'auto-confirmation douce (그렇지요 « oui, c\'est ça ») ou d\'acquiescement emphatique. Ne pas employer avec une information totalement neuve — on aurait l\'air de mettre des mots dans la bouche de l\'interlocuteur.',
      'Pede confirmação de algo que você já assume verdadeiro — "~, né?". Forma: anexe -지요? ao radical do verbo/adjetivo/cópula (가다 → 가지요?, 좋다 → 좋지요?, 학생이다 → 학생이지요?). Na fala casual contrai para -죠? (좋죠? "é bom, né?"). Passado: -았/었지요? (어제 갔지요? "você foi ontem, né?").\n\nDiferente de uma pergunta neutra com -아요? Perguntar 한국 사람이에요? é aberto ("você é coreano?"); 한국 사람이지요? presume que a resposta é sim e convida à confirmação ("você é coreano, né?"). Também aparece como autoconfirmação suave (그렇지요 "é, isso mesmo") ou como concordância enfática. Não use com informação completamente nova — soaria como se você estivesse colocando palavras na boca do outro.',
      'ใช้ขอการยืนยันสิ่งที่คุณคิดว่าเป็นเรื่องจริงอยู่แล้ว — "~, ใช่ไหม?". รูป: เกาะ -지요? ตรงรากกริยา/คำคุณศัพท์/กริยานุเคราะห์ (가다 → 가지요?, 좋다 → 좋지요?, 학생이다 → 학생이지요?). ในภาษาพูดหดเหลือ -죠? (좋죠? "ดีเนอะ?"). อดีต: -았/었지요? (어제 갔지요? "ไปเมื่อวานใช่ไหมคะ?")\n\nต่างจากคำถามเปิดด้วย -아요? ถาม 한국 사람이에요? เป็นกลาง ("คุณเป็นคนเกาหลีไหม?"); 한국 사람이지요? สมมุติว่าคำตอบคือใช่ และเชิญให้ยืนยัน ("คุณเป็นคนเกาหลีใช่ไหม?"). ยังใช้เป็นการยืนยันตัวเองนุ่ม ๆ (그렇지요 "ใช่ ๆ") หรือการเห็นด้วยอย่างเน้น. อย่าใช้กับข้อมูลที่อีกฝ่ายเพิ่งบอก — จะฟังเหมือนคุณกำลังใส่คำพูดให้เขา',
      'Meminta konfirmasi atas hal yang sudah kamu anggap benar — "~, kan?". Bentuk: tempelkan -지요? pada akar verba/adjektiva/kopula (가다 → 가지요?, 좋다 → 좋지요?, 학생이다 → 학생이지요?). Dalam percakapan santai mengerut jadi -죠? (좋죠? "bagus, kan?"). Lampau: -았/었지요? (어제 갔지요? "kamu pergi kemarin, kan?").\n\nBeda dari pertanyaan netral pakai -아요? Bertanya 한국 사람이에요? terbuka ("kamu orang Korea?"); 한국 사람이지요? mengasumsikan jawabannya ya dan mengundang konfirmasi ("kamu orang Korea, kan?"). Juga sering muncul sebagai konfirmasi diri yang lembut (그렇지요 "ya, betul") atau persetujuan tegas. Jangan dipakai untuk info yang benar-benar baru — kesannya jadi menempatkan kata-kata di mulut lawan bicara.',
      'Xin xác nhận điều bạn đã giả định là đúng — "~, đúng không?". Hình thức: gắn -지요? vào gốc động từ/tính từ/hệ từ (가다 → 가지요?, 좋다 → 좋지요?, 학생이다 → 학생이지요?). Trong khẩu ngữ rút gọn thành -죠? (좋죠? "tốt mà, đúng không?"). Quá khứ: -았/었지요? (어제 갔지요? "hôm qua bạn đi, đúng không?").\n\nKhác với câu hỏi trung tính dùng -아요? Hỏi 한국 사람이에요? là mở ("bạn là người Hàn à?"); 한국 사람이지요? giả định câu trả lời là có và mời xác nhận ("bạn là người Hàn nhỉ?"). Cũng hay dùng làm tự xác nhận nhẹ (그렇지요 "ừ đúng vậy") hoặc đồng tình nhấn mạnh. Đừng dùng với thông tin hoàn toàn mới — sẽ nghe như bạn đặt lời vào miệng người khác.',
      'すでに正しいと前提していることに対し確認を求める「〜ですよね?／〜でしょう?」。形: 動詞・形容詞・繋辞の語幹に -지요? を付ける(가다 → 가지요?、좋다 → 좋지요?、학생이다 → 학생이지요?)。口語では -죠? に縮約する(좋죠?「いいですよね?」)。過去形は -았/었지요?(어제 갔지요?「昨日行きましたよね?」)。\n\n-아요? の素朴な疑問とは違う。한국 사람이에요? は中立的(「韓国の方ですか?」)、한국 사람이지요? は答えがイエスだという前提で確認を促す(「韓国の方ですよね?」)。柔らかな自己確認(그렇지요「そうですね」)や強い同意としても多用される。完全に新しい情報には使わない方がよい — 相手の口に言葉を入れているように聞こえる。',
    ),
  '-아/어도 되다': L(
      'Gives or asks for permission — "may / it\'s ok to ~". Form: build the -아/어 stem (same harmony and contractions as -아/어요) and add 도 되다 (앉다 → 앉아도 되다, 먹다 → 먹어도 되다, 하다 → 해도 되다). The "되다" part conjugates normally (돼요, 됩니다, 됐어요). Common variants swap 되다 for 괜찮다 ("be ok") or 좋다 ("be fine") with the same meaning: 앉아도 괜찮아요, 앉아도 좋아요.\n\nAs a question (앉아도 돼요?) it asks permission politely. As a statement (앉아도 돼요) it grants permission. The opposite — denial of permission — is -(으)면 안 되다 ("must not / can\'t": 여기 앉으면 안 돼요 "you can\'t sit here"). Don\'t confuse with -지 않아도 되다, which means "don\'t HAVE to" (absence of obligation) rather than "MUSTN\'T" (prohibition).',
      'Concede o pide permiso — "se puede / ¿puedo ~?". Forma: armá la raíz -아/어 (misma armonía y contracciones que -아/어요) y agregale 도 되다 (앉다 → 앉아도 되다, 먹다 → 먹어도 되다, 하다 → 해도 되다). El 되다 se conjuga normal (돼요, 됩니다, 됐어요). Variantes comunes cambian 되다 por 괜찮다 ("estar bien") o 좋다 ("estar perfecto") con el mismo sentido: 앉아도 괜찮아요, 앉아도 좋아요.\n\nComo pregunta (앉아도 돼요?) pide permiso de manera educada. Como afirmación (앉아도 돼요) concede el permiso. Su opuesto — la negación del permiso — es -(으)면 안 되다 ("no se puede / no debés": 여기 앉으면 안 돼요 "acá no podés sentarte"). No lo confundas con -지 않아도 되다, que significa "no HACE FALTA" (ausencia de obligación) y NO "no debés" (prohibición).',
      'Donne ou demande la permission — « il est permis de / je peux ~ ». Forme : on construit la racine -아/어 (mêmes harmonies et contractions qu\'avec -아/어요) puis on ajoute 도 되다 (앉다 → 앉아도 되다, 먹다 → 먹어도 되다, 하다 → 해도 되다). Le 되다 se conjugue normalement (돼요, 됩니다, 됐어요). Variantes courantes : 되다 se remplace par 괜찮다 (« être ok ») ou 좋다 (« être bien ») avec le même sens : 앉아도 괜찮아요, 앉아도 좋아요.\n\nEn question (앉아도 돼요?) on demande poliment la permission. En affirmation (앉아도 돼요) on l\'accorde. L\'opposé — refus de permission — est -(으)면 안 되다 (« il ne faut pas / on ne peut pas » : 여기 앉으면 안 돼요 « on ne peut pas s\'asseoir ici »). À ne pas confondre avec -지 않아도 되다, qui signifie « ne pas être obligé de » (absence d\'obligation), pas « il ne faut pas » (interdiction).',
      'Concede ou pede permissão — "pode / posso ~?". Forma: construa o radical -아/어 (mesma harmonia e contrações de -아/어요) e some 도 되다 (앉다 → 앉아도 되다, 먹다 → 먹어도 되다, 하다 → 해도 되다). O 되다 se conjuga normalmente (돼요, 됩니다, 됐어요). Variantes comuns trocam 되다 por 괜찮다 ("estar bem") ou 좋다 ("estar legal") com o mesmo sentido: 앉아도 괜찮아요, 앉아도 좋아요.\n\nComo pergunta (앉아도 돼요?) pede permissão educadamente. Como afirmação (앉아도 돼요) concede. O oposto — recusa de permissão — é -(으)면 안 되다 ("não pode": 여기 앉으면 안 돼요 "não pode sentar aqui"). Não confunda com -지 않아도 되다, que significa "não PRECISA" (ausência de obrigação) e NÃO "não pode" (proibição).',
      'ขอหรือให้การอนุญาต — "...ก็ได้ / ขอ ... ได้ไหม?". รูป: สร้างรากของ -아/어 (กฎสระและการหดเหมือน -아/어요) แล้วเติม 도 되다 (앉다 → 앉아도 되다, 먹다 → 먹어도 되다, 하다 → 해도 되다). ส่วน 되다 ผันปกติ (돼요, 됩니다, 됐어요). มีตัวเลือกอื่น: เปลี่ยน 되다 เป็น 괜찮다 ("ไม่เป็นไร") หรือ 좋다 ("ก็ดี") โดยความหมายไม่ต่าง: 앉아도 괜찮아요, 앉아도 좋아요\n\nเป็นคำถาม (앉아도 돼요?) คือขออนุญาตอย่างสุภาพ. เป็นบอกเล่า (앉아도 돼요) คือให้อนุญาต. คู่ตรงข้าม — การห้าม — คือ -(으)면 안 되다 ("ทำไม่ได้": 여기 앉으면 안 돼요 "นั่งตรงนี้ไม่ได้"). อย่าสับสนกับ -지 않아도 되다 ซึ่งแปลว่า "ไม่จำเป็นต้อง" (ไม่มีหน้าที่) ไม่ใช่ "ทำไม่ได้" (ห้าม)',
      'Memberi atau meminta izin — "boleh / boleh saya ~?". Bentuk: bangun akar -아/어 (harmoni dan kontraksi sama dengan -아/어요) lalu tambahkan 도 되다 (앉다 → 앉아도 되다, 먹다 → 먹어도 되다, 하다 → 해도 되다). Bagian 되다 dikonjugasikan normal (돼요, 됩니다, 됐어요). Varian umum mengganti 되다 dengan 괜찮다 ("tidak apa") atau 좋다 ("oke") dengan arti sama: 앉아도 괜찮아요, 앉아도 좋아요.\n\nSebagai pertanyaan (앉아도 돼요?) ini meminta izin dengan sopan. Sebagai pernyataan (앉아도 돼요) memberi izin. Lawannya — penolakan izin — adalah -(으)면 안 되다 ("tidak boleh": 여기 앉으면 안 돼요 "tidak boleh duduk di sini"). Jangan tertukar dengan -지 않아도 되다 yang berarti "tidak HARUS" (tidak ada kewajiban), bukan "tidak BOLEH" (larangan).',
      'Cho hoặc xin phép — "có thể ~ / em ~ được không?". Hình thức: tạo gốc -아/어 (hài hòa và co rút như -아/어요) rồi thêm 도 되다 (앉다 → 앉아도 되다, 먹다 → 먹어도 되다, 하다 → 해도 되다). Phần 되다 chia bình thường (돼요, 됩니다, 됐어요). Biến thể phổ biến: thay 되다 bằng 괜찮다 ("không sao") hoặc 좋다 ("tốt mà") cùng nghĩa: 앉아도 괜찮아요, 앉아도 좋아요.\n\nLà câu hỏi (앉아도 돼요?) là xin phép lịch sự. Là câu khẳng định (앉아도 돼요) là cho phép. Đối lập — cấm — là -(으)면 안 되다 ("không được": 여기 앉으면 안 돼요 "không được ngồi đây"). Đừng nhầm với -지 않아도 되다 nghĩa là "không CẦN PHẢI" (không có nghĩa vụ), không phải "không ĐƯỢC" (cấm).',
      '許可を求めたり与えたりする「〜てもいい」。形: -아/어 語幹を作り(-아/어요 と同じ調和・縮約)、도 되다 を付ける(앉다 → 앉아도 되다、먹다 → 먹어도 되다、하다 → 해도 되다)。되다 は通常通り活用する(돼요、됩니다、됐어요)。되다 を 괜찮다(「大丈夫」)や 좋다(「いい」)に置き換えても意味は同じ: 앉아도 괜찮아요、앉아도 좋아요。\n\n疑問形(앉아도 돼요?)では丁寧に許可を求め、叙述形(앉아도 돼요)では許可を与える。反対の「不許可・禁止」は -(으)면 안 되다(여기 앉으면 안 돼요「ここに座ってはいけません」)。義務がないことを表す -지 않아도 되다(「〜なくてもいい」)と混同しないこと — 後者は禁止ではなく義務免除。',
    ),
  '-지 않아도 되다': L(
      'Expresses absence of obligation — "don\'t have to ~". Form: take the verb stem, add the long-negation -지 않다, then drop into -아도 되다 style: -지 않아도 되다 (걱정하다 → 걱정하지 않아도 되다, 가다 → 가지 않아도 되다). Spoken Korean often contracts to -아/어도 되다 with 안 (안 가도 돼요 "you don\'t have to go"). 되다 can swap with 괜찮다 (걱정 안 해도 괜찮아요).\n\nCritical distinction from prohibition. -지 않아도 되다 = "it\'s not REQUIRED" (you may, but you don\'t have to). -(으)면 안 되다 = "you MUST NOT" (forbidden). 가지 않아도 돼요 "you don\'t have to go" leaves the door open to going; 가면 안 돼요 "you can\'t go" closes it. Mixing them up sends the opposite social signal — be especially careful when reassuring someone or giving directions.',
      'Expresa la ausencia de obligación — "no hace falta ~". Forma: tomá la raíz del verbo, sumá la negación larga -지 않다, y metelo en -아도 되다: -지 않아도 되다 (걱정하다 → 걱정하지 않아도 되다, 가다 → 가지 않아도 되다). El coreano hablado lo contrae a -아/어도 되다 con 안 (안 가도 돼요 "no hace falta que vayas"). 되다 puede cambiarse por 괜찮다 (걱정 안 해도 괜찮아요).\n\nDistinción crítica con la prohibición. -지 않아도 되다 = "no es OBLIGATORIO" (podés, pero no tenés que). -(으)면 안 되다 = "NO DEBÉS / no podés" (prohibido). 가지 않아도 돼요 "no hace falta que vayas" deja abierta la opción de ir; 가면 안 돼요 "no podés ir" la cierra. Mezclarlos manda la señal social opuesta — cuidá especialmente al tranquilizar a alguien o dar indicaciones.',
      'Exprime l\'absence d\'obligation — « ne pas avoir à ~ ». Forme : prends la racine du verbe, ajoute la négation longue -지 않다, puis applique -아도 되다 : -지 않아도 되다 (걱정하다 → 걱정하지 않아도 되다, 가다 → 가지 않아도 되다). À l\'oral, on contracte souvent en -아/어도 되다 avec 안 (안 가도 돼요 « tu n\'es pas obligé d\'y aller »). 되다 se remplace par 괜찮다 (걱정 안 해도 괜찮아요).\n\nDistinction cruciale avec l\'interdiction. -지 않아도 되다 = « ce n\'est pas REQUIS » (tu peux, mais tu n\'es pas obligé). -(으)면 안 되다 = « il ne faut PAS / on n\'a pas le droit » (interdit). 가지 않아도 돼요 « tu n\'es pas obligé d\'y aller » laisse la porte ouverte ; 가면 안 돼요 « tu ne peux pas y aller » la ferme. Les confondre envoie le signal social inverse — fais très attention quand tu rassures quelqu\'un ou donnes une consigne.',
      'Expressa ausência de obrigação — "não precisa ~". Forma: pegue o radical do verbo, some a negação longa -지 않다 e aplique o -아도 되다: -지 않아도 되다 (걱정하다 → 걱정하지 않아도 되다, 가다 → 가지 않아도 되다). Na fala se contrai para -아/어도 되다 com 안 (안 가도 돼요 "você não precisa ir"). 되다 pode trocar por 괜찮다 (걱정 안 해도 괜찮아요).\n\nDistinção crucial com a proibição. -지 않아도 되다 = "não é OBRIGATÓRIO" (você pode, mas não precisa). -(으)면 안 되다 = "NÃO PODE" (proibido). 가지 않아도 돼요 "você não precisa ir" deixa a porta aberta para ir; 가면 안 돼요 "você não pode ir" fecha. Confundi-los manda o sinal social oposto — cuide-se especialmente ao tranquilizar alguém ou dar instruções.',
      'แสดงว่าไม่มีหน้าที่ต้องทำ — "ไม่ต้อง ~ ก็ได้". รูป: เอารากของกริยา, เติมรูปปฏิเสธยาว -지 않다 แล้วใส่เข้า -아도 되다: -지 않아도 되다 (걱정하다 → 걱정하지 않아도 되다, 가다 → 가지 않아도 되다). ภาษาพูดมักหดเป็น -아/어도 되다 ร่วมกับ 안 (안 가도 돼요 "ไม่ต้องไปก็ได้"). 되다 สลับเป็น 괜찮다 ได้ (걱정 안 해도 괜찮아요)\n\nข้อแตกต่างสำคัญกับการห้าม. -지 않아도 되다 = "ไม่จำเป็น" (จะทำหรือไม่ทำก็ได้). -(으)면 안 되다 = "ห้าม / ทำไม่ได้". 가지 않아도 돼요 "ไม่ต้องไปก็ได้" ยังเปิดทางให้ไป; 가면 안 돼요 "ห้ามไป / ไปไม่ได้" ปิดทาง. ใช้สลับกันจะส่งสัญญาณตรงข้ามทางสังคม — ระวังเป็นพิเศษเมื่อปลอบใจหรือให้คำแนะนำ',
      'Mengungkapkan ketiadaan kewajiban — "tidak perlu / tidak harus ~". Bentuk: ambil akar verba, tambahkan negasi panjang -지 않다, lalu masukkan ke -아도 되다: -지 않아도 되다 (걱정하다 → 걱정하지 않아도 되다, 가다 → 가지 않아도 되다). Dalam percakapan sering dikerutkan jadi -아/어도 되다 dengan 안 (안 가도 돼요 "kamu tidak perlu pergi"). 되다 bisa diganti 괜찮다 (걱정 안 해도 괜찮아요).\n\nPerbedaan krusial dari larangan. -지 않아도 되다 = "tidak DIWAJIBKAN" (kamu boleh, tapi tidak harus). -(으)면 안 되다 = "TIDAK BOLEH" (dilarang). 가지 않아도 돼요 "kamu tidak perlu pergi" tetap membuka opsi untuk pergi; 가면 안 돼요 "kamu tidak boleh pergi" menutup. Mencampurnya mengirim sinyal sosial yang berlawanan — ekstra hati-hati saat menenangkan orang atau memberi arahan.',
      'Diễn tả sự vắng mặt của nghĩa vụ — "không cần phải ~". Hình thức: lấy gốc động từ, thêm phủ định dài -지 않다, rồi áp dụng -아도 되다: -지 않아도 되다 (걱정하다 → 걱정하지 않아도 되다, 가다 → 가지 않아도 되다). Khẩu ngữ thường rút gọn thành -아/어도 되다 với 안 (안 가도 돼요 "bạn không cần đi"). 되다 có thể đổi thành 괜찮다 (걱정 안 해도 괜찮아요).\n\nPhân biệt then chốt với cấm đoán. -지 않아도 되다 = "không BẮT BUỘC" (bạn có thể, nhưng không cần). -(으)면 안 되다 = "KHÔNG ĐƯỢC" (cấm). 가지 않아도 돼요 "không cần đi" vẫn để ngỏ khả năng đi; 가면 안 돼요 "không được đi" đóng lại. Lẫn lộn hai cái này sẽ truyền tín hiệu xã hội ngược lại — hết sức cẩn thận khi an ủi ai đó hay đưa ra chỉ dẫn.',
      '義務がないことを表す「〜なくてもいい」。形: 動詞の語幹に長形否定 -지 않다 を付け、-아도 되다 にする: -지 않아도 되다(걱정하다 → 걱정하지 않아도 되다、가다 → 가지 않아도 되다)。会話では 안 と組んで -아/어도 되다 に縮約することが多い(안 가도 돼요「行かなくてもいいですよ」)。되다 は 괜찮다 と置き換え可(걱정 안 해도 괜찮아요)。\n\n禁止との重要な対比。-지 않아도 되다 =「義務ではない」(してもしなくてもよい)。-(으)면 안 되다 =「〜してはいけない」(禁止)。가지 않아도 돼요「行かなくてもいい」は行く選択肢を残す、가면 안 돼요「行ってはいけない」は閉ざす。混同すると社会的メッセージが正反対になる — 安心させたり指示を出したりするときは特に注意。',
    ),
  '-아/어 드리다': L(
      'Expresses "do something for someone" with humility — the humble (낮춤) counterpart of -아/어 주다. Form: take the -아/어 stem (same harmony and contractions as -아/어요) and add 드리다 (돕다 → 도와 드리다, 사다 → 사 드리다, 만들다 → 만들어 드리다). Drop 드리다 in place of 주다 whenever the beneficiary deserves deference — customers, elders, bosses, teachers, anyone you address with 께/께서.\n\nUse it whenever YOU are the one acting for THEM. 도와 드릴게요 "I\'ll help you" (to a customer); 사 드렸어요 "I bought it for them" (about a grandparent). If the helpful one is THEM acting for YOU, use 주시다 instead — the receiver-honoring side of the same favor system (선생님이 가르쳐 주셨어요 "the teacher kindly taught me"). Common in service and formal speech: 안내해 드리겠습니다, 확인해 드릴게요.',
      'Expresa "hacer algo para alguien" con humildad — la versión humilde (낮춤) de -아/어 주다. Forma: tomá la raíz -아/어 (misma armonía y contracciones que -아/어요) y sumá 드리다 (돕다 → 도와 드리다, 사다 → 사 드리다, 만들다 → 만들어 드리다). Cambiá 주다 por 드리다 siempre que el beneficiario merezca deferencia — clientes, mayores, jefes, profes, cualquiera al que tratés con 께/께서.\n\nÚsalo cuando VOS actuás a favor de la OTRA persona. 도와 드릴게요 "lo ayudo" (a un cliente); 사 드렸어요 "se lo compré" (a un abuelo). Si el que ayuda es la OTRA persona hacia VOS, usá 주시다 — la cara que honra al receptor en el mismo sistema de favores (선생님이 가르쳐 주셨어요 "el profe me lo enseñó (amablemente)"). Muy común en servicio y registro formal: 안내해 드리겠습니다, 확인해 드릴게요.',
      'Exprime « faire quelque chose pour quelqu\'un » avec humilité — pendant humble (낮춤) de -아/어 주다. Forme : prends la racine -아/어 (mêmes harmonies et contractions qu\'avec -아/어요) puis ajoute 드리다 (돕다 → 도와 드리다, 사다 → 사 드리다, 만들다 → 만들어 드리다). Remplace 주다 par 드리다 dès que le bénéficiaire mérite la déférence — clients, aînés, supérieurs, enseignants, toute personne qu\'on traite avec 께/께서.\n\nEmploie-le quand C\'EST TOI qui agis pour AUTRUI. 도와 드릴게요 « je vais vous aider » (à un client) ; 사 드렸어요 « je le lui ai acheté » (parlant d\'un grand-parent). Si c\'est AUTRUI qui agit pour TOI, utilise plutôt 주시다 — l\'autre face du système, qui honore celui qui rend service (선생님이 가르쳐 주셨어요 « le professeur a eu la gentillesse de m\'enseigner »). Très courant dans le service et le registre formel : 안내해 드리겠습니다, 확인해 드릴게요.',
      'Expressa "fazer algo por alguém" com humildade — a contraparte humilde (낮춤) de -아/어 주다. Forma: pegue o radical -아/어 (mesma harmonia e contrações de -아/어요) e some 드리다 (돕다 → 도와 드리다, 사다 → 사 드리다, 만들다 → 만들어 드리다). Troque 주다 por 드리다 sempre que o beneficiário merecer deferência — clientes, mais velhos, chefes, professores, qualquer pessoa que você trate com 께/께서.\n\nUse quando VOCÊ é quem age a favor da OUTRA pessoa. 도와 드릴게요 "vou ajudá-lo" (a um cliente); 사 드렸어요 "comprei para ele/ela" (sobre um avô). Se quem está agindo a favor de VOCÊ é a OUTRA pessoa, use 주시다 — o lado que honra quem faz o favor no mesmo sistema (선생님이 가르쳐 주셨어요 "o professor gentilmente me ensinou"). Muito comum em atendimento e registro formal: 안내해 드리겠습니다, 확인해 드릴게요.',
      'แสดงความหมาย "ทำให้ใคร" แบบถ่อมตัว — รูปถ่อม (낮춤) คู่กันกับ -아/어 주다. รูป: เอารากของ -아/어 (กฎสระและการหดเหมือน -아/어요) แล้วเติม 드리다 (돕다 → 도와 드리다, 사다 → 사 드리다, 만들다 → 만들어 드리다). เปลี่ยน 주다 เป็น 드리다 เมื่อผู้รับสมควรได้รับการเคารพ — ลูกค้า ผู้อาวุโส เจ้านาย คุณครู หรือใครก็ตามที่ใช้ 께/께서 ในประโยค\n\nใช้เมื่อ "คุณ" ทำเพื่อ "อีกฝ่าย". 도와 드릴게요 "ดิฉันจะช่วยให้ค่ะ" (กับลูกค้า); 사 드렸어요 "ฉันซื้อให้แล้ว" (เล่าถึงคุณปู่/คุณย่า). ถ้า "อีกฝ่าย" เป็นคนทำเพื่อ "คุณ" ให้ใช้ 주시다 แทน — เป็นอีกด้านของระบบเดียวกันที่ให้เกียรติผู้ทำ (선생님이 가르쳐 주셨어요 "อาจารย์กรุณาสอนให้ฉัน"). พบบ่อยในงานบริการและภาษาทางการ: 안내해 드리겠습니다, 확인해 드릴게요',
      'Mengungkapkan "melakukan untuk seseorang" dengan rendah hati — versi merendah (낮춤) dari -아/어 주다. Bentuk: ambil akar -아/어 (harmoni dan kontraksi sama dengan -아/어요) lalu tambahkan 드리다 (돕다 → 도와 드리다, 사다 → 사 드리다, 만들다 → 만들어 드리다). Ganti 주다 dengan 드리다 setiap kali penerima layak dihormati — pelanggan, orang yang lebih tua, atasan, guru, atau siapa pun yang kamu panggil dengan 께/께서.\n\nPakai saat KAMU yang bertindak untuk ORANG LAIN. 도와 드릴게요 "saya akan membantu Anda" (kepada pelanggan); 사 드렸어요 "saya membelikan untuk beliau" (tentang kakek/nenek). Kalau ORANG LAIN yang bertindak untuk KAMU, pakai 주시다 — sisi sistem yang menghormati pelaku kebaikan (선생님이 가르쳐 주셨어요 "guru mengajari saya dengan baik"). Sering dipakai di pelayanan dan register formal: 안내해 드리겠습니다, 확인해 드릴게요.',
      'Diễn tả "làm gì cho ai" với sự khiêm nhường — đối ngẫu khiêm tốn (낮춤) của -아/어 주다. Hình thức: lấy gốc -아/어 (hài hòa và co rút như -아/어요) rồi thêm 드리다 (돕다 → 도와 드리다, 사다 → 사 드리다, 만들다 → 만들어 드리다). Đổi 주다 sang 드리다 mỗi khi người hưởng lợi đáng được tôn kính — khách hàng, người lớn tuổi, sếp, thầy cô, bất cứ ai bạn xưng hô bằng 께/께서.\n\nDùng khi BẠN là người hành động vì NGƯỜI KIA. 도와 드릴게요 "để em giúp ạ" (với khách); 사 드렸어요 "em đã mua cho bà" (kể về ông/bà). Nếu NGƯỜI KIA là người hành động vì BẠN, dùng 주시다 — mặt còn lại của cùng hệ thống, tôn vinh người làm ơn (선생님이 가르쳐 주셨어요 "thầy đã chỉ dạy em"). Rất phổ biến trong dịch vụ và văn phong trang trọng: 안내해 드리겠습니다, 확인해 드릴게요.',
      '「〜してさしあげる」(謙譲)を表す — -아/어 주다 の謙譲対応形。形: -아/어 語幹を作り(-아/어요 と同じ調和・縮約)、드리다 を付ける(돕다 → 도와 드리다、사다 → 사 드리다、만들다 → 만들어 드리다)。恩恵の受け手が敬意の対象(顧客、目上、上司、先生、께/께서 で呼ぶ相手)であれば、주다 を 드리다 に置き換える。\n\n「自分」が「相手」のために行為するときに使う。도와 드릴게요「お手伝いします」(顧客に); 사 드렸어요「お買いしてさしあげました」(祖父母について)。逆に「相手」が「自分」のために行為する場合は 주시다 を使う — 同じ恩恵システムで、行為者(目上)を敬う側(선생님이 가르쳐 주셨어요「先生が教えてくださった」)。接客やフォーマルな会話で頻出: 안내해 드리겠습니다、확인해 드릴게요。',
    ),
  '의문사': L(
      'The core question words: 뭐 / 무엇 ("what"), 누구 ("who"), 어디 ("where"), 언제 ("when"), 왜 ("why"), 어떻게 ("how"). They sit IN PLACE of the noun in the original sentence — Korean does NOT front them like English does (이름이 뭐예요? "what\'s your name?", literally "name-as-for what-is?"). For "what" the conversational form is 뭐 (뭐 해요? "what are you doing?"); 무엇 is the more written/formal form.\n\nIrregular contractions to remember: 누구 + 가 → 누가 (subject); 무엇 + 을 → 무엇을 / 뭘 (object, often dropped in speech). For "which", use 어느 + noun (어느 나라? "which country?") or 어떤 + noun for "what kind of" (어떤 영화? "what kind of movie?"). Intonation rises naturally at the end like any -아/어요 question — no extra 까? particle needed.',
      'Las palabras de pregunta básicas: 뭐 / 무엇 ("qué"), 누구 ("quién"), 어디 ("dónde"), 언제 ("cuándo"), 왜 ("por qué"), 어떻게 ("cómo"). Van EN EL LUGAR del sustantivo en la frase — el coreano NO las adelanta como el español (이름이 뭐예요? "¿cómo te llamás?", literalmente "nombre-en cuanto a qué-es?"). Para "qué" la forma conversacional es 뭐 (뭐 해요? "¿qué hacés?"); 무엇 es la forma más escrita o formal.\n\nContracciones irregulares clave: 누구 + 가 → 누가 (sujeto); 무엇 + 을 → 무엇을 / 뭘 (objeto, frecuente en habla). Para "cuál" usá 어느 + sustantivo (어느 나라? "¿qué país?") o 어떤 + sustantivo para "qué tipo de" (어떤 영화? "¿qué tipo de película?"). La entonación sube al final como en cualquier pregunta -아/어요 — no hace falta agregar la partícula 까?.',
      'Mots interrogatifs essentiels : 뭐 / 무엇 (« quoi »), 누구 (« qui »), 어디 (« où »), 언제 (« quand »), 왜 (« pourquoi »), 어떻게 (« comment »). Ils restent À LA PLACE du nom dans la phrase ; le coréen ne les antépose PAS comme le français (이름이 뭐예요? « comment t\'appelles-tu ? », littéralement « nom-quant à quoi-est ? »). Pour « quoi », l\'oral préfère 뭐 (뭐 해요? « tu fais quoi ? ») ; 무엇 est plus écrit / formel.\n\nContractions irrégulières à connaître : 누구 + 가 → 누가 (sujet) ; 무엇 + 을 → 무엇을 / 뭘 (objet, souvent omis à l\'oral). Pour « lequel », on emploie 어느 + nom (어느 나라? « quel pays ? ») ou 어떤 + nom pour « quel type de » (어떤 영화? « quel genre de film ? »). L\'intonation monte naturellement à la fin, comme dans toute question en -아/어요 — pas besoin d\'ajouter la particule 까?.',
      'Palavras de pergunta essenciais: 뭐 / 무엇 ("o que"), 누구 ("quem"), 어디 ("onde"), 언제 ("quando"), 왜 ("por que"), 어떻게 ("como"). Elas ficam NO LUGAR do substantivo na frase — coreano NÃO as coloca no início como o português (이름이 뭐예요? "qual é seu nome?", literalmente "nome-quanto a o que-é?"). Para "o que" a forma conversacional é 뭐 (뭐 해요? "o que está fazendo?"); 무엇 é a forma mais escrita ou formal.\n\nContrações irregulares importantes: 누구 + 가 → 누가 (sujeito); 무엇 + 을 → 무엇을 / 뭘 (objeto, frequente na fala). Para "qual" use 어느 + substantivo (어느 나라? "qual país?") ou 어떤 + substantivo para "que tipo de" (어떤 영화? "que tipo de filme?"). A entonação sobe ao final como em qualquer pergunta -아/어요 — não precisa adicionar a partícula 까?.',
      'คำถามหลัก: 뭐 / 무엇 ("อะไร"), 누구 ("ใคร"), 어디 ("ที่ไหน"), 언제 ("เมื่อไหร่"), 왜 ("ทำไม"), 어떻게 ("อย่างไร"). คำเหล่านี้อยู่ "ในตำแหน่ง" ของคำนามในประโยค — เกาหลี "ไม่" ย้ายไปขึ้นต้นแบบภาษาอังกฤษ (이름이 뭐예요? "ชื่ออะไร?" ตามตัวอักษรคือ "ชื่อ-นั้น อะไร-เป็น?"). "อะไร" รูปพูดคือ 뭐 (뭐 해요? "ทำอะไรอยู่?") ส่วน 무엇 เป็นรูปเขียน/ทางการ\n\nรูปหดที่ต้องจำ: 누구 + 가 → 누가 (ประธาน); 무엇 + 을 → 무엇을 / 뭘 (กรรม มักตัดในคำพูด). "อันไหน" ใช้ 어느 + คำนาม (어느 나라? "ประเทศไหน?") หรือ 어떤 + คำนาม สำหรับ "แบบไหน" (어떤 영화? "หนังแบบไหน?"). น้ำเสียงขึ้นปลายเหมือนคำถาม -아/어요 ทั่วไป — ไม่ต้องใส่ 까?',
      'Kata tanya inti: 뭐 / 무엇 ("apa"), 누구 ("siapa"), 어디 ("di mana"), 언제 ("kapan"), 왜 ("mengapa"), 어떻게 ("bagaimana"). Kata-kata ini berada DI POSISI kata bendanya dalam kalimat — bahasa Korea TIDAK menariknya ke depan seperti bahasa Inggris (이름이 뭐예요? "siapa namamu?", harfiah "nama-mengenai apa-adalah?"). Untuk "apa" bentuk percakapan adalah 뭐 (뭐 해요? "sedang apa?"); 무엇 lebih ke bentuk tulisan/formal.\n\nKontraksi tak beraturan yang penting: 누구 + 가 → 누가 (subjek); 무엇 + 을 → 무엇을 / 뭘 (objek, sering dilepas saat bicara). Untuk "yang mana" pakai 어느 + kata benda (어느 나라? "negara mana?") atau 어떤 + kata benda untuk "macam apa" (어떤 영화? "film macam apa?"). Intonasi naik di akhir seperti pertanyaan -아/어요 mana pun — tidak perlu partikel 까?.',
      'Từ để hỏi cốt lõi: 뭐 / 무엇 ("gì"), 누구 ("ai"), 어디 ("ở đâu"), 언제 ("khi nào"), 왜 ("tại sao"), 어떻게 ("thế nào"). Chúng giữ Ở VỊ TRÍ của danh từ trong câu — tiếng Hàn KHÔNG đảo lên đầu như tiếng Anh (이름이 뭐예요? "tên bạn là gì?", nghĩa đen "tên-là gì-là?"). Với "gì", dạng khẩu ngữ là 뭐 (뭐 해요? "bạn đang làm gì?"); 무엇 là dạng viết/trang trọng hơn.\n\nCo rút bất quy tắc cần nhớ: 누구 + 가 → 누가 (chủ ngữ); 무엇 + 을 → 무엇을 / 뭘 (tân ngữ, hay bị bỏ khi nói). Để hỏi "cái nào", dùng 어느 + danh từ (어느 나라? "nước nào?") hoặc 어떤 + danh từ cho "loại nào" (어떤 영화? "phim loại nào?"). Ngữ điệu lên ở cuối như mọi câu hỏi -아/어요 — không cần thêm tiểu từ 까?.',
      '主要な疑問詞: 뭐 / 무엇(「何」)、누구(「誰」)、어디(「どこ」)、언제(「いつ」)、왜(「なぜ」)、어떻게(「どう」)。これらの語は元の文での「名詞の位置にそのまま」入る — 英語のように文頭に出さない(이름이 뭐예요?「お名前は何ですか?」、直訳「名前-は 何-である?」)。「何」の会話形は 뭐(뭐 해요?「何してる?」)、무엇 は文語的・改まった形。\n\n覚えておきたい不規則縮約: 누구 + 가 → 누가(主格); 무엇 + 을 → 무엇을 / 뭘(目的語、会話ではしばしば省略)。「どれ／どの」には 어느 + 名詞(어느 나라?「どの国?」)、「どんな」には 어떤 + 名詞(어떤 영화?「どんな映画?」)。語尾を上げるだけで疑問文になる — 까? 助詞を足す必要はない。',
    ),
  '숫자': L(
      'Korean has TWO complete number systems and you have to pick the right one. Sino-Korean (일, 이, 삼, 사, 오, 육, 칠, 팔, 구, 십...) is for prices, dates, phone numbers, math, anything year-related, big numbers, minutes, seconds, and counters borrowed from Chinese (월/月, 분/分, 초/秒, 번/番). Native Korean (하나, 둘, 셋, 넷, 다섯, 여섯, 일곱, 여덟, 아홉, 열...) is for counting things you can see, ages, hours of the clock, and most native counters (개, 명, 사람, 마리, 살, 시). Time mixes them: 3시 30분 = native 3 (세 시) + sino 30 (삼십 분).\n\nNative numbers 1–4 and 20 shorten before a counter: 하나 → 한, 둘 → 두, 셋 → 세, 넷 → 네, 스물 → 스무 (한 개, 두 명, 세 시, 스무 살). Native numbers only go up to 99 in everyday use; from 100 onward Korean reaches for Sino-Korean even for items (책 백 권 "100 books" uses Sino-Korean 백). Don\'t worry about getting them perfect at first — picking the wrong system is the most forgivable beginner mistake and Koreans will understand.',
      'El coreano tiene DOS sistemas de números completos y hay que elegir el correcto. El sino-coreano (일, 이, 삼, 사, 오, 육, 칠, 팔, 구, 십...) se usa para precios, fechas, números de teléfono, matemática, todo lo del año, números grandes, minutos, segundos y contadores tomados del chino (월/月, 분/分, 초/秒, 번/番). El nativo (하나, 둘, 셋, 넷, 다섯, 여섯, 일곱, 여덟, 아홉, 열...) se usa para contar cosas, edad, horas del reloj y casi todos los contadores autóctonos (개, 명, 사람, 마리, 살, 시). La hora mezcla: 3시 30분 = nativo 3 (세 시) + sino 30 (삼십 분).\n\nLos nativos 1–4 y 20 se acortan antes de un contador: 하나 → 한, 둘 → 두, 셋 → 세, 넷 → 네, 스물 → 스무 (한 개, 두 명, 세 시, 스무 살). Los nativos llegan a 99 en uso cotidiano; de 100 en adelante el coreano usa sino-coreano incluso para objetos (책 백 권 "100 libros" usa el sino 백). Tranquilo si no te sale al principio — equivocar el sistema es el error más perdonable y los coreanos te entienden igual.',
      'Le coréen possède DEUX systèmes de nombres complets et il faut choisir le bon. Le sino-coréen (일, 이, 삼, 사, 오, 육, 칠, 팔, 구, 십...) s\'emploie pour les prix, dates, numéros de téléphone, mathématiques, années, grands nombres, minutes, secondes, ainsi que pour les classificateurs d\'origine chinoise (월/月, 분/分, 초/秒, 번/番). Le natif (하나, 둘, 셋, 넷, 다섯, 여섯, 일곱, 여덟, 아홉, 열...) sert à compter des objets visibles, l\'âge, les heures de l\'horloge et la plupart des classificateurs autochtones (개, 명, 사람, 마리, 살, 시). L\'heure les combine : 3시 30분 = natif 3 (세 시) + sino 30 (삼십 분).\n\nLes nombres natifs 1–4 et 20 s\'abrègent devant un classificateur : 하나 → 한, 둘 → 두, 셋 → 세, 넷 → 네, 스물 → 스무 (한 개, 두 명, 세 시, 스무 살). Les natifs ne montent qu\'à 99 dans l\'usage courant ; à partir de 100, le coréen passe au sino-coréen même pour les objets (책 백 권 « 100 livres » emploie le sino 백). Pas de panique si tu te trompes au début — choisir le mauvais système est l\'erreur la plus excusable et tout le monde comprendra.',
      'Coreano tem DOIS sistemas de números completos e você precisa escolher o certo. Sino-coreano (일, 이, 삼, 사, 오, 육, 칠, 팔, 구, 십...) é para preços, datas, números de telefone, matemática, tudo relacionado a ano, números grandes, minutos, segundos e contadores emprestados do chinês (월/月, 분/分, 초/秒, 번/番). O nativo (하나, 둘, 셋, 넷, 다섯, 여섯, 일곱, 여덟, 아홉, 열...) é para contar coisas visíveis, idade, horas do relógio e a maioria dos contadores autóctones (개, 명, 사람, 마리, 살, 시). A hora mistura: 3시 30분 = nativo 3 (세 시) + sino 30 (삼십 분).\n\nNativos 1–4 e 20 encurtam antes de um contador: 하나 → 한, 둘 → 두, 셋 → 세, 넷 → 네, 스물 → 스무 (한 개, 두 명, 세 시, 스무 살). Os nativos vão até 99 no uso diário; a partir de 100, o coreano usa sino-coreano mesmo para objetos (책 백 권 "100 livros" usa o sino 백). Tranquilo se errar no início — escolher o sistema errado é o erro mais perdoável e os coreanos vão entender.',
      'เกาหลีมีระบบตัวเลขที่ "สมบูรณ์ทั้งคู่" สองระบบ และต้องเลือกใช้ให้ถูก. ตัวเลขจีน-เกาหลี (일, 이, 삼, 사, 오, 육, 칠, 팔, 구, 십...) ใช้กับราคา วันที่ เบอร์โทร คณิตศาสตร์ เรื่องปี ตัวเลขใหญ่ นาที วินาที และตัวจำแนกที่ยืมมาจากจีน (월/月, 분/分, 초/秒, 번/番). ตัวเลขเกาหลีแท้ (하나, 둘, 셋, 넷, 다섯, 여섯, 일곱, 여덟, 아홉, 열...) ใช้นับสิ่งของที่มองเห็น อายุ ชั่วโมงบนนาฬิกา และตัวจำแนกพื้นเมืองส่วนใหญ่ (개, 명, 사람, 마리, 살, 시). บอกเวลาผสมสองระบบ: 3시 30분 = แท้ 3 (세 시) + จีน 30 (삼십 분)\n\nเลขแท้ 1–4 และ 20 จะหดก่อนตัวจำแนก: 하나 → 한, 둘 → 두, 셋 → 세, 넷 → 네, 스물 → 스무 (한 개, 두 명, 세 시, 스무 살). เลขแท้ใช้ในชีวิตประจำวันถึง 99 พ้นจาก 100 ขึ้นไปแม้นับสิ่งของก็ใช้จีน-เกาหลี (책 백 권 "หนังสือ 100 เล่ม" ใช้ 백). อย่ากดดันตัวเองให้สมบูรณ์ตั้งแต่แรก — เลือกผิดระบบเป็นข้อผิดพลาดที่ให้อภัยง่ายที่สุด คนเกาหลีเข้าใจอยู่แล้ว',
      'Bahasa Korea punya DUA sistem angka utuh dan kamu harus pilih yang tepat. Sino-Korea (일, 이, 삼, 사, 오, 육, 칠, 팔, 구, 십...) untuk harga, tanggal, nomor telepon, matematika, segala soal tahun, angka besar, menit, detik, dan klasifikator yang dipinjam dari Cina (월/月, 분/分, 초/秒, 번/番). Asli Korea (하나, 둘, 셋, 넷, 다섯, 여섯, 일곱, 여덟, 아홉, 열...) untuk menghitung benda yang terlihat, usia, jam pada arloji, dan kebanyakan klasifikator pribumi (개, 명, 사람, 마리, 살, 시). Waktu mencampur keduanya: 3시 30분 = asli 3 (세 시) + Sino 30 (삼십 분).\n\nAngka asli 1–4 dan 20 memendek sebelum klasifikator: 하나 → 한, 둘 → 두, 셋 → 세, 넷 → 네, 스물 → 스무 (한 개, 두 명, 세 시, 스무 살). Angka asli hanya sampai 99 dalam pemakaian sehari-hari; dari 100 ke atas Korea pakai Sino-Korea bahkan untuk benda (책 백 권 "100 buku" pakai Sino 백). Jangan terlalu cemas di awal — salah pilih sistem adalah kesalahan paling dimaklumi dan orang Korea akan tetap mengerti.',
      'Tiếng Hàn có HAI hệ số đầy đủ và bạn phải chọn đúng. Hán-Hàn (일, 이, 삼, 사, 오, 육, 칠, 팔, 구, 십...) dùng cho giá cả, ngày tháng, số điện thoại, toán, mọi thứ liên quan đến năm, số lớn, phút, giây, và các loại từ vay từ Hán (월/月, 분/分, 초/秒, 번/番). Thuần Hàn (하나, 둘, 셋, 넷, 다섯, 여섯, 일곱, 여덟, 아홉, 열...) dùng để đếm đồ vật, tuổi, giờ trên đồng hồ, và hầu hết các loại từ bản địa (개, 명, 사람, 마리, 살, 시). Giờ thì pha trộn: 3시 30분 = thuần 3 (세 시) + Hán 30 (삼십 분).\n\nThuần Hàn 1–4 và 20 rút gọn trước loại từ: 하나 → 한, 둘 → 두, 셋 → 세, 넷 → 네, 스물 → 스무 (한 개, 두 명, 세 시, 스무 살). Thuần Hàn chỉ dùng tới 99 trong sinh hoạt thường ngày; từ 100 trở lên tiếng Hàn chuyển sang Hán-Hàn ngay cả khi đếm vật (책 백 권 "100 quyển sách" dùng 백 Hán-Hàn). Đừng quá lo lúc mới học — chọn nhầm hệ là lỗi dễ tha thứ nhất và người Hàn vẫn hiểu.',
      '韓国語には数体系が二つあり、用途で使い分ける必要がある。漢字語数(일, 이, 삼, 사, 오, 육, 칠, 팔, 구, 십...)は値段・日付・電話番号・数学・年号関連・大きな数・分・秒、漢字語起源の助数詞(월/月、분/分、초/秒、번/番)に使う。固有語数(하나, 둘, 셋, 넷, 다섯, 여섯, 일곱, 여덟, 아홉, 열...)は目に見える物の数え、年齢、時刻の「時」、固有の助数詞(개、명、사람、마리、살、시)に使う。時刻は両方を混ぜる: 3시 30분 = 固有語の3(세 시)+ 漢字語の30(삼십 분)。\n\n固有語の1〜4と20は助数詞の前で短くなる: 하나 → 한、둘 → 두、셋 → 세、넷 → 네、스물 → 스무(한 개、두 명、세 시、스무 살)。固有語は日常では99までで、100以上は物の数え方でも漢字語に切り替わる(책 백 권「本100冊」は 백 を使う)。最初から完璧でなくて大丈夫 — 体系を間違えるのは最も許される初心者ミスで、相手は普通に理解してくれる。',
    ),
  '시간 표현': L(
      'Core time adverbs to memorize as a set: 어제 ("yesterday"), 오늘 ("today"), 내일 ("tomorrow"), 모레 ("day after tomorrow"), 지금 ("now"), 아까 ("a little while ago"), 이따가 ("a little later"), 항상 / 늘 ("always"), 가끔 / 자주 ("sometimes / often"), 보통 ("usually"), 매일 ("every day"). Days of the week: 월/화/수/목/금/토/일요일. Most time adverbs go BEFORE the verb but order is flexible — what matters is the time word comes earlier in the sentence than the verb.\n\nA quirk to remember: most simple time words like 오늘, 어제, 내일, 지금 DROP the particle even when they\'d logically be the time of an event (오늘 만나요, not 오늘에 만나요). But specific time points keep their particle: 3시에 (at 3), 월요일에 (on Monday), 2026년에 (in 2026). For frequency adverbs, no particle needed — they slot in next to the verb (매일 운동해요, 가끔 영화 봐요).',
      'Adverbios de tiempo a memorizar como conjunto: 어제 ("ayer"), 오늘 ("hoy"), 내일 ("mañana"), 모레 ("pasado mañana"), 지금 ("ahora"), 아까 ("hace un ratito"), 이따가 ("dentro de un rato"), 항상 / 늘 ("siempre"), 가끔 / 자주 ("a veces / seguido"), 보통 ("normalmente"), 매일 ("todos los días"). Días de la semana: 월/화/수/목/금/토/일요일. La mayoría van ANTES del verbo pero el orden es flexible — lo importante es que el adverbio temporal venga antes del verbo.\n\nDetalle a recordar: la mayoría de palabras simples como 오늘, 어제, 내일, 지금 NO llevan partícula aunque lógicamente serían el momento del evento (오늘 만나요, no 오늘에 만나요). Pero los puntos temporales concretos sí la llevan: 3시에 (a las 3), 월요일에 (el lunes), 2026년에 (en 2026). Para adverbios de frecuencia no hace falta partícula — se encajan al lado del verbo (매일 운동해요, 가끔 영화 봐요).',
      'Adverbes de temps à mémoriser en bloc : 어제 (« hier »), 오늘 (« aujourd\'hui »), 내일 (« demain »), 모레 (« après-demain »), 지금 (« maintenant »), 아까 (« il y a un instant »), 이따가 (« dans un moment »), 항상 / 늘 (« toujours »), 가끔 / 자주 (« parfois / souvent »), 보통 (« d\'habitude »), 매일 (« tous les jours »). Jours de la semaine : 월/화/수/목/금/토/일요일. La plupart se placent AVANT le verbe, mais l\'ordre reste souple — l\'essentiel est que l\'adverbe de temps précède le verbe.\n\nPoint à retenir : la majorité des mots simples comme 오늘, 어제, 내일, 지금 SE PASSENT DE PARTICULE même quand ils servent logiquement de moment de l\'événement (오늘 만나요, et non 오늘에 만나요). Mais les points temporels précis gardent la particule : 3시에 (à 3 h), 월요일에 (le lundi), 2026년에 (en 2026). Les adverbes de fréquence n\'en ont pas besoin — ils se glissent à côté du verbe (매일 운동해요, 가끔 영화 봐요).',
      'Advérbios de tempo para decorar em bloco: 어제 ("ontem"), 오늘 ("hoje"), 내일 ("amanhã"), 모레 ("depois de amanhã"), 지금 ("agora"), 아까 ("há pouco"), 이따가 ("daqui a pouco"), 항상 / 늘 ("sempre"), 가끔 / 자주 ("às vezes / com frequência"), 보통 ("normalmente"), 매일 ("todo dia"). Dias da semana: 월/화/수/목/금/토/일요일. A maioria vai ANTES do verbo mas a ordem é flexível — o importante é que o advérbio venha antes do verbo.\n\nDetalhe a lembrar: a maioria de palavras simples como 오늘, 어제, 내일, 지금 NÃO leva partícula mesmo quando seria o momento do evento (오늘 만나요, não 오늘에 만나요). Mas pontos temporais específicos mantêm a partícula: 3시에 (às 3), 월요일에 (na segunda), 2026년에 (em 2026). Para advérbios de frequência não precisa partícula — encaixam ao lado do verbo (매일 운동해요, 가끔 영화 봐요).',
      'คำบอกเวลาที่ควรท่องเป็นชุด: 어제 ("เมื่อวาน"), 오늘 ("วันนี้"), 내일 ("พรุ่งนี้"), 모레 ("มะรืน"), 지금 ("ตอนนี้"), 아까 ("เมื่อกี้"), 이따가 ("เดี๋ยว"), 항상 / 늘 ("เสมอ"), 가끔 / 자주 ("บางครั้ง / บ่อย"), 보통 ("ปกติ"), 매일 ("ทุกวัน"). วันในสัปดาห์: 월/화/수/목/금/토/일요일. ส่วนใหญ่วาง "ก่อน" กริยา แต่ลำดับยืดหยุ่นได้ — ที่สำคัญคือคำบอกเวลามาก่อนกริยา\n\nจุดที่ต้องจำ: คำเวลาธรรมดาส่วนใหญ่อย่าง 오늘, 어제, 내일, 지금 "ไม่ใส่อนุภาค" แม้ว่าจะเป็นเวลาของเหตุการณ์ (오늘 만나요 ไม่ใช่ 오늘에 만나요). แต่จุดเวลาที่ระบุเจาะจงจะใส่อนุภาค: 3시에 (สามโมง), 월요일에 (วันจันทร์), 2026년에 (ปี 2026). คำบอกความถี่ไม่ต้องใส่อนุภาค — วางข้างกริยาได้เลย (매일 운동해요, 가끔 영화 봐요)',
      'Kata waktu inti yang sebaiknya dihapal sekaligus: 어제 ("kemarin"), 오늘 ("hari ini"), 내일 ("besok"), 모레 ("lusa"), 지금 ("sekarang"), 아까 ("tadi"), 이따가 ("nanti sebentar"), 항상 / 늘 ("selalu"), 가끔 / 자주 ("kadang / sering"), 보통 ("biasanya"), 매일 ("setiap hari"). Hari dalam minggu: 월/화/수/목/금/토/일요일. Sebagian besar ditempatkan SEBELUM verba, tapi urutan fleksibel — yang penting kata waktu muncul lebih dulu daripada verba.\n\nHal yang perlu diingat: kata waktu sederhana seperti 오늘, 어제, 내일, 지금 TIDAK pakai partikel meskipun secara logis adalah waktu kejadian (오늘 만나요, bukan 오늘에 만나요). Tapi titik waktu spesifik tetap pakai partikel: 3시에 (jam 3), 월요일에 (hari Senin), 2026년에 (tahun 2026). Untuk adverbia frekuensi tidak butuh partikel — langsung disisipkan dekat verba (매일 운동해요, 가끔 영화 봐요).',
      'Trạng từ thời gian cốt lõi nên thuộc cả cụm: 어제 ("hôm qua"), 오늘 ("hôm nay"), 내일 ("ngày mai"), 모레 ("ngày kia"), 지금 ("bây giờ"), 아까 ("lúc nãy"), 이따가 ("lát nữa"), 항상 / 늘 ("luôn"), 가끔 / 자주 ("thỉnh thoảng / thường"), 보통 ("thường"), 매일 ("mỗi ngày"). Thứ trong tuần: 월/화/수/목/금/토/일요일. Đa số đặt TRƯỚC động từ nhưng trật tự linh hoạt — miễn là trạng từ thời gian đứng trước động từ.\n\nĐiểm cần nhớ: hầu hết từ thời gian đơn giản như 오늘, 어제, 내일, 지금 KHÔNG dùng tiểu từ dù về logic là thời điểm xảy ra (오늘 만나요, không phải 오늘에 만나요). Nhưng các thời điểm cụ thể vẫn giữ tiểu từ: 3시에 (3 giờ), 월요일에 (thứ Hai), 2026년에 (năm 2026). Với trạng từ tần suất không cần tiểu từ — chèn ngay cạnh động từ (매일 운동해요, 가끔 영화 봐요).',
      'まとめて覚えておきたい時の副詞: 어제(「昨日」)、오늘(「今日」)、내일(「明日」)、모레(「明後日」)、지금(「今」)、아까(「さっき」)、이따가(「あとで」)、항상 / 늘(「いつも」)、가끔 / 자주(「たまに／よく」)、보통(「ふつう」)、매일(「毎日」)。曜日: 월/화/수/목/금/토/일요일。ほとんどは動詞の「前」に置くが、語順は柔軟 — 大事なのは時を表す語が動詞より先に来ること。\n\n覚えておきたい癖: 오늘、어제、내일、지금 のような単純な時の語は、論理的には出来事の時を示していても「助詞を取らない」(오늘 만나요、오늘에 만나요 とは言わない)。一方、具体的な時点には助詞を残す: 3시에(3時に)、월요일에(月曜に)、2026년에(2026年に)。頻度副詞も助詞不要で、動詞の隣に置くだけでよい(매일 운동해요、가끔 영화 봐요)。',
    ),
  '이 / 그 / 저': L(
      'Three-way demonstrative system based on distance to the speakers, not just two like English. 이 = near the speaker ("this"), 그 = near the listener OR already mentioned in conversation ("that / that we just talked about"), 저 = far from both ("that one over there"). They go BEFORE a noun (이 책, 그 사람, 저 건물) and form pronouns: 이거 / 그거 / 저거 (casual "this / that / that over there", contracted from 이것 / 그것 / 저것).\n\nThe 그 = "the one we just mentioned" use is huge in conversation — when someone says "the friend I told you about", in Korean it\'s 그 친구. Place words come from the same set: 여기 ("here"), 거기 ("there, near listener / the place mentioned"), 저기 ("over there"). For "this / that one" referring to a person politely, use 이분 / 그분 / 저분 ("this/that person", honorific). Quick test for 이 vs 그: if the listener can see or touch it, 이; if you\'re both thinking of it but it\'s not physically here, 그.',
      'Sistema de demostrativos en TRES grados según la distancia al hablante y al oyente, no en dos como el español. 이 = cerca del hablante ("este"), 그 = cerca del oyente O ya mencionado en la conversación ("ese / aquel del que hablamos"), 저 = lejos de ambos ("aquel allá"). Van ANTES del sustantivo (이 책, 그 사람, 저 건물) y forman pronombres: 이거 / 그거 / 저거 (informales "esto / eso / aquello", contraídos de 이것 / 그것 / 저것).\n\nEl uso de 그 = "el que ya mencionamos" es enorme en conversación — cuando alguien dice "el amigo del que te hablé", en coreano es 그 친구. Los lugares siguen la misma serie: 여기 ("acá"), 거기 ("ahí, cerca del oyente / el lugar mencionado"), 저기 ("allá lejos"). Para "este/ese" referido a una persona con respeto, usá 이분 / 그분 / 저분 (honorífico). Test rápido entre 이 y 그: si el oyente lo ve o lo puede tocar, 이; si los dos lo están pensando pero no está acá, 그.',
      'Système démonstratif à TROIS niveaux basé sur la distance vis-à-vis du locuteur et de l\'interlocuteur, pas seulement à deux comme en français. 이 = près du locuteur (« ce / cette ... -ci »), 그 = près de l\'interlocuteur OU déjà mentionné dans la conversation (« ce / cette ... dont on a parlé »), 저 = loin des deux (« ce / cette ... -là, là-bas »). Ils précèdent le nom (이 책, 그 사람, 저 건물) et forment des pronoms : 이거 / 그거 / 저거 (familier « ceci / cela / cela là-bas », contraction de 이것 / 그것 / 저것).\n\nL\'emploi de 그 = « celui dont on vient de parler » est omniprésent — quand quelqu\'un dit « l\'ami dont je t\'ai parlé », en coréen c\'est 그 친구. Les noms de lieu suivent la même série : 여기 (« ici »), 거기 (« là, près de l\'interlocuteur / le lieu mentionné »), 저기 (« là-bas »). Pour une personne avec respect : 이분 / 그분 / 저분 (honorifique). Test rapide pour 이 vs 그 : si l\'interlocuteur peut voir / toucher, c\'est 이 ; si vous y pensez tous les deux mais ce n\'est pas devant vous, c\'est 그.',
      'Sistema de demonstrativos com TRÊS níveis baseado na distância para falante e ouvinte, não só dois como em português. 이 = perto do falante ("este"), 그 = perto do ouvinte OU já mencionado na conversa ("esse / aquele de que falamos"), 저 = longe de ambos ("aquele lá"). Vão ANTES do substantivo (이 책, 그 사람, 저 건물) e formam pronomes: 이거 / 그거 / 저거 (informais "isto / isso / aquilo", contrações de 이것 / 그것 / 저것).\n\nO uso de 그 = "o que acabamos de mencionar" é enorme em conversa — quando alguém diz "o amigo de que te falei", em coreano é 그 친구. Os lugares seguem a mesma série: 여기 ("aqui"), 거기 ("aí, perto do ouvinte / o lugar mencionado"), 저기 ("lá"). Para "este/esse" referido a uma pessoa com respeito, use 이분 / 그분 / 저분 (honorífico). Teste rápido entre 이 e 그: se o ouvinte vê ou pode tocar, 이; se os dois estão pensando mas não está aqui, 그.',
      'ระบบคำชี้สามขั้นตามระยะห่างจากผู้พูดและผู้ฟัง ไม่ใช่สองขั้นแบบภาษาไทย. 이 = ใกล้ผู้พูด ("นี้"), 그 = ใกล้ผู้ฟัง หรือสิ่งที่กล่าวถึงไปแล้วในบทสนทนา ("นั้น / ที่พูดถึง"), 저 = ไกลทั้งคู่ ("โน้น"). วาง "ก่อน" คำนาม (이 책, 그 사람, 저 건물) และมีรูปสรรพนาม: 이거 / 그거 / 저거 (รูปกันเอง "อันนี้ / อันนั้น / อันโน้น" หดมาจาก 이것 / 그것 / 저것)\n\nการใช้ 그 = "อันที่เพิ่งพูดถึง" สำคัญมากในบทสนทนา — เวลาคนพูดว่า "เพื่อนคนที่ฉันเล่าให้ฟัง" ภาษาเกาหลีคือ 그 친구. คำสถานที่อยู่ในชุดเดียวกัน: 여기 ("ที่นี่"), 거기 ("ที่นั่น ใกล้ผู้ฟัง / ที่ที่พูดถึง"), 저기 ("ที่โน่น"). หากชี้ตัวคนแบบยกย่อง ใช้ 이분 / 그분 / 저분 (รูปยกย่อง). เทคนิคแยก 이 กับ 그: ถ้าผู้ฟังเห็นหรือจับได้ใช้ 이; ถ้าทั้งคู่กำลังนึกถึงแต่ไม่อยู่ตรงนี้ใช้ 그',
      'Sistem demonstratif TIGA tingkat berdasarkan jarak ke penutur dan lawan bicara, bukan dua tingkat seperti bahasa Indonesia. 이 = dekat penutur ("ini"), 그 = dekat lawan bicara ATAU sudah disebut sebelumnya ("itu / yang tadi dibicarakan"), 저 = jauh dari keduanya ("itu di sana"). Diletakkan SEBELUM kata benda (이 책, 그 사람, 저 건물) dan membentuk kata ganti: 이거 / 그거 / 저거 (informal "ini / itu / itu di sana", kerutan dari 이것 / 그것 / 저것).\n\nPenggunaan 그 = "yang baru saja disebut" sangat sering muncul dalam percakapan — saat seseorang bilang "teman yang aku ceritakan tadi", dalam bahasa Korea jadi 그 친구. Kata tempat memakai seri yang sama: 여기 ("di sini"), 거기 ("di sana, dekat lawan bicara / tempat yang disebut"), 저기 ("di sana jauh"). Untuk menyebut orang dengan hormat, pakai 이분 / 그분 / 저분 (honorifik). Tes cepat antara 이 dan 그: kalau lawan bicara bisa melihat atau menyentuh, pakai 이; kalau kalian berdua memikirkannya tapi tidak ada di sini, pakai 그.',
      'Hệ chỉ định BA cấp dựa vào khoảng cách với người nói và người nghe, không phải hai cấp như tiếng Việt. 이 = gần người nói ("này"), 그 = gần người nghe HOẶC đã được nhắc đến trong hội thoại ("đó / cái đã nói"), 저 = xa cả hai ("kia"). Đặt TRƯỚC danh từ (이 책, 그 사람, 저 건물) và tạo đại từ: 이거 / 그거 / 저거 (thân mật "cái này / cái đó / cái kia", rút gọn từ 이것 / 그것 / 저것).\n\nDùng 그 = "cái vừa nhắc tới" cực kỳ phổ biến trong hội thoại — khi ai đó nói "người bạn mà tôi đã kể", tiếng Hàn là 그 친구. Từ chỉ nơi chốn cùng hệ: 여기 ("ở đây"), 거기 ("ở đó, gần người nghe / nơi đã nhắc"), 저기 ("ở kia"). Khi chỉ một người với sự tôn trọng, dùng 이분 / 그분 / 저분 (kính ngữ). Mẹo phân biệt 이 và 그: nếu người nghe có thể thấy hoặc chạm, dùng 이; nếu cả hai cùng nghĩ tới nhưng không có ở đây, dùng 그.',
      '韓国語の指示語は話し手・聞き手からの距離に基づく「3段階」(日本語のコ・ソ・アと同じ)。이 = 話し手の近く(「この」)、그 = 聞き手の近く、または会話で既に話題に出たもの(「その／さっき話したあの」)、저 = 双方から遠い(「あの・あそこの」)。名詞の前に置き(이 책、그 사람、저 건물)、代名詞形は 이거 / 그거 / 저거(口語「これ／それ／あれ」、이것 / 그것 / 저것 の縮約)。\n\n그 を「さっき話したあれ」の意味で使うのは会話で非常に多い — 「前に話した友達」と言うとき韓国語は 그 친구。場所表現も同じ系列: 여기「ここ」、거기「そこ・聞き手の近く・話に出た場所」、저기「あそこ」。人を敬意を込めて指すなら 이분 / 그분 / 저분(尊敬形)。이 と 그 の簡単な見分け: 聞き手が見えたり触れたりできるなら 이、両者が頭の中で共有しているが目の前にないなら 그。',
    ),
  '위치어 (위 / 아래 / 앞 / 뒤 / 옆 …)': L(
      'Where English uses prepositions ("on, under, in"), Korean uses location NOUNS placed AFTER the reference noun: 가방 위 ("bag-top" = on top of the bag), 책상 아래 ("desk-bottom" = under the desk), 집 앞 ("house-front" = in front of the house), 의자 뒤 ("chair-back"), 학교 옆 ("school-side"), 가방 안 ("bag-inside"), 학교 밖 ("school-outside"), 학생들 사이 ("students-between"), 학교 근처 ("school-vicinity"). The word order is reversed from English.\n\nAttach 에 for state ("there IS something at...": 가방 안에 책이 있어요 "there\'s a book in the bag") or 에서 for action ("an action HAPPENS at...": 가방 안에서 책을 꺼내요 "I take a book out of the bag"). For more precision you can use 의: 가방의 안 ("the inside OF the bag"), though native speakers usually drop the 의. Don\'t add 에 directly to the reference noun — it has to go on the location word: ✓ 가방 안에, ✗ 가방에 안.',
      'Donde el español usa preposiciones ("encima, debajo, en"), el coreano usa SUSTANTIVOS de ubicación colocados DESPUÉS del sustantivo de referencia: 가방 위 ("encima de la mochila"), 책상 아래 ("debajo del escritorio"), 집 앞 ("delante de la casa"), 의자 뒤 ("detrás de la silla"), 학교 옆 ("al lado de la escuela"), 가방 안 ("dentro de la mochila"), 학교 밖 ("fuera de la escuela"), 학생들 사이 ("entre los estudiantes"), 학교 근처 ("cerca de la escuela"). El orden es opuesto al español.\n\nAgregá 에 para estado ("hay algo en...": 가방 안에 책이 있어요) o 에서 para acción ("una acción ocurre en...": 가방 안에서 책을 꺼내요 "saco el libro de la mochila"). Si querés más precisión podés usar 의: 가방의 안 ("el interior DE la mochila"), aunque los nativos suelen omitir el 의. NO añadas 에 al sustantivo de referencia — va en la palabra de ubicación: ✓ 가방 안에, ✗ 가방에 안.',
      'Là où le français emploie des prépositions (« sur, sous, dans »), le coréen utilise des NOMS de lieu placés APRÈS le nom de référence : 가방 위 (« dessus du sac » = sur le sac), 책상 아래 (« dessous du bureau »), 집 앞 (« devant de la maison »), 의자 뒤 (« derrière de la chaise »), 학교 옆 (« côté de l\'école »), 가방 안 (« intérieur du sac »), 학교 밖 (« extérieur de l\'école »), 학생들 사이 (« entre les étudiants »), 학교 근처 (« près de l\'école »). L\'ordre est inverse du français.\n\nAjoute 에 pour l\'état (« il y a quelque chose à... » : 가방 안에 책이 있어요) ou 에서 pour l\'action (« une action a lieu à... » : 가방 안에서 책을 꺼내요 « je sors un livre du sac »). Pour plus de précision, on peut employer 의 : 가방의 안 (« l\'intérieur DU sac »), mais les natifs omettent souvent le 의. Ne mets pas 에 directement sur le nom de référence — il doit être sur le mot de lieu : ✓ 가방 안에, ✗ 가방에 안.',
      'Onde o português usa preposições ("em cima, embaixo, dentro"), o coreano usa SUBSTANTIVOS de localização colocados DEPOIS do substantivo de referência: 가방 위 ("em cima da mochila"), 책상 아래 ("embaixo da mesa"), 집 앞 ("na frente da casa"), 의자 뒤 ("atrás da cadeira"), 학교 옆 ("ao lado da escola"), 가방 안 ("dentro da mochila"), 학교 밖 ("fora da escola"), 학생들 사이 ("entre os estudantes"), 학교 근처 ("perto da escola"). A ordem é o oposto do português.\n\nAdicione 에 para estado ("há algo em...": 가방 안에 책이 있어요) ou 에서 para ação ("uma ação acontece em...": 가방 안에서 책을 꺼내요 "tiro o livro de dentro da mochila"). Se quiser mais precisão pode usar 의: 가방의 안 ("o interior DA mochila"), mas os nativos costumam omitir o 의. Não coloque 에 diretamente no substantivo de referência — vai na palavra de localização: ✓ 가방 안에, ✗ 가방에 안.',
      'ที่ภาษาอังกฤษใช้คำบุพบท ("on, under, in") ภาษาเกาหลีใช้ "คำนาม" บอกตำแหน่งวางไว้ "หลัง" คำนามอ้างอิง: 가방 위 ("ส่วนบนของกระเป๋า" = บนกระเป๋า), 책상 아래 ("ส่วนล่างของโต๊ะ" = ใต้โต๊ะ), 집 앞 ("ส่วนหน้าของบ้าน"), 의자 뒤 ("ส่วนหลังของเก้าอี้"), 학교 옆 ("ข้างโรงเรียน"), 가방 안 ("ข้างในกระเป๋า"), 학교 밖 ("ข้างนอกโรงเรียน"), 학생들 사이 ("ระหว่างนักเรียน"), 학교 근처 ("ใกล้โรงเรียน"). ลำดับสลับกับภาษาไทย/อังกฤษ\n\nเติม 에 ถ้าเป็นสภาพ ("มี ... ที่ ...": 가방 안에 책이 있어요) หรือ 에서 ถ้าเป็นการกระทำ ("ทำ ... ที่ ...": 가방 안에서 책을 꺼내요 "หยิบหนังสือออกจากในกระเป๋า"). ต้องการความแม่นยำขึ้นใช้ 의 ได้: 가방의 안 ("ข้างในของกระเป๋า") แม้คนพื้นเมืองจะตัด 의 ออก. อย่าใส่ 에 ที่คำนามอ้างอิงโดยตรง — ต้องใส่ที่คำตำแหน่ง: ✓ 가방 안에, ✗ 가방에 안',
      'Di mana bahasa Inggris pakai preposisi ("on, under, in"), bahasa Korea pakai KATA BENDA lokasi yang ditaruh SETELAH kata benda acuan: 가방 위 ("atas-tas" = di atas tas), 책상 아래 ("bawah-meja"), 집 앞 ("depan-rumah"), 의자 뒤 ("belakang-kursi"), 학교 옆 ("samping-sekolah"), 가방 안 ("dalam-tas"), 학교 밖 ("luar-sekolah"), 학생들 사이 ("antara-siswa"), 학교 근처 ("dekat-sekolah"). Urutannya kebalikan dari bahasa Inggris.\n\nTambahkan 에 untuk keadaan ("ada sesuatu di...": 가방 안에 책이 있어요) atau 에서 untuk aksi ("aksi terjadi di...": 가방 안에서 책을 꺼내요 "saya keluarkan buku dari dalam tas"). Untuk presisi tambahan bisa pakai 의: 가방의 안 ("bagian dalam DARI tas"), meskipun penutur asli biasanya melepas 의. Jangan tambahkan 에 langsung ke kata benda acuan — harus pada kata lokasi: ✓ 가방 안에, ✗ 가방에 안.',
      'Trong khi tiếng Anh dùng giới từ ("on, under, in"), tiếng Hàn dùng các DANH TỪ chỉ vị trí đặt SAU danh từ tham chiếu: 가방 위 ("trên-cặp" = trên cặp), 책상 아래 ("dưới-bàn"), 집 앞 ("trước-nhà"), 의자 뒤 ("sau-ghế"), 학교 옆 ("cạnh-trường"), 가방 안 ("trong-cặp"), 학교 밖 ("ngoài-trường"), 학생들 사이 ("giữa-các học sinh"), 학교 근처 ("gần-trường"). Thứ tự ngược với tiếng Anh.\n\nThêm 에 cho trạng thái ("có gì ở...": 가방 안에 책이 있어요) hoặc 에서 cho hành động ("hành động xảy ra ở...": 가방 안에서 책을 꺼내요 "tôi lấy sách ra khỏi cặp"). Muốn chính xác hơn có thể dùng 의: 가방의 안 ("phần bên trong CỦA cặp"), dù người bản ngữ thường bỏ 의. Đừng dán 에 trực tiếp vào danh từ tham chiếu — phải đặt trên từ chỉ vị trí: ✓ 가방 안에, ✗ 가방에 안.',
      '英語が前置詞「on/under/in」を使う場面で、韓国語は「位置名詞」を参照名詞の「後ろ」に置く: 가방 위「カバンの上」、책상 아래「机の下」、집 앞「家の前」、의자 뒤「椅子の後ろ」、학교 옆「学校の隣」、가방 안「カバンの中」、학교 밖「学校の外」、학생들 사이「学生たちの間」、학교 근처「学校の近く」。語順は英語の逆になる。\n\n状態(「〜にある」)には 에 を、動作の場所(「〜で〜する」)には 에서 を付ける: 가방 안에 책이 있어요「カバンの中に本がある」、가방 안에서 책을 꺼내요「カバンの中から本を取り出す」。厳密に言いたいときは 의 を間に入れられる(가방의 안「カバンの中」)が、ネイティブは省略するのが普通。참조名詞そのものに 에 を付けないこと — 位置名詞に付ける: ✓ 가방 안에、✗ 가방에 안。',
    ),
  '수 분류사 (개 / 명 / 권 / 잔 / 마리 …)': L(
      'Korean cannot say "two apples" without telling you HOW it counts apples. Counters (classifiers) sit between the noun and the number: 사과 두 개 ("apples two pieces"). Core counters to memorize: 개 ("generic / piece" for objects), 명 / 분 ("people", 분 is honorific), 마리 ("animals"), 권 ("books / volumes"), 잔 ("cups / glasses"), 병 ("bottles"), 장 ("flat sheets — paper, tickets"), 그릇 ("bowls of food"), 송이 ("flowers, bunches"), 켤레 ("pairs of shoes/socks"), 대 ("vehicles, machines"). Most pair with NATIVE Korean numbers.\n\nNative numbers 1–4 and 20 shorten before the counter: 한 개, 두 명, 세 마리, 네 권, 스무 살. After 100, Sino-Korean numbers take over even for objects (책 백 권 "100 books"). Sino-borrowed counters skip native numbers entirely and use Sino: 일 회 ("one time / round"), 이 인분 ("two servings"), 삼 분 ("three minutes"). When in doubt, 개 is the friendliest fallback — overusing it sounds slightly childish but you\'ll always be understood.',
      'El coreano no puede decir "dos manzanas" sin contarte CÓMO cuenta las manzanas. Los contadores van entre el sustantivo y el número: 사과 두 개 ("manzanas dos piezas"). Contadores básicos a memorizar: 개 ("genérico / unidad" para cosas), 명 / 분 ("personas", 분 es honorífico), 마리 ("animales"), 권 ("libros / volúmenes"), 잔 ("tazas / copas"), 병 ("botellas"), 장 ("hojas planas — papeles, tickets"), 그릇 ("tazones de comida"), 송이 ("flores, ramos"), 켤레 ("pares de zapatos/medias"), 대 ("vehículos, máquinas"). La mayoría se combinan con los NÚMEROS NATIVOS.\n\nLos nativos 1–4 y 20 se acortan delante del contador: 한 개, 두 명, 세 마리, 네 권, 스무 살. A partir de 100 el sino-coreano toma el relevo incluso para objetos (책 백 권 "100 libros"). Los contadores de origen chino saltan el sistema nativo y van con sino: 일 회 ("una vez"), 이 인분 ("dos porciones"), 삼 분 ("tres minutos"). Si tenés dudas, 개 es el salvavidas amistoso — abusarlo suena un poquito infantil pero te van a entender siempre.',
      'En coréen, on ne dit pas « deux pommes » sans préciser COMMENT on les compte. Les classificateurs se placent entre le nom et le nombre : 사과 두 개 (« pommes deux unités »). Classificateurs essentiels : 개 (« unité, pièce » pour des objets), 명 / 분 (« personnes », 분 est honorifique), 마리 (« animaux »), 권 (« livres / volumes »), 잔 (« tasses / verres »), 병 (« bouteilles »), 장 (« feuilles plates : papiers, tickets »), 그릇 (« bols de nourriture »), 송이 (« fleurs, bouquets »), 켤레 (« paires de chaussures/chaussettes »), 대 (« véhicules, machines »). La plupart vont avec les NOMBRES NATIFS.\n\nLes natifs 1–4 et 20 se raccourcissent devant le classificateur : 한 개, 두 명, 세 마리, 네 권, 스무 살. À partir de 100, le sino-coréen prend le relais même pour des objets (책 백 권 « 100 livres »). Les classificateurs empruntés au chinois sautent le système natif et prennent du sino : 일 회 (« une fois »), 이 인분 (« deux portions »), 삼 분 (« trois minutes »). Dans le doute, 개 est la bouée amicale — en abuser fait un peu enfantin, mais tu seras toujours compris.',
      'O coreano não consegue dizer "duas maçãs" sem dizer COMO conta as maçãs. Os contadores ficam entre o substantivo e o número: 사과 두 개 ("maçãs duas peças"). Contadores essenciais para decorar: 개 ("genérico / unidade" para objetos), 명 / 분 ("pessoas", 분 é honorífico), 마리 ("animais"), 권 ("livros / volumes"), 잔 ("xícaras / copos"), 병 ("garrafas"), 장 ("folhas planas — papéis, ingressos"), 그릇 ("tigelas de comida"), 송이 ("flores, buquês"), 켤레 ("pares de sapatos/meias"), 대 ("veículos, máquinas"). A maioria se combina com os NÚMEROS NATIVOS.\n\nOs nativos 1–4 e 20 encurtam antes do contador: 한 개, 두 명, 세 마리, 네 권, 스무 살. De 100 em diante o sino-coreano assume mesmo para objetos (책 백 권 "100 livros"). Contadores de origem chinesa pulam o sistema nativo e usam sino: 일 회 ("uma vez"), 이 인분 ("duas porções"), 삼 분 ("três minutos"). Na dúvida, 개 é o salva-vidas amigável — abusar dele soa um pouco infantil mas você sempre será entendido.',
      'ภาษาเกาหลีพูดว่า "แอปเปิ้ลสองลูก" ไม่ได้โดยไม่บอกว่านับยังไง. ลักษณนามอยู่ระหว่างคำนามกับตัวเลข: 사과 두 개 ("แอปเปิ้ล สอง ลูก"). ลักษณนามหลักที่ต้องท่อง: 개 ("อัน/ชิ้น" สำหรับสิ่งของทั่วไป), 명 / 분 ("คน", 분 เป็นรูปยกย่อง), 마리 ("ตัว" สำหรับสัตว์), 권 ("เล่ม" สำหรับหนังสือ), 잔 ("ถ้วย/แก้ว"), 병 ("ขวด"), 장 ("ใบ/แผ่น" กระดาษ/ตั๋ว), 그릇 ("ชาม" อาหาร), 송이 ("ช่อ" ดอกไม้), 켤레 ("คู่" รองเท้า/ถุงเท้า), 대 ("คัน" รถ/เครื่องจักร). ส่วนใหญ่ใช้ "ตัวเลขเกาหลีแท้"\n\nเลขแท้ 1–4 และ 20 หดก่อนลักษณนาม: 한 개, 두 명, 세 마리, 네 권, 스무 살. ตั้งแต่ 100 ขึ้นไป จีน-เกาหลีรับช่วงแม้กับสิ่งของ (책 백 권 "หนังสือ 100 เล่ม"). ลักษณนามรากจีนข้ามระบบเลขแท้และใช้จีนตรง: 일 회 ("หนึ่งครั้ง"), 이 인분 ("สองที่"), 삼 분 ("สามนาที"). ถ้าไม่แน่ใจ ใช้ 개 ปลอดภัยที่สุด — ใช้บ่อยเกินไปจะฟังเหมือนเด็ก แต่คนเกาหลีเข้าใจเสมอ',
      'Bahasa Korea tidak bisa berkata "dua apel" tanpa memberitahu BAGAIMANA cara menghitungnya. Penggolong duduk di antara kata benda dan angka: 사과 두 개 ("apel dua biji"). Penggolong inti yang harus dihafal: 개 ("biji / unit" untuk benda umum), 명 / 분 ("orang", 분 hormat), 마리 ("ekor"), 권 ("jilid / buku"), 잔 ("cangkir / gelas"), 병 ("botol"), 장 ("lembar"), 그릇 ("mangkuk makanan"), 송이 ("tangkai bunga"), 켤레 ("pasang sepatu/kaus kaki"), 대 ("unit kendaraan/mesin"). Sebagian besar berpasangan dengan ANGKA ASLI Korea.\n\nAngka asli 1–4 dan 20 memendek sebelum penggolong: 한 개, 두 명, 세 마리, 네 권, 스무 살. Mulai 100, Sino-Korea ambil alih bahkan untuk benda (책 백 권 "100 buku"). Penggolong yang dipinjam dari Cina sepenuhnya melewati angka asli dan pakai Sino: 일 회 ("satu kali"), 이 인분 ("dua porsi"), 삼 분 ("tiga menit"). Kalau ragu, 개 adalah pelampung paling ramah — kebanyakan dipakai akan terdengar agak kekanak-kanakan, tapi kamu selalu akan dimengerti.',
      'Tiếng Hàn không thể nói "hai quả táo" mà không cho biết ĐẾM CHÚNG NHƯ THẾ NÀO. Loại từ nằm giữa danh từ và số: 사과 두 개 ("táo hai cái"). Các loại từ cốt lõi cần thuộc: 개 ("cái / chiếc" cho vật thông dụng), 명 / 분 ("người", 분 kính ngữ), 마리 ("con" cho động vật), 권 ("quyển" cho sách), 잔 ("ly/tách"), 병 ("chai"), 장 ("tờ" giấy/vé), 그릇 ("bát" thức ăn), 송이 ("bó/bông" hoa), 켤레 ("đôi" giày/tất), 대 ("chiếc" xe/máy). Phần lớn đi cùng SỐ THUẦN HÀN.\n\nThuần Hàn 1–4 và 20 rút gọn trước loại từ: 한 개, 두 명, 세 마리, 네 권, 스무 살. Từ 100 trở lên, Hán-Hàn tiếp quản ngay cả khi đếm vật (책 백 권 "100 quyển sách"). Các loại từ gốc Hán bỏ qua hệ thuần Hàn và dùng Hán-Hàn: 일 회 ("một lần"), 이 인분 ("hai phần"), 삼 분 ("ba phút"). Nếu phân vân, 개 là phao cứu sinh thân thiện nhất — lạm dụng có thể nghe hơi trẻ con, nhưng người Hàn luôn hiểu.',
      '韓国語では「リンゴを二つ」とは言わず、必ず「どう数えるか」も明示する。助数詞は名詞と数の間に置く: 사과 두 개「リンゴ 二 つ」。覚えておきたい主要助数詞: 개(一般的な「個」)、명 / 분(「人」、분 は尊敬形)、마리(動物の「匹」)、권(本の「冊」)、잔(コップやカップの「杯」)、병(瓶の「本」)、장(平らな紙・チケット類の「枚」)、그릇(料理の「杯」)、송이(花の「房」)、켤레(靴・靴下の「足」)、대(車・機械の「台」)。基本的に「固有語数詞」と組み合わせる。\n\n固有語の1〜4と20は助数詞の前で短くなる: 한 개、두 명、세 마리、네 권、스무 살。100以降は物の数えでも漢字語に切り替わる(책 백 권「100冊」)。漢字由来の助数詞は固有語をスキップして漢字語と組む: 일 회(「1回」)、이 인분(「2人前」)、삼 분(「3分」)。迷ったら 개 で乗り切れる — 多用すると幼く聞こえるが、常に通じる。',
    ),
  '인사 표현': L(
      'Korean greetings come in pairs of who-stays vs who-leaves and casual vs formal. "Hello" is 안녕하세요 (polite, all-day) or 안녕 (casual, friend-only). Goodbye has TWO forms: 안녕히 가세요 ("go in peace") to the one leaving, 안녕히 계세요 ("stay in peace") to the one staying. Thank you: 감사합니다 (formal) / 고맙습니다 (warmer, equally formal) / 고마워요 (polite-casual) / 고마워 (friends). Sorry: 죄송합니다 (formal) / 미안해요 (polite-casual) / 미안해 (casual). Yes/No: 네 (formal yes) / 예 (also yes) / 응 / 어 (casual yes) / 아니요 (no).\n\nA few survival phrases that come up constantly. 잘 부탁드립니다 ("please take care of me / nice to meet you" in business). 수고하세요 / 수고하셨어요 ("good work" — say it when leaving the workplace or to staff). 잘 먹겠습니다 (before eating) and 잘 먹었습니다 (after eating). 잘 자요 (good night). 화이팅! / 파이팅! (encouragement, "you can do it!"). 어서 오세요 ("welcome", what staff say when you enter a shop). All of these have register cousins — start with the polite forms (-요 / -세요 / -습니다) and you\'ll never offend.',
      'Los saludos coreanos vienen en pares de quién-se-queda vs quién-se-va, y de formal vs informal. "Hola" es 안녕하세요 (educado, todo el día) o 안녕 (informal, solo con amigos). El adiós tiene DOS formas: 안녕히 가세요 ("andá en paz") al que se va, 안녕히 계세요 ("quedate en paz") al que se queda. Gracias: 감사합니다 (formal) / 고맙습니다 (cálido, igual de formal) / 고마워요 (educado-informal) / 고마워 (amigos). Perdón: 죄송합니다 (formal) / 미안해요 (educado-informal) / 미안해 (informal). Sí/No: 네 (sí formal) / 예 (también sí) / 응 / 어 (sí informal) / 아니요 (no).\n\nFrases de supervivencia que aparecen todo el tiempo: 잘 부탁드립니다 ("por favor, cuidame / mucho gusto" en negocios). 수고하세요 / 수고하셨어요 ("buen trabajo" — al salir del trabajo o al personal de un comercio). 잘 먹겠습니다 (antes de comer) y 잘 먹었습니다 (después). 잘 자요 (buenas noches). 화이팅! / 파이팅! (¡vamos!, ánimo). 어서 오세요 ("bienvenido", lo que dicen los empleados al entrar a una tienda). Todas tienen primos en distintos registros — arrancá con las educadas (-요 / -세요 / -습니다) y nunca vas a ofender.',
      'Les salutations coréennes se distribuent par paires (qui reste vs qui s\'en va) et par registres (familier vs formel). « Bonjour » : 안녕하세요 (poli, toute la journée) ou 안녕 (familier, entre amis). « Au revoir » a DEUX formes : 안녕히 가세요 (« va en paix ») à celui qui part, 안녕히 계세요 (« reste en paix ») à celui qui reste. Merci : 감사합니다 (formel) / 고맙습니다 (plus chaleureux, aussi formel) / 고마워요 (poli-familier) / 고마워 (entre amis). Désolé : 죄송합니다 (formel) / 미안해요 (poli-familier) / 미안해 (familier). Oui/Non : 네 (oui formel) / 예 (aussi oui) / 응 / 어 (oui familier) / 아니요 (non).\n\nQuelques expressions de survie omniprésentes : 잘 부탁드립니다 (« merci d\'avance, enchanté(e) » en contexte pro). 수고하세요 / 수고하셨어요 (« bon courage / bon travail » — en quittant le bureau ou au personnel). 잘 먹겠습니다 (avant de manger) et 잘 먹었습니다 (après). 잘 자요 (bonne nuit). 화이팅! / 파이팅! (encouragement, « tu vas y arriver ! »). 어서 오세요 (« bienvenue », ce que disent les employés à l\'entrée d\'un commerce). Toutes ont leurs cousines en différents registres — commence par les formes polies (-요 / -세요 / -습니다) et tu ne vexeras jamais personne.',
      'As saudações coreanas vêm em pares de quem-fica vs quem-vai e formal vs casual. "Olá" é 안녕하세요 (educado, o dia inteiro) ou 안녕 (casual, só com amigos). Adeus tem DUAS formas: 안녕히 가세요 ("vá em paz") para quem está saindo, 안녕히 계세요 ("fique em paz") para quem fica. Obrigado: 감사합니다 (formal) / 고맙습니다 (mais caloroso, igualmente formal) / 고마워요 (educado-casual) / 고마워 (amigos). Desculpa: 죄송합니다 (formal) / 미안해요 (educado-casual) / 미안해 (casual). Sim/Não: 네 (sim formal) / 예 (também sim) / 응 / 어 (sim casual) / 아니요 (não).\n\nFrases de sobrevivência que aparecem o tempo todo: 잘 부탁드립니다 ("por favor, cuide de mim / prazer em conhecer" em negócios). 수고하세요 / 수고하셨어요 ("bom trabalho" — ao sair do trabalho ou ao pessoal de uma loja). 잘 먹겠습니다 (antes de comer) e 잘 먹었습니다 (depois). 잘 자요 (boa noite). 화이팅! / 파이팅! (incentivo, "vamos lá!"). 어서 오세요 ("bem-vindo", o que os funcionários dizem ao entrar numa loja). Todas têm primas em registros diferentes — comece pelas formas educadas (-요 / -세요 / -습니다) e nunca vai ofender.',
      'คำทักทายภาษาเกาหลีจะมาเป็นคู่ ๆ ระหว่าง "คนที่อยู่" กับ "คนที่ไป" และระหว่าง "ทางการ" กับ "กันเอง". "สวัสดี" คือ 안녕하세요 (สุภาพ ใช้ได้ทั้งวัน) หรือ 안녕 (กันเอง สำหรับเพื่อน). คำลาก่อนมีสองรูป: 안녕히 가세요 ("ขอให้ไปดี") พูดกับคนที่จะจากไป, 안녕히 계세요 ("ขอให้อยู่ดี") พูดกับคนที่จะอยู่. ขอบคุณ: 감사합니다 (ทางการ) / 고맙습니다 (อบอุ่น ทางการเท่ากัน) / 고마워요 (สุภาพ-กันเอง) / 고마워 (เพื่อน). ขอโทษ: 죄송합니다 (ทางการ) / 미안해요 (สุภาพ-กันเอง) / 미안해 (กันเอง). ใช่/ไม่ใช่: 네 (ใช่ทางการ) / 예 (ใช่เช่นกัน) / 응 / 어 (ใช่กันเอง) / 아니요 (ไม่ใช่)\n\nวลีเอาตัวรอดที่เจอบ่อยมาก: 잘 부탁드립니다 ("ฝากเนื้อฝากตัวด้วย / ยินดีที่ได้รู้จัก" ในบริบทธุรกิจ). 수고하세요 / 수고하셨어요 ("ทำงานหนักนะ" — พูดเวลาออกจากที่ทำงานหรือกับพนักงาน). 잘 먹겠습니다 (ก่อนกิน) และ 잘 먹었습니다 (หลังกิน). 잘 자요 (ราตรีสวัสดิ์). 화이팅! / 파이팅! (ให้กำลังใจ "สู้ ๆ!"). 어서 오세요 ("ยินดีต้อนรับ" พนักงานพูดตอนคุณเข้าร้าน). ทุกตัวมีรูปในระดับต่าง ๆ — เริ่มจากรูปสุภาพ (-요 / -세요 / -습니다) ก็จะไม่มีวันเสียมารยาท',
      'Sapaan Korea hadir berpasangan: yang-tinggal vs yang-pergi, dan santai vs formal. "Halo" adalah 안녕하세요 (sopan, seharian) atau 안녕 (santai, hanya untuk teman). Selamat tinggal punya DUA bentuk: 안녕히 가세요 ("pergi dalam damai") kepada yang akan pergi, 안녕히 계세요 ("tinggal dalam damai") kepada yang tinggal. Terima kasih: 감사합니다 (formal) / 고맙습니다 (lebih hangat, sama formalnya) / 고마워요 (sopan-santai) / 고마워 (untuk teman). Maaf: 죄송합니다 (formal) / 미안해요 (sopan-santai) / 미안해 (santai). Ya/Tidak: 네 (ya formal) / 예 (juga ya) / 응 / 어 (ya santai) / 아니요 (tidak).\n\nFrasa bertahan hidup yang sangat sering muncul: 잘 부탁드립니다 ("mohon bimbingannya / senang berkenalan" dalam bisnis). 수고하세요 / 수고하셨어요 ("kerja yang bagus" — saat meninggalkan kantor atau ke staf). 잘 먹겠습니다 (sebelum makan) dan 잘 먹었습니다 (sesudah makan). 잘 자요 (selamat malam). 화이팅! / 파이팅! (semangat, "kamu bisa!"). 어서 오세요 ("selamat datang", yang dikatakan pegawai saat kamu masuk toko). Semuanya punya saudara di register berbeda — mulai dengan bentuk sopan (-요 / -세요 / -습니다) dan kamu tidak akan pernah menyinggung.',
      'Lời chào tiếng Hàn đi theo từng cặp người-ở vs người-đi và thân mật vs trang trọng. "Xin chào" là 안녕하세요 (lịch sự, suốt cả ngày) hoặc 안녕 (thân mật, chỉ với bạn). Tạm biệt có HAI dạng: 안녕히 가세요 ("đi bình an") với người ra đi, 안녕히 계세요 ("ở lại bình an") với người ở lại. Cảm ơn: 감사합니다 (trang trọng) / 고맙습니다 (ấm áp hơn, vẫn trang trọng) / 고마워요 (lịch sự-thân mật) / 고마워 (với bạn). Xin lỗi: 죄송합니다 (trang trọng) / 미안해요 (lịch sự-thân mật) / 미안해 (thân mật). Có/Không: 네 (vâng trang trọng) / 예 (cũng là vâng) / 응 / 어 (ừ thân mật) / 아니요 (không).\n\nNhững câu sinh tồn xuất hiện liên tục: 잘 부탁드립니다 ("rất mong được giúp đỡ / hân hạnh" trong công việc). 수고하세요 / 수고하셨어요 ("anh/chị vất vả rồi" — khi rời chỗ làm hoặc với nhân viên). 잘 먹겠습니다 (trước khi ăn) và 잘 먹었습니다 (sau khi ăn). 잘 자요 (chúc ngủ ngon). 화이팅! / 파이팅! (cổ vũ, "cố lên!"). 어서 오세요 ("hoan nghênh", câu nhân viên nói khi bạn bước vào cửa hàng). Tất cả đều có biến thể ở các cấp độ khác — bắt đầu bằng dạng lịch sự (-요 / -세요 / -습니다) thì bạn sẽ không bao giờ làm phật lòng ai.',
      '韓国語の挨拶は「残る人 vs 去る人」「カジュアル vs フォーマル」のペアでセットになっている。「こんにちは」は 안녕하세요(丁寧、終日使える)、안녕(친구同士のカジュアル)。「さようなら」は二種類: 안녕히 가세요「お元気で行ってください」(去る人に)、안녕히 계세요「お元気でいてください」(残る人に)。ありがとう: 감사합니다(フォーマル)/ 고맙습니다(温かみのある同等のフォーマル)/ 고마워요(丁寧カジュアル)/ 고마워(친구)。ごめんなさい: 죄송합니다(フォーマル)/ 미안해요(丁寧カジュアル)/ 미안해(친구)。はい/いいえ: 네(フォーマルなはい)/ 예(同じくはい)/ 응 / 어(カジュアルなはい)/ 아니요(いいえ)。\n\nよく出てくる「サバイバルフレーズ」: 잘 부탁드립니다(「よろしくお願いします」ビジネスでの初対面など)。수고하세요 / 수고하셨어요(「お疲れさまです」職場を出るとき、店員さんへ)。잘 먹겠습니다(食事の前)、잘 먹었습니다(食事の後)。잘 자요(おやすみ)。화이팅! / 파이팅!(「がんばれ!」)。어서 오세요(店に入るときに店員が言う「いらっしゃいませ」)。すべて違う丁寧度の親戚があるが、まずは丁寧形(-요 / -세요 / -습니다)で覚えれば誰にも失礼にならない。',
    ),
  '얼마나 걸려요?': L(
      '얼마나 = "how much / how many / how long" — a multipurpose intensity word. With 걸리다 ("take, of time") it forms the standard question for travel times: 얼마나 걸려요? "how long does it take?". The "from X to Y" framing uses 에서 ... 까지: 서울에서 부산까지 KTX로 얼마나 걸려요? "how long does it take from Seoul to Busan by KTX?". To answer, drop in a duration: 한 시간 (one hour, native), 삼십 분 (thirty minutes, sino-Korean), 두 시간 반 (two and a half hours).\n\nOther useful 얼마나 patterns: 얼마예요? (price, "how much does it cost?", using -이에요/예요), 얼마나 자주? ("how often?"), 얼마나 멀어요? ("how far?"), 얼마나 자요? ("how long do you sleep?"). Note that for prices you generally don\'t need the 나 — just 얼마예요? On signs you\'ll see 소요 시간 ("duration") at stations and 약 (approximately) before time estimates: 약 30분 소요. For a rough "around / about" answer use 한 + duration: 한 30분 ("about 30 minutes").',
      '얼마나 = "cuánto / cuántos / cuánto tiempo" — palabra de intensidad multipropósito. Con 걸리다 ("llevar, demorar tiempo") forma la pregunta estándar de viajes: 얼마나 걸려요? "¿cuánto tarda?". El "de X a Y" usa 에서 ... 까지: 서울에서 부산까지 KTX로 얼마나 걸려요? "¿cuánto se tarda de Seúl a Busan en KTX?". Para responder, metés una duración: 한 시간 (una hora, nativo), 삼십 분 (treinta minutos, sino-coreano), 두 시간 반 (dos horas y media).\n\nOtros patrones útiles con 얼마나: 얼마예요? (precio, "¿cuánto cuesta?", con -이에요/예요), 얼마나 자주? ("¿cada cuánto?"), 얼마나 멀어요? ("¿qué tan lejos?"), 얼마나 자요? ("¿cuánto dormís?"). Notá que para precios generalmente no hace falta el 나 — solo 얼마예요?. En carteles vas a ver 소요 시간 ("duración") en estaciones y 약 (aproximadamente) antes de estimaciones de tiempo: 약 30분 소요. Para una respuesta tipo "más o menos / como" usá 한 + duración: 한 30분 ("unos 30 minutos").',
      '얼마나 = « combien / combien de temps » — mot d\'intensité multifonction. Combiné à 걸리다 (« prendre, durer »), il forme la question standard sur les durées de trajet : 얼마나 걸려요? « combien de temps ça prend ? ». La structure « de X à Y » utilise 에서 ... 까지 : 서울에서 부산까지 KTX로 얼마나 걸려요? « combien de temps de Séoul à Busan en KTX ? ». Pour répondre, glisse une durée : 한 시간 (une heure, natif), 삼십 분 (trente minutes, sino-coréen), 두 시간 반 (deux heures et demie).\n\nAutres tournures utiles avec 얼마나 : 얼마예요? (prix, « ça coûte combien ? », avec -이에요/예요), 얼마나 자주? (« à quelle fréquence ? »), 얼마나 멀어요? (« c\'est à quelle distance ? »), 얼마나 자요? (« tu dors combien de temps ? »). Pour les prix, on n\'a en général pas besoin du 나 — simplement 얼마예요?. Sur les panneaux des gares, on lit 소요 시간 (« durée ») et 약 (« environ ») devant une estimation : 약 30분 소요. Pour une réponse approximative, utilise 한 + durée : 한 30분 (« environ 30 minutes »).',
      '얼마나 = "quanto / quantos / quanto tempo" — palavra de intensidade multiuso. Com 걸리다 ("levar, demorar tempo") forma a pergunta padrão de viagens: 얼마나 걸려요? "quanto tempo leva?". O "de X até Y" usa 에서 ... 까지: 서울에서 부산까지 KTX로 얼마나 걸려요? "quanto tempo leva de Seul a Busan de KTX?". Para responder, encaixe uma duração: 한 시간 (uma hora, nativo), 삼십 분 (trinta minutos, sino-coreano), 두 시간 반 (duas horas e meia).\n\nOutros padrões úteis com 얼마나: 얼마예요? (preço, "quanto custa?", com -이에요/예요), 얼마나 자주? ("com que frequência?"), 얼마나 멀어요? ("quão longe?"), 얼마나 자요? ("quanto tempo você dorme?"). Para preços geralmente não precisa do 나 — só 얼마예요?. Em placas você vai ver 소요 시간 ("duração") em estações e 약 (aproximadamente) antes de estimativas: 약 30분 소요. Para uma resposta tipo "uns / mais ou menos" use 한 + duração: 한 30분 ("uns 30 minutos").',
      '얼마나 = "เท่าไหร่ / นานแค่ไหน" — คำบอกความเข้มข้นที่ใช้ได้หลายแบบ. คู่กับ 걸리다 ("ใช้เวลา") กลายเป็นคำถามมาตรฐานเรื่องการเดินทาง: 얼마나 걸려요? "ใช้เวลาเท่าไหร่?". รูป "จาก X ถึง Y" ใช้ 에서 ... 까지: 서울에서 부산까지 KTX로 얼마나 걸려요? "จากโซลถึงปูซานนั่ง KTX ใช้เวลาเท่าไหร่?". ตอบโดยใส่ช่วงเวลา: 한 시간 (หนึ่งชั่วโมง รูปเกาหลีแท้), 삼십 분 (สามสิบนาที จีน-เกาหลี), 두 시간 반 (สองชั่วโมงครึ่ง)\n\n얼마나 ในบริบทอื่นที่มีประโยชน์: 얼마예요? (ราคา "เท่าไหร่?" ใช้ -이에요/예요), 얼마나 자주? ("บ่อยแค่ไหน?"), 얼마나 멀어요? ("ไกลแค่ไหน?"), 얼마나 자요? ("นอนนานเท่าไหร่?"). สำหรับราคามักไม่ต้องมี 나 — แค่ 얼마예요? พอ. ตามป้ายในสถานีจะเห็น 소요 시간 ("ระยะเวลา") และ 약 ("ประมาณ") นำหน้าเวลา: 약 30분 소요. ถ้าตอบแบบประมาณ ใช้ 한 + ช่วงเวลา: 한 30분 ("ประมาณ 30 นาที")',
      '얼마나 = "berapa / berapa lama" — kata intensitas serbaguna. Bersama 걸리다 ("memakan waktu") membentuk pertanyaan standar tentang durasi perjalanan: 얼마나 걸려요? "berapa lama?". Pola "dari X ke Y" memakai 에서 ... 까지: 서울에서 부산까지 KTX로 얼마나 걸려요? "berapa lama dari Seoul ke Busan naik KTX?". Untuk menjawab, masukkan durasi: 한 시간 (satu jam, asli), 삼십 분 (tiga puluh menit, Sino-Korea), 두 시간 반 (dua setengah jam).\n\nPola 얼마나 berguna lainnya: 얼마예요? (harga, "berapa harganya?", dengan -이에요/예요), 얼마나 자주? ("seberapa sering?"), 얼마나 멀어요? ("seberapa jauh?"), 얼마나 자요? ("berapa lama kamu tidur?"). Untuk harga umumnya tidak butuh 나 — cukup 얼마예요?. Di papan-papan kamu akan melihat 소요 시간 ("durasi") di stasiun dan 약 ("sekitar") sebelum estimasi waktu: 약 30분 소요. Untuk jawaban "sekitar / kira-kira" gunakan 한 + durasi: 한 30분 ("sekitar 30 menit").',
      '얼마나 = "bao nhiêu / bao lâu" — từ chỉ mức độ đa năng. Kết hợp với 걸리다 ("mất thời gian") tạo thành câu hỏi chuẩn về thời gian đi lại: 얼마나 걸려요? "mất bao lâu?". Cấu trúc "từ X đến Y" dùng 에서 ... 까지: 서울에서 부산까지 KTX로 얼마나 걸려요? "từ Seoul đến Busan đi KTX mất bao lâu?". Để trả lời, gắn vào một khoảng thời gian: 한 시간 (một tiếng, thuần Hàn), 삼십 분 (ba mươi phút, Hán-Hàn), 두 시간 반 (hai tiếng rưỡi).\n\nCác mẫu 얼마나 hữu ích khác: 얼마예요? (giá, "bao nhiêu tiền?", với -이에요/예요), 얼마나 자주? ("bao lâu một lần?"), 얼마나 멀어요? ("xa cỡ nào?"), 얼마나 자요? ("bạn ngủ bao lâu?"). Với giá thì thường không cần 나 — chỉ 얼마예요? là đủ. Trên các bảng ở ga bạn sẽ thấy 소요 시간 ("thời gian") và 약 ("khoảng") trước con số ước lượng: 약 30분 소요. Để trả lời ước lượng, dùng 한 + thời gian: 한 30분 ("khoảng 30 phút").',
      '얼마나 =「どれくらい／どのくらい」— 多用途の程度を尋ねる語。걸리다(「(時間が)かかる」)と組むと、移動時間の定番質問になる: 얼마나 걸려요?「どのくらいかかりますか?」。「XからYまで」は 에서 ... 까지 を使う: 서울에서 부산까지 KTX로 얼마나 걸려요?「ソウルから釜山までKTXでどのくらいかかりますか?」。返答には所要時間を入れる: 한 시간(1時間、固有語)、삼십 분(30分、漢字語)、두 시간 반(2時間半)。\n\nそのほか役立つ 얼마나 パターン: 얼마예요?(値段「いくらですか?」、-이에요/예요 と組む)、얼마나 자주?(「どのくらい頻繁に?」)、얼마나 멀어요?(「どのくらい遠い?」)、얼마나 자요?(「どのくらい眠りますか?」)。値段には 나 は普通付けない — 얼마예요? で十分。駅などの掲示には 소요 시간(「所要時間」)、推定時間の前に 약(「約」)が出る: 약 30분 소요。ざっくり答えるときは 한 + 所要時間: 한 30분(「30分くらい」)。',
    ),
  'N(이)랑 / 하고 + 같이 / 함께': L(
      'Korean "together with someone" combines two pieces: a companion particle attached to the person + the adverb 같이 or 함께 ("together") next to the verb. The particles are the same family you already know from "and / with": 와/과 (formal/written), 하고 (neutral spoken default), (이)랑 (casual, friend-to-friend). Stacked with 같이 or 함께 it becomes 친구하고 같이 / 친구랑 같이 / 친구와 함께 — all "together with a friend". 같이 is conversational; 함께 sounds slightly warmer or more literary.\n\nYou CAN drop the 같이 / 함께 — 친구하고 밥을 먹었어요 already implies "with a friend". Adding 같이 / 함께 makes the togetherness explicit, which is often what you want in invitations and offers (같이 갈래요? "want to go together?"). For three or more people, put the particle only between people, not after the last one: 친구하고 동생하고 같이 ("with a friend and a sibling"). For the honorific "with someone respected" use 함께 with 께/와 (선생님과 함께 / 어머니와 함께 sounds more formal than 어머니하고 같이).',
      'El coreano expresa "junto con alguien" combinando dos piezas: una partícula de compañía pegada a la persona + el adverbio 같이 o 함께 ("juntos") al lado del verbo. Las partículas son las que ya conocés de "y / con": 와/과 (formal/escrito), 하고 (neutro hablado), (이)랑 (informal entre amigos). Con 같이 o 함께 quedan: 친구하고 같이 / 친구랑 같이 / 친구와 함께 — "junto con un amigo". 같이 es conversacional; 함께 suena algo más cálido o literario.\n\nPodés OMITIR el 같이 / 함께 — 친구하고 밥을 먹었어요 ya implica "con un amigo". Agregar 같이 / 함께 vuelve explícita la idea de compañía, útil en invitaciones (같이 갈래요? "¿vamos juntos?"). Para tres o más personas, la partícula va solo entre ellas, no después de la última: 친구하고 동생하고 같이 ("con un amigo y mi hermano/a"). Para la versión honorífica "con alguien respetado", usá 함께 con 께/와 (선생님과 함께 / 어머니와 함께 suenan más formales que 어머니하고 같이).',
      'En coréen, « ensemble avec quelqu\'un » combine deux pièces : une particule de compagnie sur la personne + l\'adverbe 같이 ou 함께 (« ensemble ») près du verbe. Les particules sont la même famille que pour « et / avec » : 와/과 (formel / écrit), 하고 (neutre à l\'oral), (이)랑 (familier entre amis). Avec 같이 ou 함께 cela donne : 친구하고 같이 / 친구랑 같이 / 친구와 함께 — « avec un ami ». 같이 est conversationnel ; 함께 sonne un peu plus chaleureux ou littéraire.\n\nOn peut OMETTRE 같이 / 함께 — 친구하고 밥을 먹었어요 implique déjà « avec un ami ». Les ajouter rend la compagnie explicite, ce qui est souvent souhaité dans une invitation (같이 갈래요? « tu veux y aller avec moi ? »). Pour trois personnes ou plus, la particule ne se met qu\'entre elles, pas après la dernière : 친구하고 동생하고 같이 (« avec un ami et mon petit frère/ma petite sœur »). Pour la version honorifique « avec une personne qu\'on respecte », emploie 함께 avec 께/와 (선생님과 함께 / 어머니와 함께 sonnent plus formels que 어머니하고 같이).',
      'O coreano forma "junto com alguém" combinando duas peças: uma partícula de companhia anexada à pessoa + o advérbio 같이 ou 함께 ("juntos") perto do verbo. As partículas são da mesma família de "e / com": 와/과 (formal/escrita), 하고 (neutro falado), (이)랑 (casual entre amigos). Com 같이 ou 함께 fica: 친구하고 같이 / 친구랑 같이 / 친구와 함께 — "junto com um amigo". 같이 é conversacional; 함께 soa um pouco mais caloroso ou literário.\n\nVocê PODE omitir o 같이 / 함께 — 친구하고 밥을 먹었어요 já implica "com um amigo". Adicionar 같이 / 함께 deixa a ideia de companhia explícita, ótimo em convites (같이 갈래요? "vamos juntos?"). Para três ou mais pessoas, a partícula vai só entre elas, não depois da última: 친구하고 동생하고 같이 ("com um amigo e meu irmão/irmã"). Para a versão honorífica "com alguém respeitado", use 함께 com 께/와 (선생님과 함께 / 어머니와 함께 soam mais formais que 어머니하고 같이).',
      'ภาษาเกาหลีบอกความหมาย "ทำกับใครด้วยกัน" ด้วยสองชิ้นคู่กัน: อนุภาคบอกการเป็นเพื่อนร่วมกระทำเกาะคน + คำวิเศษณ์ 같이 หรือ 함께 ("ด้วยกัน") ข้างกริยา. อนุภาคเป็นชุดเดียวกับที่ใช้ "และ/กับ": 와/과 (ทางการ/เขียน), 하고 (พูดเป็นกลาง), (이)랑 (กันเองระหว่างเพื่อน). คู่กับ 같이/함께 จะเป็น 친구하고 같이 / 친구랑 같이 / 친구와 함께 — "กับเพื่อน". 같이 ใช้พูด ส่วน 함께 ฟังอบอุ่นหรือออกเชิงวรรณกรรมมากกว่า\n\nสามารถ "ตัด" 같이 / 함께 ได้ — 친구하고 밥을 먹었어요 ก็มีนัยว่า "กับเพื่อน" อยู่แล้ว. การเพิ่ม 같이 / 함께 ทำให้ความหมาย "ด้วยกัน" ชัดเจน เหมาะกับคำเชิญ (같이 갈래요? "ไปด้วยกันไหม?"). ถ้ามีตั้งแต่สามคนขึ้นไป ใส่อนุภาคระหว่างคนเท่านั้น ไม่ใส่หลังคนสุดท้าย: 친구하고 동생하고 같이 ("กับเพื่อนและน้อง"). รูปยกย่อง "กับผู้ที่เคารพ" ใช้ 함께 กับ 께/와 (선생님과 함께 / 어머니와 함께 ทางการกว่า 어머니하고 같이)',
      'Bahasa Korea menyatakan "bersama dengan seseorang" dengan dua bagian: partikel pendamping yang menempel pada orang + adverbia 같이 atau 함께 ("bersama") di dekat verba. Partikelnya satu keluarga dengan "dan / dengan": 와/과 (formal/tulis), 하고 (netral lisan), (이)랑 (santai antar teman). Dipasangkan dengan 같이 atau 함께 jadi: 친구하고 같이 / 친구랑 같이 / 친구와 함께 — "bersama teman". 같이 lebih percakapan; 함께 terdengar lebih hangat atau bersastra.\n\nKamu BISA melepas 같이 / 함께 — 친구하고 밥을 먹었어요 sudah bermakna "bersama teman". Menambahkan 같이 / 함께 membuat kebersamaan eksplisit, cocok untuk ajakan (같이 갈래요? "yuk pergi bareng?"). Untuk tiga orang atau lebih, partikel hanya di antara orang, bukan setelah yang terakhir: 친구하고 동생하고 같이 ("bersama teman dan adik"). Untuk versi hormat "bersama orang yang dihormati", pakai 함께 dengan 께/와 (선생님과 함께 / 어머니와 함께 terdengar lebih formal dibanding 어머니하고 같이).',
      'Tiếng Hàn diễn đạt "cùng với ai đó" bằng hai mảnh ghép: tiểu từ chỉ người đồng hành gắn vào người + trạng từ 같이 hoặc 함께 ("cùng nhau") cạnh động từ. Các tiểu từ chính là họ "và / với" bạn đã biết: 와/과 (trang trọng/viết), 하고 (chuẩn khẩu ngữ), (이)랑 (thân mật giữa bạn bè). Ghép với 같이 hoặc 함께 thành 친구하고 같이 / 친구랑 같이 / 친구와 함께 — "cùng với một người bạn". 같이 thiên về hội thoại; 함께 nghe ấm áp hoặc văn vẻ hơn một chút.\n\nBạn CÓ THỂ bỏ 같이 / 함께 — 친구하고 밥을 먹었어요 đã hàm nghĩa "với một người bạn". Thêm 같이 / 함께 làm rõ ý "cùng nhau", rất hợp với lời mời (같이 갈래요? "đi cùng nhau không?"). Với ba người trở lên, tiểu từ chỉ đặt giữa các người, không đặt sau người cuối: 친구하고 동생하고 같이 ("với bạn và em"). Với phiên bản kính ngữ "cùng người được tôn trọng", dùng 함께 với 께/와 (선생님과 함께 / 어머니와 함께 nghe trang trọng hơn 어머니하고 같이).',
      '韓国語の「(誰か)と一緒に」は二つの部品で成り立つ: 人に付ける同伴助詞 + 動詞の近くに置く 같이 か 함께(「いっしょに」)。助詞は「と／〜と」で見たのと同じ仲間: 와/과(文語・フォーマル)、하고(会話の中立)、(이)랑(親しい間柄)。같이/함께 と組むと、친구하고 같이 / 친구랑 같이 / 친구와 함께 —「友達と一緒に」。같이 は会話的、함께 はやや温かみがあったり文語的に響く。\n\n같이 / 함께 は「省略」できる — 친구하고 밥을 먹었어요 だけで「友達と」が含意される。같이 / 함께 を入れると「一緒に」が明示され、誘いに最適(같이 갈래요?「一緒に行きませんか?」)。3人以上を並べるときは、助詞は人と人の間にだけ付け、最後の人の後には付けない: 친구하고 동생하고 같이(「友達と弟／妹と一緒に」)。敬意を込めた「目上の方と」は 함께 を 께/와 と組む(선생님과 함께 / 어머니와 함께 は 어머니하고 같이 よりフォーマル)。',
    ),
  '가져가다 / 가져오다 / 데려가다 / 데려오다': L(
      'Four high-frequency compound verbs built from movement (가다 "go", 오다 "come") + an action root. 가져가다 = "take (an object) away from speaker", 가져오다 = "bring (an object) toward speaker", 데려가다 = "take (a person/animal) away from speaker", 데려오다 = "bring (a person/animal) toward speaker". Korean is strict about the object/person split: 가져 for things, 데려 for living beings.\n\nThe direction marker is built into 가다 vs 오다 — pick by whose side the destination is on, not by who\'s speaking. 우산을 가져가세요 "please take the umbrella (with you, away)" vs 우산을 가져오세요 "please bring an umbrella (here)". For honorific "bringing a respected person" use 모시고 오다 / 모시고 가다 ("escort and come/go", with 모시다 "to serve / accompany respectfully"): 부모님을 모시고 왔어요 "I brought my parents (with proper respect)". Don\'t use 데려 with elders — it sounds like you\'re leading a child.',
      'Cuatro verbos compuestos muy frecuentes que combinan movimiento (가다 "ir", 오다 "venir") con una raíz de acción. 가져가다 = "llevarse (un objeto, lejos del hablante)", 가져오다 = "traer (un objeto, hacia el hablante)", 데려가다 = "llevarse (una persona/animal, lejos)", 데려오다 = "traer (persona/animal, hacia el hablante)". El coreano separa estrictamente objetos y seres vivos: 가져 para cosas, 데려 para seres vivos.\n\nLa dirección queda en 가다 vs 오다 — se elige según dónde está el destino, no quién habla. 우산을 가져가세요 "llevate el paraguas (lejos)" vs 우산을 가져오세요 "traé un paraguas (acá)". Para el honorífico "traer a una persona respetada", usá 모시고 오다 / 모시고 가다 ("escoltar y venir/ir", con 모시다 "atender / acompañar con respeto"): 부모님을 모시고 왔어요 "traje a mis padres (con el debido respeto)". No uses 데려 con personas mayores — suena a que estás guiando a un niño.',
      'Quatre verbes composés très fréquents formés sur un verbe de mouvement (가다 « aller », 오다 « venir ») + une racine d\'action. 가져가다 = « emporter (un objet, loin du locuteur) », 가져오다 = « apporter (un objet, vers le locuteur) », 데려가다 = « emmener (une personne/un animal, loin) », 데려오다 = « amener (une personne/un animal, vers le locuteur) ». Le coréen sépare strictement objets et êtres vivants : 가져 pour les choses, 데려 pour les êtres vivants.\n\nLa direction se trouve dans 가다 vs 오다 — on choisit en fonction du côté où se trouve la destination, pas en fonction de qui parle. 우산을 가져가세요 « prends ton parapluie (avec toi, en partant) » vs 우산을 가져오세요 « apporte un parapluie (ici) ». Pour la forme honorifique « amener une personne qu\'on respecte », employer 모시고 오다 / 모시고 가다 (« escorter et venir/aller », avec 모시다 « accompagner avec respect ») : 부모님을 모시고 왔어요 « j\'ai amené mes parents (avec déférence) ». Ne pas employer 데려 avec ses aînés — on a l\'air de mener un enfant.',
      'Quatro verbos compostos de alta frequência formados por movimento (가다 "ir", 오다 "vir") + uma raiz de ação. 가져가다 = "levar (um objeto) para longe do falante", 가져오다 = "trazer (um objeto) na direção do falante", 데려가다 = "levar (uma pessoa/animal) para longe", 데려오다 = "trazer (uma pessoa/animal) na direção do falante". O coreano separa estritamente objetos e seres vivos: 가져 para coisas, 데려 para seres vivos.\n\nA direção mora em 가다 vs 오다 — escolha pelo lado em que está o destino, não por quem fala. 우산을 가져가세요 "leve o guarda-chuva (com você, embora)" vs 우산을 가져오세요 "traga um guarda-chuva (aqui)". Para o honorífico "trazer alguém respeitado", use 모시고 오다 / 모시고 가다 ("escoltar e vir/ir", com 모시다 "acompanhar com respeito"): 부모님을 모시고 왔어요 "trouxe meus pais (com o devido respeito)". Não use 데려 com pessoas mais velhas — soa como se estivesse guiando uma criança.',
      'คำกริยาประสมความถี่สูง 4 ตัว ที่สร้างจากกริยาเคลื่อนที่ (가다 "ไป", 오다 "มา") + ราก. 가져가다 = "เอา (สิ่งของ) ไปจากผู้พูด", 가져오다 = "เอา (สิ่งของ) มาทางผู้พูด", 데려가다 = "พา (คน/สัตว์) ไป", 데려오다 = "พา (คน/สัตว์) มา". เกาหลีแยกชัดเจนระหว่างของกับสิ่งมีชีวิต: 가져 ใช้กับของ, 데려 ใช้กับสิ่งมีชีวิต\n\nทิศทางอยู่ที่ 가다 กับ 오다 — เลือกตามว่าปลายทางอยู่ฝั่งไหน ไม่ใช่ว่าผู้พูดอยู่ฝั่งไหน. 우산을 가져가세요 "เอาร่มไปด้วยนะ (ออกไป)" vs 우산을 가져오세요 "เอาร่มมาที่นี่หน่อย". รูปยกย่อง "พาผู้ใหญ่มา" ใช้ 모시고 오다 / 모시고 가다 (พา = "ปรนนิบัติ" 모시다 + 오다/가다): 부모님을 모시고 왔어요 "ฉันพาพ่อแม่มาด้วยอย่างให้เกียรติ". อย่าใช้ 데려 กับผู้สูงอายุ — จะฟังเหมือนจูงเด็ก',
      'Empat verba majemuk berfrekuensi tinggi yang dibangun dari verba gerak (가다 "pergi", 오다 "datang") + akar tindakan. 가져가다 = "membawa (benda) menjauh dari penutur", 가져오다 = "membawa (benda) menuju penutur", 데려가다 = "membawa (orang/hewan) menjauh", 데려오다 = "membawa (orang/hewan) menuju penutur". Bahasa Korea ketat memisahkan benda dan makhluk hidup: 가져 untuk benda, 데려 untuk makhluk hidup.\n\nArah ada di 가다 vs 오다 — pilih berdasarkan di sisi mana tujuannya, bukan di sisi mana penuturnya. 우산을 가져가세요 "bawa payungmu (pergi)" vs 우산을 가져오세요 "bawa payung (ke sini)". Untuk versi hormat "membawa orang yang dihormati", gunakan 모시고 오다 / 모시고 가다 ("mengantar dengan hormat dan datang/pergi", dengan 모시다 "menyertai dengan hormat"): 부모님을 모시고 왔어요 "saya membawa orang tua saya (dengan rasa hormat)". Jangan pakai 데려 untuk orang yang lebih tua — kesannya seperti menuntun anak kecil.',
      'Bốn động từ ghép tần suất cao tạo từ động từ chuyển động (가다 "đi", 오다 "đến") + gốc hành động. 가져가다 = "đem (đồ vật) ra xa người nói", 가져오다 = "đem (đồ vật) về phía người nói", 데려가다 = "dẫn (người/động vật) ra xa", 데려오다 = "dẫn (người/động vật) về phía người nói". Tiếng Hàn phân biệt nghiêm: 가져 cho đồ vật, 데려 cho sinh vật.\n\nHướng nằm ở 가다 vs 오다 — chọn theo nơi đích đến, không theo người nói. 우산을 가져가세요 "đem ô theo (đi nhé)" vs 우산을 가져오세요 "mang ô tới (đây)". Bản kính ngữ "đưa người đáng kính đến" dùng 모시고 오다 / 모시고 가다 ("hộ tống và đến/đi", với 모시다 "phụng dưỡng / đi cùng một cách kính trọng"): 부모님을 모시고 왔어요 "tôi đã đưa bố mẹ đến (với sự tôn kính)". Đừng dùng 데려 với người lớn tuổi — nghe như dẫn trẻ con.',
      '使用頻度の高い4つの複合動詞。移動動詞(가다「行く」、오다「来る」)に動作の語根を組み合わせる。가져가다 = 「(物を)持っていく」、가져오다 = 「(物を)持ってくる」、데려가다 = 「(人・動物を)連れていく」、데려오다 = 「(人・動物を)連れてくる」。韓国語は厳格に区別する: 가져 は物、데려 は生き物。\n\n方向は 가다 / 오다 で決まる — 話し手の側ではなく「到達点がどちら側か」で選ぶ。우산을 가져가세요「傘を持っていってね(出かけるとき)」vs 우산을 가져오세요「傘を持ってきて(こっちへ)」。「目上の方をお連れする」尊敬形には 모시고 오다 / 모시고 가다 を使う(모시다「(目上を)お世話する／お供する」+ 오다/가다): 부모님을 모시고 왔어요「両親をお連れしました」。데려 を年配者に使うと子どもを引率しているような失礼な響きになるので避ける。',
    ),
  '-지 말다': L(
      'Forms the negative imperative ("don\'t do X"). Attach -지 말다 to a verb stem and then pick the right ending by register: 마세요 (polite, the everyday default — 걱정하지 마세요), 마 (casual, friend-to-friend — 걱정하지 마), 말자 ("let\'s not" — 걱정하지 말자), 마십시오 (formal command — 걱정하지 마십시오). 말다 is itself a verb (ㄹ-irregular), which is why the conjugations look the way they do.\n\nUse 말다 ONLY in commands and proposals — for "I don\'t want to / I won\'t" use plain negative -지 않다 or 안 instead (저는 가지 않아요 / 저는 안 가요, NOT 저는 가지 말아요). The pattern always reads as "stop / don\'t" addressed to someone — yourself, the listener, or "let\'s not". For "no need to" (absence of obligation, not a command), use the very different -지 않아도 되다.',
      'Forma el imperativo negativo ("no hagas X"). Pegá -지 말다 a la raíz del verbo y elegí la terminación según el registro: 마세요 (educado, el estándar diario — 걱정하지 마세요), 마 (informal entre amigos — 걱정하지 마), 말자 ("no hagamos" — 걱정하지 말자), 마십시오 (orden formal — 걱정하지 마십시오). 말다 es un verbo (irregular en ㄹ), por eso las conjugaciones se ven así.\n\nUsá 말다 SOLO en órdenes y propuestas — para "no quiero / no voy a" usá la negación regular -지 않다 o 안 (저는 가지 않아요 / 저는 안 가요, NO 저는 가지 말아요). El patrón siempre se lee como "no hagas eso", dirigido a alguien — vos mismo, el oyente o "no hagamos". Para "no hace falta" (ausencia de obligación, no una orden), usá el muy distinto -지 않아도 되다.',
      'Forme l\'impératif négatif (« ne fais pas X »). Colle -지 말다 à la racine du verbe puis choisis la terminaison selon le registre : 마세요 (poli, le standard du quotidien — 걱정하지 마세요), 마 (familier, entre amis — 걱정하지 마), 말자 (« n\'allons pas » — 걱정하지 말자), 마십시오 (commande formelle — 걱정하지 마십시오). 말다 est lui-même un verbe (irrégulier en ㄹ), d\'où la forme des conjugaisons.\n\nUtilise 말다 UNIQUEMENT pour des ordres et des propositions — pour « je ne veux pas / je ne vais pas », emploie la négation ordinaire -지 않다 ou 안 (저는 가지 않아요 / 저는 안 가요, et NON 저는 가지 말아요). Le motif s\'adresse toujours à quelqu\'un (« n\'aie pas », « n\'allons pas »). Pour « il n\'est pas nécessaire de » (absence d\'obligation, pas un ordre), utiliser le tout autre -지 않아도 되다.',
      'Forma o imperativo negativo ("não faça X"). Anexe -지 말다 ao radical do verbo e escolha a terminação pelo registro: 마세요 (educado, o padrão do dia a dia — 걱정하지 마세요), 마 (casual entre amigos — 걱정하지 마), 말자 ("não vamos fazer" — 걱정하지 말자), 마십시오 (ordem formal — 걱정하지 마십시오). 말다 é em si um verbo (irregular em ㄹ), por isso as conjugações têm essa forma.\n\nUse 말다 SOMENTE em ordens e propostas — para "não quero / não vou" use a negação comum -지 않다 ou 안 (저는 가지 않아요 / 저는 안 가요, NÃO 저는 가지 말아요). O padrão sempre se lê como "não faça isso", dirigido a alguém — você mesmo, o ouvinte, ou "não vamos". Para "não precisa" (ausência de obrigação, não uma ordem), use o totalmente diferente -지 않아도 되다.',
      'สร้างคำสั่งเชิงปฏิเสธ ("อย่าทำ X"). เกาะ -지 말다 ที่รากของกริยา แล้วเลือกท้ายตามระดับภาษา: 마세요 (สุภาพ ใช้ทุกวัน — 걱정하지 마세요), 마 (กันเองกับเพื่อน — 걱정하지 마), 말자 ("อย่ามาทำเลย" — 걱정하지 말자), 마십시오 (คำสั่งทางการ — 걱정하지 마십시오). 말다 เองเป็นกริยา (ไม่ปกติแบบ ㄹ) ดังนั้นการผันถึงออกมาแบบนี้\n\nใช้ 말다 "เฉพาะ" คำสั่งและข้อเสนอ — ถ้าจะพูด "ฉันไม่อยาก / ฉันไม่ทำ" ใช้รูปปฏิเสธปกติ -지 않다 หรือ 안 (저는 가지 않아요 / 저는 안 가요, ไม่ใช่ 저는 가지 말아요). รูปแบบนี้สื่อความหมาย "อย่าทำ" ไปยังใครคนหนึ่งเสมอ — ตัวเอง ผู้ฟัง หรือ "พวกเราอย่าทำ". สำหรับ "ไม่จำเป็นต้อง" (ไม่มีหน้าที่ ไม่ใช่ห้าม) ใช้ -지 않아도 되다 ซึ่งต่างกันอย่างสิ้นเชิง',
      'Membentuk imperatif negatif ("jangan lakukan X"). Tempelkan -지 말다 pada akar verba lalu pilih akhiran sesuai register: 마세요 (sopan, standar harian — 걱정하지 마세요), 마 (santai antar teman — 걱정하지 마), 말자 ("jangan kita ..." — 걱정하지 말자), 마십시오 (perintah formal — 걱정하지 마십시오). 말다 sendiri adalah verba (tak beraturan ㄹ), itu sebabnya konjugasinya seperti ini.\n\nPakai 말다 HANYA dalam perintah dan ajakan — untuk "saya tidak mau / saya tidak akan" pakai negasi biasa -지 않다 atau 안 (저는 가지 않아요 / 저는 안 가요, BUKAN 저는 가지 말아요). Pola ini selalu berarti "jangan lakukan" ditujukan kepada seseorang — diri sendiri, lawan bicara, atau "jangan kita". Untuk "tidak perlu" (tidak ada kewajiban, bukan larangan) pakai -지 않아도 되다 yang sangat berbeda.',
      'Tạo mệnh lệnh phủ định ("đừng làm X"). Gắn -지 말다 vào gốc động từ rồi chọn đuôi theo cấp độ: 마세요 (lịch sự, mặc định hằng ngày — 걱정하지 마세요), 마 (thân mật giữa bạn bè — 걱정하지 마), 말자 ("đừng nào / mình đừng" — 걱정하지 말자), 마십시오 (mệnh lệnh trang trọng — 걱정하지 마십시오). 말다 bản thân là động từ (bất quy tắc ㄹ), nên các dạng chia ra như vậy.\n\nDùng 말다 CHỈ trong mệnh lệnh và đề nghị — để nói "tôi không muốn / tôi không làm" hãy dùng phủ định thường -지 않다 hoặc 안 (저는 가지 않아요 / 저는 안 가요, KHÔNG phải 저는 가지 말아요). Mẫu này luôn có ý "đừng làm" hướng đến ai đó — bản thân, người nghe, hoặc "đừng cùng nhau". Để nói "không cần phải" (vắng nghĩa vụ, không phải cấm) dùng -지 않아도 되다 hoàn toàn khác.',
      '否定の命令(「Xしないで」)を作る。動詞の語幹に -지 말다 を付け、丁寧度で語尾を選ぶ: 마세요(丁寧、日常の標準 — 걱정하지 마세요)、마(친구同士のカジュアル — 걱정하지 마)、말자(「やめよう」 — 걱정하지 말자)、마십시오(フォーマル命令 — 걱정하지 마십시오)。말다 自体が動詞(ㄹ 不規則)で、その活用がこれらの形を生む。\n\n말다 は「命令・勧誘でのみ」使う — 「したくない／しない」と言いたいときは普通の否定 -지 않다 や 안 を使う(저는 가지 않아요 / 저는 안 가요、저는 가지 말아요 とは言わない)。このパターンは常に誰か(自分・聞き手・「やめよう」)に向けた「やめて／〜しないで」を表す。「義務がない」(命令ではない)を表すには、まったく別の -지 않아도 되다 を用いる。',
    ),
  'N 말고': L(
      'Lets you reject one noun in favor of another — "not N, but ...". Attach 말고 to the noun you\'re rejecting and follow with the noun you actually want: 커피 말고 차 주세요 "not coffee, please give me tea". 말고 is built from 말다 ("don\'t") + the connector -고, so think of it as "leave N aside and ...". Very useful at restaurants, when ordering, or when answering a wrong assumption.\n\nFor extra emphasis or a written register, swap to N이/가 아니라 ("not N, rather ..."): 커피가 아니라 차예요 "it\'s not coffee, it\'s tea". The two are slightly different in role: 말고 is conversational and works smoothly in commands and requests, while N이/가 아니라 is more declarative and is preferred in explanations. For "not X but Y" with verbs or clauses, use -지 말고 instead (싸우지 말고 이야기해요 "don\'t fight, let\'s talk"). Don\'t confuse 말고 with 말고서 / 말고는, which add further nuance ("apart from" / "except for") and lean more written.',
      'Permite rechazar un sustantivo a favor de otro — "no N, sino ...". Pegá 말고 al sustantivo que rechazás y seguí con el que querés: 커피 말고 차 주세요 "café no, deme té". 말고 viene de 말다 ("no") + el conector -고, así que pensalo como "dejá N de lado y ...". Muy útil en restaurantes, al pedir o al responder a una suposición equivocada.\n\nPara más énfasis o registro escrito, cambialo por N이/가 아니라 ("no N, sino ..."): 커피가 아니라 차예요 "no es café, es té". Hay un matiz: 말고 es conversacional y va fluido en órdenes y pedidos, mientras que N이/가 아니라 es más declarativo y se prefiere en explicaciones. Para "no X sino Y" con verbos o cláusulas, usá -지 말고 (싸우지 말고 이야기해요 "no peleemos, hablemos"). No lo confundas con 말고서 / 말고는, que añaden el matiz de "aparte de / excepto" y son más escritos.',
      'Permet de rejeter un nom au profit d\'un autre — « pas N, mais ... ». Colle 말고 sur le nom rejeté et fais suivre par celui que tu veux : 커피 말고 차 주세요 « pas de café, du thé s\'il vous plaît ». 말고 vient de 말다 (« ne pas ») + le connecteur -고, donc pense « laisse N de côté et ... ». Très utile au restaurant, à la commande ou pour corriger une supposition.\n\nPour insister ou un registre écrit, on bascule sur N이/가 아니라 (« pas N, plutôt ... ») : 커피가 아니라 차예요 « ce n\'est pas du café, c\'est du thé ». Nuance : 말고 est conversationnel et passe sans accroc dans les ordres ou demandes, tandis que N이/가 아니라 est plus déclaratif, préféré dans les explications. Pour « pas X mais Y » avec verbes ou propositions, utilise -지 말고 (싸우지 말고 이야기해요 « ne nous disputons pas, parlons »). Ne confonds pas 말고 avec 말고서 / 말고는, qui ajoutent la nuance « à part / sauf » et restent surtout écrits.',
      'Permite rejeitar um substantivo em favor de outro — "N não, e sim ...". Anexe 말고 ao substantivo rejeitado e siga com o que você quer: 커피 말고 차 주세요 "café não, me dá chá". 말고 vem de 말다 ("não") + o conector -고, então pense em "deixe N de lado e ...". Muito útil em restaurantes, ao pedir, ou para corrigir uma suposição errada.\n\nPara mais ênfase ou registro escrito, troque por N이/가 아니라 ("não N, mas ..."): 커피가 아니라 차예요 "não é café, é chá". Há nuance: 말고 é conversacional e fica bem em ordens e pedidos, enquanto N이/가 아니라 é mais declarativo e preferido em explicações. Para "não X mas Y" com verbos ou orações, use -지 말고 (싸우지 말고 이야기해요 "não vamos brigar, vamos conversar"). Não confunda 말고 com 말고서 / 말고는, que adicionam a nuance "tirando / exceto" e são mais escritos.',
      'ใช้ปฏิเสธคำนามตัวหนึ่งและเลือกอีกตัวแทน — "ไม่เอา N เอา ...". เกาะ 말고 ที่คำนามที่ปฏิเสธ แล้วตามด้วยตัวที่อยาก: 커피 말고 차 주세요 "ไม่เอากาแฟ ขอชาแทนค่ะ". 말고 มาจาก 말다 ("อย่า") + คำเชื่อม -고 จึงคิดเป็น "วาง N ไว้ก่อน แล้ว ...". มีประโยชน์มากในร้านอาหาร เวลาสั่งของ หรือเวลาแก้ความเข้าใจผิด\n\nถ้าจะเน้นหรืออยู่ในงานเขียน เปลี่ยนเป็น N이/가 아니라 ("ไม่ใช่ N แต่ ..."): 커피가 아니라 차예요 "ไม่ใช่กาแฟ เป็นชา". ความต่าง: 말고 ใช้พูด ไหลดีในคำสั่ง/คำขอ ส่วน N이/가 아니라 บอกเล่า เหมาะกับคำอธิบาย. ถ้าจะปฏิเสธกริยา/อนุประโยค ให้ใช้ -지 말고 (싸우지 말고 이야기해요 "อย่าทะเลาะกัน คุยกันเถอะ"). อย่าสับสนกับ 말고서 / 말고는 ซึ่งให้ความหมาย "นอกจาก / ยกเว้น" และมักใช้ในงานเขียน',
      'Memungkinkan menolak satu kata benda demi yang lain — "bukan N, melainkan ...". Tempelkan 말고 pada kata benda yang ditolak lalu lanjutkan dengan yang diinginkan: 커피 말고 차 주세요 "bukan kopi, tolong tehnya". 말고 berasal dari 말다 ("jangan") + penghubung -고, jadi pikirkan sebagai "kesampingkan N dan ...". Sangat berguna di restoran, saat memesan, atau saat mengoreksi asumsi.\n\nUntuk penekanan lebih atau register tulis, ganti dengan N이/가 아니라 ("bukan N, tetapi ..."): 커피가 아니라 차예요 "ini bukan kopi, ini teh". Nuansanya: 말고 percakapan dan cocok di perintah/permintaan, sementara N이/가 아니라 lebih deklaratif dan dipilih untuk penjelasan. Untuk "bukan X melainkan Y" dengan verba atau klausa, pakai -지 말고 (싸우지 말고 이야기해요 "jangan berkelahi, mari bicara"). Jangan tertukar dengan 말고서 / 말고는 yang menambah nuansa "selain / kecuali" dan lebih ke tulis.',
      'Cho phép từ chối một danh từ và chọn danh từ khác — "không phải N, mà ...". Gắn 말고 vào danh từ bị từ chối rồi nối với danh từ bạn muốn: 커피 말고 차 주세요 "không phải cà phê, cho tôi trà". 말고 đến từ 말다 ("đừng") + liên từ -고, nên hãy nghĩ "gác N sang một bên và ...". Rất hữu dụng ở nhà hàng, khi đặt món, hoặc khi sửa giả định sai.\n\nĐể nhấn mạnh hơn hoặc trong văn viết, chuyển sang N이/가 아니라 ("không phải N, mà ..."): 커피가 아니라 차예요 "đây không phải cà phê, đây là trà". Sắc thái khác nhau: 말고 thuộc khẩu ngữ và mượt trong mệnh lệnh/yêu cầu, còn N이/가 아니라 thiên về tuyên bố và phù hợp khi giải thích. Với "không X mà Y" cho động từ hoặc mệnh đề, dùng -지 말고 (싸우지 말고 이야기해요 "đừng cãi nhau, mình nói chuyện đi"). Đừng nhầm 말고 với 말고서 / 말고는, vốn thêm sắc thái "trừ / ngoài" và thiên về viết.',
      '名詞を「Nではなく…」と置き換える表現。拒否する名詞に 말고 を付け、欲しい方を続ける: 커피 말고 차 주세요「コーヒーじゃなくてお茶をください」。말고 は 말다(「やめる／ない」)+ 接続 -고 から成り、「Nは置いておいて…」と考えるとよい。レストランや注文、誤解を訂正するときに非常に便利。\n\n強調や文語的な場面では N이/가 아니라(「Nではなく…」)に切り替える: 커피가 아니라 차예요「コーヒーではなくお茶です」。ニュアンス差: 말고 は会話的で命令や依頼に自然に乗る、N이/가 아니라 はより断定的で説明や叙述に好まれる。動詞や節を「Xではなくて Y」とする場合は -지 말고 を使う(싸우지 말고 이야기해요「喧嘩しないで話し合おう」)。말고서 / 말고는 (「〜以外に／〜を除いて」)とは別物で、こちらはより文語的なので混同しない。',
    ),
}
